                          {isStudent ? (
                            <><Target className="h-4 w-4 text-blue-500" /> {t('app.page.gelen_ba_lar')}</>
                          ) : (
                            <><Heart className="h-4 w-4 text-red-500" /> {t('app.page.son_ba_lar')}</>
