'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useState } from 'react';
import Link from 'next/link';
import { toast } from 'sonner';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface Campaign {
  campaign_id: string;
  title: string;
  status: string;
  goal_amount: number;
  raised_amount: number;
  created_at: string;
  student?: {
    name: string;
    email: string;
  };
}

const STATUS_OPTIONS = [
  { value: 'draft', label: 'Draft', bg: 'bg-gray-100', text: 'text-gray-800' },
  { value: 'published', label: 'Published', bg: 'bg-blue-100', text: 'text-blue-800' },
  { value: 'paused', label: 'Paused', bg: 'bg-yellow-100', text: 'text-yellow-800' },
  { value: 'completed', label: 'Completed', bg: 'bg-green-100', text: 'text-green-800' },
  { value: 'cancelled', label: 'Cancelled', bg: 'bg-red-100', text: 'text-red-800' },
];

export default function AdminCampaignsPage() {
    const { t } = useTranslation();
  const { data: session } = useSession();
  const { formatAmount } = useCurrency();
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  const fetchCampaigns = async () => {
    try {
      const response = await fetch('/api/admin/campaigns', { cache: 'no-store' });
      if (!response.ok) {
        throw new Error('Failed to fetch campaigns');
      }
      const data = await response.json();
      if (data.success) {
        setCampaigns(data.data || []);
      } else {
        throw new Error(data.error?.message || 'Failed to fetch campaigns');
      }
    } catch (err: any) {
      setError(err.message || 'Error loading campaigns');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCampaigns();
  }, []);

  const handleStatusChange = async (campaignId: string, newStatus: string) => {
    setUpdatingId(campaignId);
    try {
      const response = await fetch(`/api/admin/campaigns/${campaignId}/status`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      });

      const data = await response.json();

      if (!response.ok || !data.success) {
        throw new Error(data.error?.message || 'Failed to update status');
      }

      // Update local state
      setCampaigns(prev =>
        prev.map(c => c.campaign_id === campaignId ? { ...c, status: newStatus } : c)
      );

      toast.success(`Campaign ${newStatus === 'published' ? 'published' : `status changed to ${newStatus}`}`);
    } catch (err: any) {
      toast.error(err.message || 'Failed to update campaign status');
    } finally {
      setUpdatingId(null);
    }
  };

  const getStatusBadge = (status: string) => {
    const statusStyle = STATUS_OPTIONS.find(s => s.value === status) || STATUS_OPTIONS[0];
    return (
      <span
        className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${statusStyle.bg} ${statusStyle.text}`}
      >
        {statusStyle.label}
      </span>
    );
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-md p-4">
        <p className="text-red-800">{error}</p>
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-3xl font-bold text-gray-900 mb-8">{t('app.page.campaigns')}</h2>

      {campaigns.length === 0 ? (
        <div className="bg-white rounded-lg shadow p-12 text-center">
          <p className="text-gray-500">{t('app.page.no_campaigns_found')}</p>
        </div>
      ) : (
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.title')}</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.student')}</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.status')}</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.goal')}</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.raised')}</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  {t('app.page.actions')}</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {campaigns.map((campaign) => {
                  const { t } = useTranslation();
                const progress = campaign.goal_amount > 0
                  ? (campaign.raised_amount / campaign.goal_amount) * 100
                  : 0;
                const isUpdating = updatingId === campaign.campaign_id;

                return (
                  <tr key={campaign.campaign_id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <div className="text-sm font-medium text-gray-900">{campaign.title}</div>
                      <div className="text-xs text-gray-400 font-mono">{campaign.campaign_id}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-500">
                        {campaign.student?.name || 'Unknown'}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusBadge(campaign.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {formatAmount(campaign.goal_amount)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {formatAmount(campaign.raised_amount)}
                      <div className="w-20 bg-gray-200 rounded-full h-1.5 mt-1">
                        <div
                          className="bg-blue-600 h-1.5 rounded-full"
                          style={{ width: `${Math.min(progress, 100)}%` }}
                        ></div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {/* Quick Publish Button */}
                        {campaign.status !== 'published' && (
                          <button
                            onClick={() => handleStatusChange(campaign.campaign_id, 'published')}
                            disabled={isUpdating}
                            className="inline-flex items-center px-3 py-1.5 text-xs font-medium rounded-md text-white bg-green-600 hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            {isUpdating ? 'Updating...' : 'Publish'}
                          </button>
                        )}

                        {/* Quick Pause/Unpublish Button */}
                        {campaign.status === 'published' && (
                          <button
                            onClick={() => handleStatusChange(campaign.campaign_id, 'paused')}
                            disabled={isUpdating}
                            className="inline-flex items-center px-3 py-1.5 text-xs font-medium rounded-md text-yellow-800 bg-yellow-100 hover:bg-yellow-200 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            {isUpdating ? 'Updating...' : 'Pause'}
                          </button>
                        )}

                        {/* Status Dropdown */}
                        <select
                          value={campaign.status}
                          onChange={(e) => handleStatusChange(campaign.campaign_id, e.target.value)}
                          disabled={isUpdating}
                          className="text-xs border border-gray-300 rounded-md px-2 py-1.5 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
                        >
                          {STATUS_OPTIONS.map((option) => (
                            <option key={option.value} value={option.value}>
                              {option.label}
                            </option>
                          ))}
                        </select>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { StatCard } from '@/components/ui/StatCard';
import { toast } from 'sonner';
import { DollarSign, Clock, CheckCircle, XCircle, RefreshCw, Send } from 'lucide-react';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface PayoutSummary {
  method_type: string;
  total_students: number;
  total_available: number;
}

interface PendingPayout {
  user_id: string;
  student_name: string;
  email: string;
  method_type: string;
  method_details: Record<string, string>;
  available: number;
  totalEarned: number;
  totalWithdrawn: number;
}

export default function AdminPayoutsPage() {
    const { t } = useTranslation();
  const { formatAmount } = useCurrency();
  const [summaries, setSummaries] = useState<PayoutSummary[]>([]);
  const [pendingPayouts, setPendingPayouts] = useState<PendingPayout[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [payoutAmounts, setPayoutAmounts] = useState<Record<string, string>>({});

  const fetchPayouts = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/admin/payouts');
      if (!res.ok) throw new Error('Ödeme verileri yüklenemedi');
      const data = await res.json();
      setSummaries(data.data?.summaries ?? []);
      setPendingPayouts(data.data?.pending ?? []);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Hata oluştu';
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchPayouts();
  }, [fetchPayouts]);

  const handleProcessPayout = async (payout: PendingPayout) => {
      const { t } = useTranslation();
    const amountStr = payoutAmounts[payout.user_id];
    const amount = parseFloat(amountStr);
    if (!amount || amount <= 0 || amount > payout.available) {
      toast.error(`Geçerli bir tutar girin (maks. ${formatAmount(payout.available)})`);
      return;
    }

    setProcessingId(payout.user_id);
    try {
      const res = await fetch('/api/admin/payouts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          user_id: payout.user_id,
          amount,
          method_type: payout.method_type,
        }),
      });
      if (!res.ok) {
        const errData = await res.json();
        throw new Error(errData.error ?? 'Ödeme işlenemedi');
      }
      toast.success(`${formatAmount(amount)} ödeme başarıyla işlendi`);
      setPayoutAmounts((prev) => ({ ...prev, [payout.user_id]: '' }));
      await fetchPayouts();
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Hata oluştu');
    } finally {
      setProcessingId(null);
    }
  };

  const totalAvailable = summaries.reduce((sum, s) => sum + s.total_available, 0);
  const totalStudents = summaries.reduce((sum, s) => sum + s.total_students, 0);

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center py-16">
        <p className="text-red-600 font-medium mb-4">{error}</p>
        <Button onClick={fetchPayouts}><RefreshCw className="h-4 w-4 mr-2" /> {t('app.page.yeniden_dene')}</Button>
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-3xl font-bold text-gray-900 mb-8">{t('app.page.demeler')}</h2>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
        <StatCard
          title={t('app.page.toplam_bekleyen_bakiye')}
          value={formatAmount(totalAvailable)}
          icon={<DollarSign className="h-5 w-5" />}
          loading={loading}
          valueClassName="text-green-600"
        />
        <StatCard
          title={t('app.page.deme_bekleyen_renci')}
          value={totalStudents}
          icon={<Clock className="h-5 w-5" />}
          loading={loading}
          valueClassName="text-yellow-600"
        />
        <StatCard
          title={t('app.page.deme_y_ntemleri')}
          value={summaries.length}
          subtitle={summaries.map((s) => s.method_type).join(', ')}
          icon={<CheckCircle className="h-5 w-5" />}
          loading={loading}
        />
      </div>

      {/* Method Breakdown */}
      {!loading && summaries.length > 0 && (
        <div className="bg-white rounded-lg shadow p-6 mb-8">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">{t('app.page.y_nteme_g_re_da_l_m')}</h3>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {summaries.map((s) => (
              <div key={s.method_type} className="p-4 bg-gray-50 rounded-lg text-center">
                <p className="text-xs font-medium text-gray-500 uppercase mb-1">{s.method_type}</p>
                <p className="text-xl font-bold text-gray-900">{formatAmount(s.total_available)}</p>
                <p className="text-xs text-gray-500">{s.total_students} {t('app.page.renci')}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Pending Payouts Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="p-6 border-b">
          <h3 className="text-lg font-semibold text-gray-900">{t('app.page.bekleyen_demeler')}</h3>
        </div>

        {loading ? (
          <div className="p-6 space-y-4">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="flex items-center gap-4">
                <Skeleton className="h-5 w-32" />
                <Skeleton className="h-5 w-44" />
                <Skeleton className="h-5 w-20" />
                <Skeleton className="h-5 w-24" />
                <Skeleton className="h-8 w-28 ml-auto" />
              </div>
            ))}
          </div>
        ) : pendingPayouts.length === 0 ? (
          <div className="p-12 text-center">
            <p className="text-gray-500">{t('app.page.bekleyen_deme_yok')}</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">{t('app.page.renci')}</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">E-posta</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">{t('app.page.y_ntem')}</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">{t('app.page.detay')}</th>
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">{t('app.page.bakiye')}</th>
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">{t('app.page.tutar')}</th>
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">{t('app.page.lem')}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {pendingPayouts.map((p) => (
                  <tr key={p.user_id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {p.student_name}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{p.email}</td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <Badge className="capitalize">{p.method_type}</Badge>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {Object.values(p.method_details).join(' · ')}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-right font-semibold text-green-600">
                      {formatAmount(p.available)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <Input
                        type="number"
                        placeholder={t('app.page.tutar')}
                        className="w-28 text-right"
                        min={1}
                        max={p.available}
                        value={payoutAmounts[p.user_id] ?? ''}
                        onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                          setPayoutAmounts((prev) => ({ ...prev, [p.user_id]: e.target.value }))
                        }
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <Button
                        size="sm"
                        onClick={() => handleProcessPayout(p)}
                        disabled={processingId === p.user_id}
                      >
                        <Send className="h-4 w-4 mr-1" />
                        {processingId === p.user_id ? 'İşleniyor...' : 'Gönder'}
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState, useCallback } from 'react';
import { Building2, User, Mail, Phone, MessageSquare, Clock, CheckCircle, XCircle, Eye, Trash2, Search } from 'lucide-react';
import { useTranslation } from "@/lib/i18n/context";

interface SponsorApplication {
  _id: string;
  companyName: string;
  contactName: string;
  email: string;
  phone: string;
  message: string;
  status: 'pending' | 'reviewed' | 'approved' | 'rejected';
  createdAt: string;
  updatedAt: string;
  notes: string;
}

const statusConfig: Record<string, { label: string; color: string; bg: string; icon: React.ReactNode }> = {
  pending: { label: 'Beklemede', color: 'text-yellow-800', bg: 'bg-yellow-100', icon: <Clock className="h-3.5 w-3.5" /> },
  reviewed: { label: 'Incelendi', color: 'text-blue-800', bg: 'bg-blue-100', icon: <Eye className="h-3.5 w-3.5" /> },
  approved: { label: 'Onaylandi', color: 'text-green-800', bg: 'bg-green-100', icon: <CheckCircle className="h-3.5 w-3.5" /> },
  rejected: { label: 'Reddedildi', color: 'text-red-800', bg: 'bg-red-100', icon: <XCircle className="h-3.5 w-3.5" /> },
};

export default function AdminSponsorApplicationsPage() {
    const { t } = useTranslation();
  const [applications, setApplications] = useState<SponsorApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [selectedApp, setSelectedApp] = useState<SponsorApplication | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [notes, setNotes] = useState('');
  const [pagination, setPagination] = useState({ page: 1, total: 0, totalPages: 1 });

  const fetchApplications = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filter !== 'all') params.set('status', filter);
      params.set('page', pagination.page.toString());
      params.set('limit', '20');

      const res = await fetch(`/api/admin/sponsor-applications?${params}`);
      const data = await res.json();

      if (data.success) {
        setApplications(data.data.applications);
        setPagination((prev) => ({
          ...prev,
          total: data.data.pagination.total,
          totalPages: data.data.pagination.totalPages,
        }));
      }
    } catch (error) {
      console.error('Basvurular yuklenirken hata:', error);
    } finally {
      setLoading(false);
    }
  }, [filter, pagination.page]);

  useEffect(() => {
    fetchApplications();
  }, [fetchApplications]);

  const updateStatus = async (id: string, status: string) => {
    setUpdatingId(id);
    try {
      const res = await fetch(`/api/admin/sponsor-applications/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status, notes }),
      });

      if (res.ok) {
        await fetchApplications();
        if (selectedApp?._id === id) {
          setSelectedApp((prev) => (prev ? { ...prev, status: status as any, notes } : null));
        }
      }
    } catch (error) {
      console.error('Durum guncellenirken hata:', error);
    } finally {
      setUpdatingId(null);
    }
  };

  const deleteApplication = async (id: string) => {
    if (!confirm('Bu basvuruyu silmek istediginizden emin misiniz?')) return;
    try {
      const res = await fetch(`/api/admin/sponsor-applications/${id}`, { method: 'DELETE' });
      if (res.ok) {
        setApplications((prev) => prev.filter((a) => a._id !== id));
        if (selectedApp?._id === id) setSelectedApp(null);
      }
    } catch (error) {
      console.error('Başvuru silinirken hata:', error);
    }
  };

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('tr-TR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const pendingCount = applications.filter((a) => a.status === 'pending').length;

  return (
    <div>
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">{t('app.page.sponsor_basvurulari')}</h1>
        <p className="text-gray-500 mt-1">{t('app.page.sponsor_olmak_isteyen_sirketle')}</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
        {Object.entries(statusConfig).map(([key, cfg]) => {
          const count = filter === 'all'
            ? applications.filter((a) => a.status === key).length
            : key === filter
            ? applications.length
            : 0;
          return (
            <button
              key={key}
              onClick={() => { setFilter(key === filter ? 'all' : key); setPagination((p) => ({ ...p, page: 1 })); }}
              className={`p-4 rounded-xl border-2 transition-all ${
                filter === key ? 'border-blue-500 bg-blue-50' : 'border-gray-200 bg-white hover:border-gray-300'
              }`}
            >
              <div className={`inline-flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium ${cfg.bg} ${cfg.color}`}>
                {cfg.icon}
                {cfg.label}
              </div>
              <div className="text-2xl font-bold text-gray-900 mt-2">{count}</div>
            </button>
          );
        })}
      </div>

      {/* Filter Bar */}
      <div className="flex items-center gap-3 mb-4">
        <button
          onClick={() => { setFilter('all'); setPagination((p) => ({ ...p, page: 1 })); }}
          className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
            filter === 'all' ? 'bg-gray-900 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
          }`}
        >
          {t('app.page.tumu')}{pagination.total})
        </button>
        {Object.entries(statusConfig).map(([key, cfg]) => (
          <button
            key={key}
            onClick={() => { setFilter(key); setPagination((p) => ({ ...p, page: 1 })); }}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              filter === key ? 'bg-gray-900 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            {cfg.label}
          </button>
        ))}
      </div>

      <div className="flex gap-6">
        {/* Application List */}
        <div className="flex-1">
          {loading ? (
            <div className="flex items-center justify-center py-20">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
            </div>
          ) : applications.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-xl border border-gray-200">
              <Search className="h-12 w-12 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-500">{t('app.page.hen_z_ba_vuru_bulunmuyor')}</p>
            </div>
          ) : (
            <div className="space-y-3">
              {applications.map((app) => {
                  const { t } = useTranslation();
                const sc = statusConfig[app.status] || statusConfig.pending;
                return (
                  <div
                    key={app._id}
                    onClick={() => { setSelectedApp(app); setNotes(app.notes || ''); }}
                    className={`bg-white rounded-xl border-2 p-4 cursor-pointer transition-all hover:shadow-md ${
                      selectedApp?._id === app._id ? 'border-blue-500 shadow-md' : 'border-gray-200'
                    }`}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                          <h3 className="font-semibold text-gray-900">{app.companyName}</h3>
                          <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${sc.bg} ${sc.color}`}>
                            {sc.icon}
                            {sc.label}
                          </span>
                        </div>
                        <div className="flex flex-wrap items-center gap-4 text-sm text-gray-500">
                          <span className="flex items-center gap-1">
                            <User className="h-3.5 w-3.5" /> {app.contactName}
                          </span>
                          <span className="flex items-center gap-1">
                            <Mail className="h-3.5 w-3.5" /> {app.email}
                          </span>
                          <span className="flex items-center gap-1">
                            <Phone className="h-3.5 w-3.5" /> {app.phone}
                          </span>
                        </div>
                        <div className="text-xs text-gray-400 mt-2">{formatDate(app.createdAt)}</div>
                      </div>
                      <button
                        onClick={(e) => { e.stopPropagation(); deleteApplication(app._id); }}
                        className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                        title={t('app.page.sil')}
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </div>
                );
              })}

              {/* Pagination */}
              {pagination.totalPages > 1 && (
                <div className="flex items-center justify-center gap-2 pt-4">
                  <button
                    onClick={() => setPagination((p) => ({ ...p, page: Math.max(1, p.page - 1) }))}
                    disabled={pagination.page <= 1}
                    className="px-3 py-1.5 rounded-lg border text-sm disabled:opacity-50"
                  >
                    {t('app.page.nceki')}</button>
                  <span className="text-sm text-gray-500">
                    {pagination.page} / {pagination.totalPages}
                  </span>
                  <button
                    onClick={() => setPagination((p) => ({ ...p, page: Math.min(p.totalPages, p.page + 1) }))}
                    disabled={pagination.page >= pagination.totalPages}
                    className="px-3 py-1.5 rounded-lg border text-sm disabled:opacity-50"
                  >
                    {t('app.page.sonraki')}</button>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Detail Panel */}
        {selectedApp && (
          <div className="w-96 bg-white rounded-xl border border-gray-200 p-6 h-fit sticky top-4">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-bold text-gray-900">{t('app.page.ba_vuru_detay')}</h2>
              <button onClick={() => setSelectedApp(null)} className="text-gray-400 hover:text-gray-600">
                <XCircle className="h-5 w-5" />
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.sirket_kurum')}</div>
                <div className="flex items-center gap-2 text-gray-900 font-medium">
                  <Building2 className="h-4 w-4 text-gray-500" />
                  {selectedApp.companyName}
                </div>
              </div>

              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.yetkili_kisi')}</div>
                <div className="flex items-center gap-2 text-gray-900">
                  <User className="h-4 w-4 text-gray-500" />
                  {selectedApp.contactName}
                </div>
              </div>

              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">E-posta</div>
                <a href={`mailto:${selectedApp.email}`} className="flex items-center gap-2 text-blue-600 hover:underline">
                  <Mail className="h-4 w-4" />
                  {selectedApp.email}
                </a>
              </div>

              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.telefon')}</div>
                <a href={`tel:${selectedApp.phone}`} className="flex items-center gap-2 text-blue-600 hover:underline">
                  <Phone className="h-4 w-4" />
                  {selectedApp.phone}
                </a>
              </div>

              {selectedApp.message && (
                <div>
                  <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.mesaj')}</div>
                  <div className="flex items-start gap-2 text-gray-700 bg-gray-50 p-3 rounded-lg text-sm">
                    <MessageSquare className="h-4 w-4 text-gray-400 flex-shrink-0 mt-0.5" />
                    {selectedApp.message}
                  </div>
                </div>
              )}

              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.ba_vuru_tarihi')}</div>
                <div className="text-gray-700 text-sm">{formatDate(selectedApp.createdAt)}</div>
              </div>

              {/* Admin Notes */}
              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-1">{t('app.page.admin_notlari')}</div>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder={t('app.page.bu_ba_vuru_hakk_nda_notlar_n_z')}
                  rows={3}
                  className="w-full px-3 py-2 border rounded-lg resize-none text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              {/* Status Actions */}
              <div>
                <div className="text-xs text-gray-400 uppercase tracking-wide mb-2">{t('app.page.durumu_guncelle')}</div>
                <div className="grid grid-cols-2 gap-2">
                  <button
                    onClick={() => updateStatus(selectedApp._id, 'reviewed')}
                    disabled={updatingId === selectedApp._id}
                    className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium bg-blue-50 text-blue-700 hover:bg-blue-100 disabled:opacity-50 transition-colors"
                  >
                    <Eye className="h-3.5 w-3.5" /> {t('app.page.incelendi')}</button>
                  <button
                    onClick={() => updateStatus(selectedApp._id, 'approved')}
                    disabled={updatingId === selectedApp._id}
                    className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium bg-green-50 text-green-700 hover:bg-green-100 disabled:opacity-50 transition-colors"
                  >
                    <CheckCircle className="h-3.5 w-3.5" /> {t('app.page.onayla')}</button>
                  <button
                    onClick={() => updateStatus(selectedApp._id, 'rejected')}
                    disabled={updatingId === selectedApp._id}
                    className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium bg-red-50 text-red-700 hover:bg-red-100 disabled:opacity-50 transition-colors"
                  >
                    <XCircle className="h-3.5 w-3.5" /> {t('app.page.reddet')}</button>
                  <button
                    onClick={() => updateStatus(selectedApp._id, 'pending')}
                    disabled={updatingId === selectedApp._id}
                    className="flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium bg-yellow-50 text-yellow-700 hover:bg-yellow-100 disabled:opacity-50 transition-colors"
                  >
                    <Clock className="h-3.5 w-3.5" /> {t('app.page.beklet')}</button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { toast } from 'sonner';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { MessageSquare, CheckCircle, XCircle, Clock, Eye } from 'lucide-react';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface Story {
    story_id: string;
    user_name: string;
    user_email: string;
    title: string;
    quote: string;
    university: string;
    field: string;
    funded_amount: number;
    status: 'pending' | 'approved' | 'rejected';
    admin_note?: string;
    created_at: string;
    reviewed_at?: string;
}

const statusConfig = {
    pending: { label: 'Bekliyor', color: 'bg-yellow-100 text-yellow-800', icon: Clock },
    approved: { label: 'Onaylandı', color: 'bg-green-100 text-green-800', icon: CheckCircle },
    rejected: { label: 'Reddedildi', color: 'bg-red-100 text-red-800', icon: XCircle },
};

export default function AdminStoriesPage() {
    const { t } = useTranslation();
    const { formatAmount } = useCurrency();
    const [stories, setStories] = useState<Story[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('pending');
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const [expandedStory, setExpandedStory] = useState<string | null>(null);

    const fetchStories = useCallback(async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/admin/stories?status=${filter}`);
            if (res.ok) {
                const data = await res.json();
                if (data.success) {
                    setStories(data.data?.stories || []);
                }
            }
        } catch (err) {
            toast.error('Hikayeler yüklenemedi');
        } finally {
            setLoading(false);
        }
    }, [filter]);

    useEffect(() => {
        fetchStories();
    }, [fetchStories]);

    const handleAction = async (storyId: string, status: 'approved' | 'rejected') => {
        setActionLoading(storyId);
        try {
            const res = await fetch(`/api/admin/stories/${storyId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status }),
            });
            const data = await res.json();
            if (data.success) {
                toast.success(status === 'approved' ? 'Hikaye onaylandı' : 'Hikaye reddedildi');
                fetchStories();
            } else {
                toast.error(data.error?.message || 'İşlem başarısız');
            }
        } catch {
            toast.error('Bir hata oluştu');
        } finally {
            setActionLoading(null);
        }
    };

    const tabs = [
        { key: 'pending', label: 'Bekleyenler', icon: Clock },
        { key: 'approved', label: 'Onaylananlar', icon: CheckCircle },
        { key: 'rejected', label: 'Reddedilenler', icon: XCircle },
        { key: 'all', label: 'Tümü', icon: Eye },
    ];

    return (
        <div>
            <div className="flex items-center gap-3 mb-6">
                <MessageSquare className="h-7 w-7 text-pink-600" />
                <h2 className="text-3xl font-bold text-gray-900">{t('app.page.ba_ar_hikayeleri')}</h2>
            </div>

            {/* Filter Tabs */}
            <div className="flex gap-2 mb-6 flex-wrap">
                {tabs.map((tab) => {
                    const Icon = tab.icon;
                    return (
                        <button
                            key={tab.key}
                            onClick={() => setFilter(tab.key)}
                            className={`flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filter === tab.key
                                    ? 'bg-blue-600 text-white'
                                    : 'bg-white text-gray-600 hover:bg-gray-100 border border-gray-200'
                                }`}
                        >
                            <Icon className="h-4 w-4" />
                            {tab.label}
                        </button>
                    );
                })}
            </div>

            {/* Stories List */}
            {loading ? (
                <div className="space-y-4">
                    {Array.from({ length: 3 }).map((_, i) => (
                        <div key={i} className="bg-white rounded-lg border p-6 animate-pulse">
                            <div className="h-5 bg-gray-200 rounded w-1/3 mb-3" />
                            <div className="h-4 bg-gray-200 rounded w-2/3 mb-2" />
                            <div className="h-4 bg-gray-200 rounded w-1/2" />
                        </div>
                    ))}
                </div>
            ) : stories.length === 0 ? (
                <div className="bg-white rounded-lg border p-12 text-center">
                    <MessageSquare className="h-12 w-12 text-gray-300 mx-auto mb-4" />
                    <p className="text-gray-500 text-lg">{t('app.page.bu_kategoride_hikaye_bulunamad')}</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {stories.map((story) => {
                        const { t } = useTranslation();
                        const config = statusConfig[story.status];
                        const StatusIcon = config.icon;
                        const isExpanded = expandedStory === story.story_id;

                        return (
                            <div
                                key={story.story_id}
                                className="bg-white rounded-lg border border-gray-200 overflow-hidden"
                            >
                                {/* Header */}
                                <div
                                    className="p-5 cursor-pointer hover:bg-gray-50 transition-colors"
                                    onClick={() => setExpandedStory(isExpanded ? null : story.story_id)}
                                >
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-3 mb-1">
                                                <h3 className="font-semibold text-gray-900 truncate">{story.title}</h3>
                                                <Badge className={config.color}>
                                                    <StatusIcon className="h-3 w-3 mr-1" />
                                                    {config.label}
                                                </Badge>
                                            </div>
                                            <p className="text-sm text-gray-600">
                                                {story.user_name} · {story.university} · {story.field}
                                            </p>
                                            <p className="text-xs text-gray-400 mt-1">
                                                {new Date(story.created_at).toLocaleDateString('tr-TR', {
                                                    year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit',
                                                })}
                                            </p>
                                        </div>
                                        <div className="text-xs text-gray-400">
                                            {isExpanded ? '▲' : '▼'}
                                        </div>
                                    </div>
                                </div>

                                {/* Expanded Content */}
                                {isExpanded && (
                                    <div className="border-t border-gray-100 p-5 bg-gray-50">
                                        <div className="mb-4">
                                            <p className="text-sm font-medium text-gray-500 mb-1">{t('app.page.hikaye')}</p>
                                            <p className="text-gray-800 bg-white rounded-lg p-4 border italic">
                                                &ldquo;{story.quote}&rdquo;
                                            </p>
                                        </div>

                                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4 text-sm">
                                            <div>
                                                <p className="text-gray-500">{t('app.page.sim')}</p>
                                                <p className="font-medium">{story.user_name}</p>
                                            </div>
                                            <div>
                                                <p className="text-gray-500">E-posta</p>
                                                <p className="font-medium">{story.user_email}</p>
                                            </div>
                                            <div>
                                                <p className="text-gray-500">{t('app.page.niversite')}</p>
                                                <p className="font-medium">{story.university}</p>
                                            </div>
                                            <div>
                                                <p className="text-gray-500">{t('app.page.toplanan')}</p>
                                                <p className="font-medium text-green-600">
                                                    {formatAmount(story.funded_amount)}
                                                </p>
                                            </div>
                                        </div>

                                        {story.admin_note && (
                                            <div className="mb-4 bg-blue-50 border border-blue-200 rounded-lg p-3">
                                                <p className="text-xs font-medium text-blue-600 mb-1">{t('app.page.admin_notu')}</p>
                                                <p className="text-sm text-blue-800">{story.admin_note}</p>
                                            </div>
                                        )}

                                        {story.status === 'pending' && (
                                            <div className="flex gap-3 pt-2">
                                                <Button
                                                    onClick={() => handleAction(story.story_id, 'approved')}
                                                    disabled={actionLoading === story.story_id}
                                                    className="bg-green-600 hover:bg-green-700"
                                                >
                                                    <CheckCircle className="h-4 w-4 mr-2" />
                                                    {actionLoading === story.story_id ? 'İşleniyor...' : 'Onayla'}
                                                </Button>
                                                <Button
                                                    variant="outline"
                                                    onClick={() => handleAction(story.story_id, 'rejected')}
                                                    disabled={actionLoading === story.story_id}
                                                    className="border-red-300 text-red-600 hover:bg-red-50"
                                                >
                                                    <XCircle className="h-4 w-4 mr-2" />
                                                    {t('app.page.reddet')}</Button>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useRef } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useRouter } from 'next/navigation';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { validateEmail, sanitizeInput } from '@/lib/validation';
import { toast } from 'sonner';
import {
    Users, User, Mail, Globe, Phone, FileText, Upload, CheckCircle, AlertCircle,
    Loader2, X, Shield, ArrowRight, ArrowLeft, HelpCircle, Heart, School,
    Building, MapPin, GraduationCap, Calendar, Hash, ImageIcon, Video, Baby, Tag,
} from 'lucide-react';
import { COUNTRIES, FUNDING_CATEGORIES, TURKEY_CITIES } from '@/lib/constants';
type DocStatus = 'ready' | 'uploading' | 'uploaded' | 'failed';
interface DocumentItem { id: string; name: string; file: File; status: DocStatus; size: number; uploadedUrl?: string; }
interface PhotoItem { id: string; name: string; file: File; preview: string; }
interface VideoItem { id: string; name: string; file: File; preview: string; size: number; }

const MIN_DESCRIPTION_LENGTH = 100;
const MAX_PHOTOS = 5;
const MAX_PHOTO_SIZE = 5 * 1024 * 1024;
const MAX_VIDEO_SIZE = 50 * 1024 * 1024;

const STEPS = [
    { id: 1, label: 'Parent Info', icon: User },
    { id: 2, label: 'Child Info', icon: Baby },
    { id: 3, label: 'Verification', icon: Shield },
    { id: 4, label: 'Story & Media', icon: Heart },
    { id: 5, label: 'Review', icon: CheckCircle },
];

const FieldWrapper = ({ id, label, icon: Icon, error, children, required = true }: {
    id: string; label: string; icon: any; error?: string; children: React.ReactNode; required?: boolean;
}) => (
    <div className="space-y-2">
        <Label htmlFor={id} className="text-sm font-semibold text-slate-700 flex items-center gap-2">
            <Icon className="h-4 w-4 text-slate-400" /> {label}
            {required && <span className="text-red-400">*</span>}
        </Label>
        {children}
        {error && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
    </div>
);

const inputClass = (hasError: boolean) =>
    `h-12 rounded-xl border-slate-200 bg-white focus:border-purple-400 focus:ring-purple-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 ${hasError ? 'border-red-400 focus:border-red-400 focus:ring-red-400/20' : ''}`;

const selectTriggerClass = (hasError: boolean) =>
    `h-12 rounded-xl border-slate-200 bg-white focus:border-purple-400 focus:ring-purple-400/20 focus:ring-4 transition-all duration-200 ${hasError ? 'border-red-400' : ''}`;

export default function ParentApplyPage() {
    const router = useRouter();
    const { t } = useTranslation();
    const [loading, setLoading] = useState(false);
    const [submitted, setSubmitted] = useState(false);
    const [errors, setErrors] = useState<Record<string, string>>({});
    const [currentStep, setCurrentStep] = useState(1);

    const [formData, setFormData] = useState({
        parentFullName: '', parentEmail: '', parentPhone: '', parentCountry: '', parentCity: '', parentRelation: '',
        childFullName: '', childDob: '', childGender: '', schoolName: '', schoolCity: '',
        childGrade: '', childStudentId: '', category: '',
        story: '', targetAmount: '',
    });

    // Document states
    const [parentIdDocs, setParentIdDocs] = useState<DocumentItem[]>([]);
    const [childIdDocs, setChildIdDocs] = useState<DocumentItem[]>([]);
    const [reportCards, setReportCards] = useState<DocumentItem[]>([]);
    const [enrollmentDocs, setEnrollmentDocs] = useState<DocumentItem[]>([]);
    const parentIdRef = useRef<HTMLInputElement>(null);
    const childIdRef = useRef<HTMLInputElement>(null);
    const reportCardRef = useRef<HTMLInputElement>(null);
    const enrollmentRef = useRef<HTMLInputElement>(null);

    // Photo/video states
    const [photos, setPhotos] = useState<PhotoItem[]>([]);
    const [video, setVideo] = useState<VideoItem | null>(null);
    const photoInputRef = useRef<HTMLInputElement>(null);
    const videoInputRef = useRef<HTMLInputElement>(null);
    const [photoDragOver, setPhotoDragOver] = useState(false);

    const calculateAge = (dob: string): number => {
        if (!dob) return 0;
        const birth = new Date(dob);
        const today = new Date();
        let age = today.getFullYear() - birth.getFullYear();
        const m = today.getMonth() - birth.getMonth();
        if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
        return age;
    };

    const childAge = calculateAge(formData.childDob);

    const updateField = (field: string, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        if (errors[field]) setErrors(prev => ({ ...prev, [field]: '' }));
    };

    const validateCurrentStep = (): boolean => {
        const { t } = useTranslation();
        const e: Record<string, string> = {};
        if (currentStep === 1) {
            if (!formData.parentFullName.trim()) e.parentFullName = t('applyParent.validation.parentFullName');
            if (!formData.parentEmail.trim()) e.parentEmail = t('applyParent.validation.email');
            else if (!validateEmail(formData.parentEmail)) e.parentEmail = t('applyParent.validation.invalidEmail');
            if (!formData.parentCountry) e.parentCountry = t('applyParent.validation.country');
            if (!formData.parentRelation) e.parentRelation = t('applyParent.validation.relation');
            if (parentIdDocs.length === 0) e.parentIdDoc = t('applyParent.validation.parentId');
        }
        if (currentStep === 2) {
            if (!formData.childFullName.trim()) e.childFullName = t('applyParent.validation.childName');
            if (!formData.childDob) e.childDob = t('applyParent.validation.childDob');
            else if (childAge >= 18) e.childDob = t('applyParent.validation.childAge');
            if (!formData.schoolName.trim()) e.schoolName = t('applyParent.validation.schoolName');
            if (!formData.schoolCity.trim()) e.schoolCity = t('applyParent.validation.schoolCity');
            if (!formData.childGrade.trim()) e.childGrade = t('applyParent.validation.grade');
        }
        if (currentStep === 3) {
            if (childIdDocs.length === 0) e.childIdDoc = t('applyParent.validation.childId');
            if (reportCards.length === 0) e.reportCard = t('applyParent.validation.reportCard');
        }
        if (currentStep === 4) {
            if (!formData.story.trim()) e.story = t('applyParent.validation.story');
            else if (formData.story.trim().length < MIN_DESCRIPTION_LENGTH) e.story = t('applyParent.validation.storyMin', { min: MIN_DESCRIPTION_LENGTH });
            const minTarget = formData.parentCountry === 'TR' ? 2500 : 50;
            if (!formData.targetAmount) {
                e.targetAmount = t('applyParent.validation.targetAmount');
            } else if (parseInt(formData.targetAmount) < minTarget) {
                e.targetAmount = formData.parentCountry === 'TR' ? 'Minimum 2500 TL' : 'Minimum 50 USD';
            }
        }
        setErrors(e);
        return Object.keys(e).length === 0;
    };

    const nextStep = () => { if (validateCurrentStep()) { setCurrentStep(s => Math.min(s + 1, 5)); window.scrollTo({ top: 0, behavior: 'smooth' }); } };
    const prevStep = () => { setCurrentStep(s => Math.max(s - 1, 1)); window.scrollTo({ top: 0, behavior: 'smooth' }); };

    /* ── Doc upload helpers ── */
    const processDocFile = async (file: File, setDocs: React.Dispatch<React.SetStateAction<DocumentItem[]>>) => {
        const allowed = ['application/pdf', 'image/jpeg', 'image/png'];
        if (!allowed.includes(file.type)) { toast.error(t('apply.validation.fileType')); return; }
        if (file.size > 10 * 1024 * 1024) { toast.error(t('apply.validation.fileSize')); return; }
        const newDoc: DocumentItem = { id: Math.random().toString(36).substring(7), name: file.name, file, size: file.size, status: 'uploading' };
        setDocs(prev => [...prev, newDoc]);
        await new Promise(r => setTimeout(r, 1500));
        setDocs(prev => prev.map(d => d.id === newDoc.id ? { ...d, status: 'uploaded', uploadedUrl: `mock_${d.name}` } : d));
        toast.success(t('apply.documents.status.uploaded'));
    };

    const handleDocSelect = (e: React.ChangeEvent<HTMLInputElement>, setDocs: React.Dispatch<React.SetStateAction<DocumentItem[]>>) => {
        const file = e.target.files?.[0]; if (!file) return; e.target.value = ''; processDocFile(file, setDocs);
    };
    const removeDoc = (id: string, setDocs: React.Dispatch<React.SetStateAction<DocumentItem[]>>) => setDocs(prev => prev.filter(d => d.id !== id));

    /* ── Photo handlers ── */
    const processPhoto = (file: File) => {
        if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) { toast.error('Only JPG, PNG, WebP allowed'); return; }
        if (file.size > MAX_PHOTO_SIZE) { toast.error('Photo must be < 5 MB'); return; }
        if (photos.length >= MAX_PHOTOS) { toast.error(`Max ${MAX_PHOTOS} photos`); return; }
        setPhotos(prev => [...prev, { id: Math.random().toString(36).substring(7), name: file.name, file, preview: URL.createObjectURL(file) }]);
    };
    const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => { const files = e.target.files; if (!files) return; Array.from(files).forEach(processPhoto); e.target.value = ''; };
    const handlePhotoDrop = (e: React.DragEvent) => { e.preventDefault(); setPhotoDragOver(false); const files = e.dataTransfer.files; if (files) Array.from(files).forEach(processPhoto); };
    const removePhoto = (id: string) => { setPhotos(prev => { const p = prev.find(x => x.id === id); if (p) URL.revokeObjectURL(p.preview); return prev.filter(x => x.id !== id); }); };

    /* ── Video handler ── */
    const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file) return; e.target.value = '';
        if (!['video/mp4', 'video/webm'].includes(file.type)) { toast.error('Only MP4, WebM allowed'); return; }
        if (file.size > MAX_VIDEO_SIZE) { toast.error('Video must be < 50 MB'); return; }
        if (video) URL.revokeObjectURL(video.preview);
        setVideo({ id: Math.random().toString(36).substring(7), name: file.name, file, preview: URL.createObjectURL(file), size: file.size });
    };
    const removeVideo = () => { if (video) { URL.revokeObjectURL(video.preview); setVideo(null); } };

    /* ── Submit ── */
    const handleSubmit = async () => {
        if (loading || submitted) return;
        setLoading(true); setSubmitted(true);
        try {
            const response = await fetch('/api/ops/applications', {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    type: 'parent',
                    fullName: sanitizeInput(formData.parentFullName),
                    email: formData.parentEmail.trim().toLowerCase(),
                    phone: formData.parentPhone,
                    country: formData.parentCountry,
                    city: formData.parentCity || undefined,
                    category: formData.category || undefined,
                    parentRelation: formData.parentRelation,
                    childName: sanitizeInput(formData.childFullName),
                    childDob: formData.childDob,
                    childGender: formData.childGender,
                    childSchool: sanitizeInput(formData.schoolName),
                    childSchoolCity: sanitizeInput(formData.schoolCity),
                    childGrade: formData.childGrade,
                    childStudentId: formData.childStudentId,
                    needSummary: sanitizeInput(formData.story),
                    story: sanitizeInput(formData.story),
                    targetAmount: parseInt(formData.targetAmount) || 0,
                    documents: [
                        ...parentIdDocs.map(d => `parentId:${d.name}`),
                        ...childIdDocs.map(d => `childId:${d.name}`),
                        ...reportCards.map(d => `reportCard:${d.name}`),
                        ...enrollmentDocs.map(d => `enrollment:${d.name}`),
                    ],
                    photoCount: photos.length,
                    hasVideo: !!video,
                }),
            });
            const result = await response.json();
            if (!response.ok || !result.success) throw new Error(result.error || t('applyParent.submitError'));
            toast.success(t('applyParent.submitSuccess'));
            setTimeout(() => router.push('/'), 1500);
        } catch (error: any) {
            toast.error(error.message || t('applyParent.submitError'));
            setSubmitted(false);
        } finally { setLoading(false); }
    };

    const storyLength = formData.story.trim().length;

    /* ── Doc list component ── */
    const DocList = ({ docs, setDocs }: { docs: DocumentItem[]; setDocs: React.Dispatch<React.SetStateAction<DocumentItem[]>> }) => (
        docs.length > 0 ? (
            <div className="space-y-2 mt-2">
                {docs.map(doc => (
                    <div key={doc.id} className="flex items-center justify-between bg-slate-50 border border-slate-100 rounded-xl px-4 py-3">
                        <div className="flex items-center gap-3">
                            <FileText className="h-5 w-5 text-purple-500" />
                            <div><p className="text-sm font-medium text-slate-700">{doc.name}</p><p className="text-xs text-slate-400">{(doc.size / 1024).toFixed(1)} KB</p></div>
                        </div>
                        <div className="flex items-center gap-2">
                            {doc.status === 'uploading' && <Loader2 className="h-4 w-4 text-purple-500 animate-spin" />}
                            {doc.status === 'uploaded' && <CheckCircle className="h-4 w-4 text-green-500" />}
                            {doc.status === 'failed' && <AlertCircle className="h-4 w-4 text-red-500" />}
                            <button onClick={() => removeDoc(doc.id, setDocs)} className="text-slate-400 hover:text-red-500 transition-colors"><X className="h-4 w-4" /></button>
                        </div>
                    </div>
                ))}
            </div>
        ) : null
    );

    /* ── Upload Zone component ── */
    const UploadZone = ({ label, hint, inputRef, docs, setDocs, error }: {
        label: string; hint: string; inputRef: React.RefObject<HTMLInputElement>; docs: DocumentItem[];
        setDocs: React.Dispatch<React.SetStateAction<DocumentItem[]>>; error?: string;
    }) => (
        <div className="space-y-2">
            <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                <Upload className="h-4 w-4 text-slate-400" /> {label} <span className="text-red-400">*</span>
            </Label>
            <p className="text-xs text-slate-400">{hint}</p>
            <div className="border-2 border-dashed rounded-xl p-4 text-center border-slate-200 hover:border-purple-300 transition-colors cursor-pointer"
                onClick={() => inputRef.current?.click()}>
                <Upload className="h-6 w-6 text-slate-400 mx-auto mb-1" />
                <p className="text-sm text-slate-500">{t('applyParent.uploadClick')}</p>
                <p className="text-xs text-slate-400 mt-1">{t('app.page.pdf_jpg_png_max_10_mb')}</p>
                <input ref={inputRef as any} type="file" className="hidden" accept=".pdf,.jpg,.jpeg,.png" onChange={(e) => handleDocSelect(e, setDocs)} />
            </div>
            <DocList docs={docs} setDocs={setDocs} />
            {error && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
        </div>
    );

    if (submitted && !loading) {
        return (
            <div className="min-h-screen flex flex-col bg-slate-50">
                <Navbar />
                <main className="flex-grow flex items-center justify-center py-20">
                    <div className="max-w-md mx-auto text-center bg-white rounded-3xl shadow-lg p-10">
                        <div className="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center mx-auto mb-6">
                            <CheckCircle className="h-10 w-10 text-green-600" />
                        </div>
                        <h2 className="text-2xl font-bold text-slate-900 mb-3">{t('applyParent.successTitle')}</h2>
                        <p className="text-slate-500 mb-6">{t('applyParent.successDesc')}</p>
                        <Button onClick={() => router.push('/')} className="bg-purple-600 hover:bg-purple-700">{t('applyParent.backToHome')}</Button>
                    </div>
                </main>
                <Footer />
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col bg-slate-50">
            <Navbar />
            <main className="flex-grow">
                {/* HERO */}
                <section className="relative overflow-hidden bg-gradient-to-br from-purple-600 via-violet-600 to-purple-800">
                    <div className="absolute inset-0 pointer-events-none">
                        <div className="absolute -top-24 -right-24 w-[500px] h-[500px] bg-white/5 rounded-full blur-[80px]" />
                        <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-white/5 rounded-full blur-[80px]" />
                        <div className="absolute inset-0 opacity-[0.04]" style={{ backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)', backgroundSize: '32px 32px' }} />
                    </div>
                    <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 sm:py-20">
                        <div className="max-w-3xl mx-auto text-center">
                            <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md border border-white/20 rounded-full px-5 py-2 mb-6">
                                <Users className="h-4 w-4 text-yellow-300" />
                                <span className="text-sm text-white/90 font-medium">{t('applyParent.badge')}</span>
                            </div>
                            <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-4 leading-tight">
                                {t('applyParent.heroTitle')}<br />
                                <span className="bg-gradient-to-r from-yellow-200 via-amber-200 to-orange-200 bg-clip-text text-transparent">
                                    {t('applyParent.heroHighlight')}
                                </span>
                            </h1>
                            <p className="text-base sm:text-lg text-purple-100/80 leading-relaxed max-w-xl mx-auto">{t('applyParent.heroDesc')}</p>
                        </div>
                    </div>
                    <div className="absolute bottom-0 left-0 right-0">
                        <svg viewBox="0 0 1440 60" fill="none" className="w-full"><path d="M0 60L60 52C120 44 240 28 360 24C480 20 600 28 720 32C840 36 960 36 1080 32C1200 28 1320 20 1380 16L1440 12V60H0Z" fill="#f8fafc" /></svg>
                    </div>
                </section>

                {/* MAIN CONTENT */}
                <section className="py-10 sm:py-14">
                    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                        <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">
                            {/* LEFT: Form */}
                            <div className="lg:w-[65%]">
                                {/* Step Indicator */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-5 mb-8">
                                    <div className="flex items-center justify-between">
                                        {STEPS.map((step, i) => {
                                            const { t } = useTranslation();
                                            const Icon = step.icon;
                                            const isActive = currentStep === step.id;
                                            const isCompleted = currentStep > step.id;
                                            return (
                                                <div key={step.id} className="flex items-center flex-1">
                                                    <button type="button" onClick={() => { if (step.id < currentStep) setCurrentStep(step.id); }}
                                                        className={`flex items-center gap-2 transition-all duration-300 ${isActive ? 'text-purple-600' : isCompleted ? 'text-purple-500 cursor-pointer' : 'text-slate-300'}`}>
                                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-300 ${isActive ? 'bg-purple-500 text-white shadow-lg shadow-purple-500/30' : isCompleted ? 'bg-purple-100 text-purple-600' : 'bg-slate-100 text-slate-400'}`}>
                                                            {isCompleted ? <CheckCircle className="h-5 w-5" /> : <Icon className="h-5 w-5" />}
                                                        </div>
                                                        <span className="text-xs font-medium hidden lg:block">{t(`applyParent.steps.step${step.id}`)}</span>
                                                    </button>
                                                    {i < STEPS.length - 1 && <div className="flex-1 mx-2"><div className={`h-[2px] rounded-full transition-colors duration-300 ${isCompleted ? 'bg-purple-300' : 'bg-slate-100'}`} /></div>}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>

                                {/* Form Card */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
                                    {/* STEP 1 - Parent Info */}
                                    {currentStep === 1 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-purple-50 flex items-center justify-center"><User className="h-5 w-5 text-purple-500" /></div>
                                                <div><h2 className="text-xl font-bold text-slate-900">{t('applyParent.step1.title')}</h2><p className="text-sm text-slate-400">{t('applyParent.step1.subtitle')}</p></div>
                                            </div>
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                                <FieldWrapper id="parentFullName" label={t('applyParent.labels.parentFullName')} icon={User} error={errors.parentFullName}>
                                                    <Input id="parentFullName" value={formData.parentFullName} onChange={e => updateField('parentFullName', e.target.value)} placeholder={t('applyParent.placeholders.parentFullName')} className={inputClass(!!errors.parentFullName)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="parentEmail" label={t('applyParent.labels.email')} icon={Mail} error={errors.parentEmail}>
                                                    <Input id="parentEmail" type="email" value={formData.parentEmail} onChange={e => updateField('parentEmail', e.target.value)} placeholder={t('applyParent.placeholders.email')} className={inputClass(!!errors.parentEmail)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="parentPhone" label={t('applyParent.labels.phone')} icon={Phone} error={errors.parentPhone} required={false}>
                                                    <Input id="parentPhone" type="tel" value={formData.parentPhone} onChange={e => updateField('parentPhone', e.target.value)} placeholder={t('app.page.90_5xx_xxx_xx_xx')} className={inputClass(false)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="parentCountry" label={t('applyParent.labels.country')} icon={Globe} error={errors.parentCountry}>
                                                    <Select value={formData.parentCountry} onValueChange={(v) => updateField('parentCountry', v)}>
                                                        <SelectTrigger id="parentCountry" className={selectTriggerClass(!!errors.parentCountry)}><SelectValue placeholder={t('applyParent.placeholders.country')} /></SelectTrigger>
                                                        <SelectContent>
                                                            {COUNTRIES.map((c, index) => (
                                                                <SelectItem key={c.value} value={c.value}>
                                                                    {c.flag} {c.labelTr}{index === 0 ? '' : ` / ${c.label}`}
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>
                                                {formData.parentCountry === 'TR' && (
                                                    <FieldWrapper id="parentCity" label={t('app.page.ehir_city')} icon={MapPin} error={errors.parentCity} required={false}>
                                                        <Select value={formData.parentCity} onValueChange={(v) => updateField('parentCity', v)}>
                                                            <SelectTrigger id="parentCity" className={selectTriggerClass(false)}><SelectValue placeholder={t('app.page.ehir_se_iniz')} /></SelectTrigger>
                                                            <SelectContent>
                                                                {TURKEY_CITIES.map((city) => (
                                                                    <SelectItem key={city} value={city}>{city}</SelectItem>
                                                                ))}
                                                            </SelectContent>
                                                        </Select>
                                                    </FieldWrapper>
                                                )}
                                                <div className="md:col-span-2">
                                                    <FieldWrapper id="parentRelation" label={t('applyParent.labels.relation')} icon={Users} error={errors.parentRelation}>
                                                        <Select value={formData.parentRelation} onValueChange={v => updateField('parentRelation', v)}>
                                                            <SelectTrigger id="parentRelation" className={selectTriggerClass(!!errors.parentRelation)}><SelectValue placeholder={t('applyParent.placeholders.selectRelation')} /></SelectTrigger>
                                                            <SelectContent>
                                                                <SelectItem value="mother">{t('applyParent.options.mother')}</SelectItem>
                                                                <SelectItem value="father">{t('applyParent.options.father')}</SelectItem>
                                                                <SelectItem value="guardian">{t('applyParent.options.guardian')}</SelectItem>
                                                            </SelectContent>
                                                        </Select>
                                                    </FieldWrapper>
                                                </div>
                                            </div>
                                            <UploadZone label={t('applyParent.labels.parentId')} hint={t('applyParent.hints.parentId')} inputRef={parentIdRef} docs={parentIdDocs} setDocs={setParentIdDocs} error={errors.parentIdDoc} />
                                        </div>
                                    )}

                                    {/* STEP 2 - Child Info */}
                                    {currentStep === 2 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-pink-50 flex items-center justify-center"><Baby className="h-5 w-5 text-pink-500" /></div>
                                                <div><h2 className="text-xl font-bold text-slate-900">{t('applyParent.step2.title')}</h2><p className="text-sm text-slate-400">{t('applyParent.step2.subtitle')}</p></div>
                                            </div>
                                            <div className="bg-purple-50/50 border border-purple-100 rounded-xl p-4 flex items-start gap-3">
                                                <HelpCircle className="h-5 w-5 text-purple-500 flex-shrink-0 mt-0.5" />
                                                <p className="text-sm text-purple-700">{t('applyParent.hints.childAgeNote')}</p>
                                            </div>
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                                <FieldWrapper id="childFullName" label={t('applyParent.labels.childName')} icon={User} error={errors.childFullName}>
                                                    <Input id="childFullName" value={formData.childFullName} onChange={e => updateField('childFullName', e.target.value)} placeholder={t('applyParent.placeholders.childName')} className={inputClass(!!errors.childFullName)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="childDob" label={t('applyParent.labels.childDob')} icon={Calendar} error={errors.childDob}>
                                                    <Input id="childDob" type="date" value={formData.childDob} onChange={e => updateField('childDob', e.target.value)} className={inputClass(!!errors.childDob)} />
                                                    {formData.childDob && <p className="text-xs text-slate-500 mt-1">{t('applyParent.labels.age')}: {childAge}</p>}
                                                </FieldWrapper>
                                                <FieldWrapper id="childGender" label={t('applyParent.labels.gender')} icon={User} error={errors.childGender} required={false}>
                                                    <Select value={formData.childGender} onValueChange={v => updateField('childGender', v)}>
                                                        <SelectTrigger id="childGender" className={selectTriggerClass(false)}><SelectValue placeholder={t('applyParent.placeholders.selectGender')} /></SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="male">{t('applyParent.options.male')}</SelectItem>
                                                            <SelectItem value="female">{t('applyParent.options.female')}</SelectItem>
                                                            <SelectItem value="other">{t('applyParent.options.other')}</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>
                                                <FieldWrapper id="childStudentId" label={t('applyParent.labels.studentId')} icon={Hash} error={errors.childStudentId} required={false}>
                                                    <Input id="childStudentId" value={formData.childStudentId} onChange={e => updateField('childStudentId', e.target.value)} placeholder={t('applyParent.placeholders.studentId')} className={inputClass(false)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="schoolName" label={t('applyParent.labels.schoolName')} icon={School} error={errors.schoolName}>
                                                    <Input id="schoolName" value={formData.schoolName} onChange={e => updateField('schoolName', e.target.value)} placeholder={t('applyParent.placeholders.schoolName')} className={inputClass(!!errors.schoolName)} />
                                                </FieldWrapper>
                                                <FieldWrapper id="schoolCity" label={t('applyParent.labels.schoolCity')} icon={MapPin} error={errors.schoolCity}>
                                                    <Input id="schoolCity" value={formData.schoolCity} onChange={e => updateField('schoolCity', e.target.value)} placeholder={t('applyParent.placeholders.schoolCity')} className={inputClass(!!errors.schoolCity)} />
                                                </FieldWrapper>
                                                <div className="md:col-span-2">
                                                    <FieldWrapper id="childGrade" label={t('applyParent.labels.grade')} icon={GraduationCap} error={errors.childGrade}>
                                                        <Input id="childGrade" value={formData.childGrade} onChange={e => updateField('childGrade', e.target.value)} placeholder={t('applyParent.placeholders.grade')} className={inputClass(!!errors.childGrade)} />
                                                    </FieldWrapper>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* STEP 3 - Verification Documents */}
                                    {currentStep === 3 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center"><Shield className="h-5 w-5 text-amber-500" /></div>
                                                <div><h2 className="text-xl font-bold text-slate-900">{t('applyParent.step3.title')}</h2><p className="text-sm text-slate-400">{t('applyParent.step3.subtitle')}</p></div>
                                            </div>
                                            <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-4 text-sm text-amber-700">
                                                <p className="font-medium mb-1">{t('applyParent.docTips.title')}</p>
                                                <ul className="list-disc list-inside space-y-1 text-amber-600">
                                                    <li>{t('applyParent.docTips.tip1')}</li>
                                                    <li>{t('applyParent.docTips.tip2')}</li>
                                                    <li>{t('applyParent.docTips.tip3')}</li>
                                                </ul>
                                            </div>
                                            <UploadZone label={t('applyParent.labels.childId')} hint={t('applyParent.hints.childId')} inputRef={childIdRef} docs={childIdDocs} setDocs={setChildIdDocs} error={errors.childIdDoc} />
                                            <UploadZone label={t('applyParent.labels.reportCard')} hint={t('applyParent.hints.reportCard')} inputRef={reportCardRef} docs={reportCards} setDocs={setReportCards} error={errors.reportCard} />
                                            <UploadZone label={t('applyParent.labels.enrollment')} hint={t('applyParent.hints.enrollment')} inputRef={enrollmentRef} docs={enrollmentDocs} setDocs={setEnrollmentDocs} />
                                        </div>
                                    )}

                                    {/* STEP 4 - Story & Media */}
                                    {currentStep === 4 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-rose-50 flex items-center justify-center"><Heart className="h-5 w-5 text-rose-500" /></div>
                                                <div><h2 className="text-xl font-bold text-slate-900">{t('applyParent.step4.title')}</h2><p className="text-sm text-slate-400">{t('applyParent.step4.subtitle')}</p></div>
                                            </div>
                                            <div className="bg-rose-50/50 border border-rose-100 rounded-xl p-4 flex items-start gap-3">
                                                <HelpCircle className="h-5 w-5 text-rose-500 flex-shrink-0 mt-0.5" />
                                                <div className="text-sm text-rose-700 leading-relaxed">
                                                    <p className="font-medium mb-1">{t('applyParent.tips.title')}</p>
                                                    <ul className="list-disc list-inside space-y-1 text-rose-600">
                                                        <li>{t('applyParent.tips.tip1')}</li><li>{t('applyParent.tips.tip2')}</li><li>{t('applyParent.tips.tip3')}</li>
                                                    </ul>
                                                </div>
                                            </div>
                                            {/* Story */}
                                            <div className="space-y-2">
                                                <div className="flex justify-between items-center">
                                                    <Label htmlFor="story" className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                                        <FileText className="h-4 w-4 text-slate-400" />{t('applyParent.labels.story')}<span className="text-red-400">*</span>
                                                    </Label>
                                                    <div className="flex items-center gap-2">
                                                        <div className="h-1.5 w-20 rounded-full bg-slate-100 overflow-hidden">
                                                            <div className={`h-full rounded-full transition-all duration-300 ${storyLength >= MIN_DESCRIPTION_LENGTH ? 'bg-emerald-500' : 'bg-amber-400'}`}
                                                                style={{ width: `${Math.min(100, (storyLength / MIN_DESCRIPTION_LENGTH) * 100)}%` }} />
                                                        </div>
                                                        <span className={`text-xs font-medium ${storyLength < MIN_DESCRIPTION_LENGTH ? 'text-amber-500' : 'text-emerald-500'}`}>{storyLength}/{MIN_DESCRIPTION_LENGTH}</span>
                                                    </div>
                                                </div>
                                                <Textarea id="story" value={formData.story} onChange={e => updateField('story', e.target.value)} placeholder={t('applyParent.placeholders.story')} rows={8}
                                                    className={`rounded-xl border-slate-200 bg-white focus:border-purple-400 focus:ring-purple-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 resize-none ${errors.story ? 'border-red-400' : ''}`} />
                                                {errors.story && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="h-3 w-3" />{errors.story}</p>}
                                            </div>
                                            {/* Category */}
                                            <FieldWrapper id="category" label={t('app.page.htiya_kategorisi_need_category')} icon={Tag} error={errors.category} required={false}>
                                                <Select value={formData.category} onValueChange={(v) => updateField('category', v)}>
                                                    <SelectTrigger id="category" className={selectTriggerClass(!!errors.category)}><SelectValue placeholder={t('app.page.kategori_se_iniz_select_catego')} /></SelectTrigger>
                                                    <SelectContent>
                                                        {FUNDING_CATEGORIES.map((cat) => (
                                                            <SelectItem key={cat.value} value={cat.value}>{cat.labelTr} / {cat.label}</SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                            </FieldWrapper>
                                            {/* Target Amount */}
                                            <FieldWrapper id="targetAmount" label={t('applyParent.labels.targetAmount')} icon={Heart} error={errors.targetAmount}>
                                                <div className="relative">
                                                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-semibold text-sm">$</span>
                                                    <Input id="targetAmount" type="number" min={1} value={formData.targetAmount} onChange={e => updateField('targetAmount', e.target.value)} placeholder={t('applyParent.placeholders.targetAmount')} className={`${inputClass(!!errors.targetAmount)} pl-8`} />
                                                </div>
                                            </FieldWrapper>
                                            {/* Photos */}
                                            <div className="space-y-3">
                                                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2"><ImageIcon className="h-4 w-4 text-slate-400" />{t('applyParent.labels.photos')}</Label>
                                                <div onDragOver={e => { e.preventDefault(); setPhotoDragOver(true); }} onDragLeave={() => setPhotoDragOver(false)} onDrop={handlePhotoDrop}
                                                    className={`border-2 border-dashed rounded-2xl p-6 text-center transition-all duration-300 ${photoDragOver ? 'border-purple-400 bg-purple-50/50' : 'border-slate-200 hover:border-slate-300'}`}>
                                                    <ImageIcon className="h-8 w-8 text-slate-400 mx-auto mb-2" />
                                                    <p className="text-sm text-slate-500 mb-2">{t('applyParent.photos.dropText')}</p>
                                                    <Button type="button" variant="outline" onClick={() => photoInputRef.current?.click()} className="rounded-xl text-sm">{t('applyParent.photos.selectBtn')}</Button>
                                                    <input ref={photoInputRef} type="file" className="hidden" accept="image/jpeg,image/png,image/webp" multiple onChange={handlePhotoSelect} />
                                                    <p className="text-xs text-slate-400 mt-2">{t('app.page.jpg_png_webp_max_5_mb')}{t('applyParent.photos.maxCount')}</p>
                                                </div>
                                                {photos.length > 0 && (
                                                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                        {photos.map(photo => (
                                                            <div key={photo.id} className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-[4/3]">
                                                                <img src={photo.preview} alt={photo.name} className="w-full h-full object-cover" />
                                                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors duration-200" />
                                                                <button type="button" onClick={() => removePhoto(photo.id)} className="absolute top-2 right-2 w-7 h-7 rounded-full bg-red-500/80 hover:bg-red-600 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200"><X className="h-4 w-4" /></button>
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                            {/* Video */}
                                            <div className="space-y-3">
                                                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2"><Video className="h-4 w-4 text-slate-400" />{t('applyParent.labels.video')}</Label>
                                                {!video ? (
                                                    <div className="border-2 border-dashed rounded-xl p-4 text-center border-slate-200 hover:border-purple-300 transition-colors cursor-pointer" onClick={() => videoInputRef.current?.click()}>
                                                        <Video className="h-6 w-6 text-slate-400 mx-auto mb-1" />
                                                        <p className="text-sm text-slate-500">{t('applyParent.video.selectBtn')}</p>
                                                        <p className="text-xs text-slate-400 mt-1">{t('app.page.mp4_webm_max_50_mb')}</p>
                                                        <input ref={videoInputRef} type="file" className="hidden" accept="video/mp4,video/webm" onChange={handleVideoSelect} />
                                                    </div>
                                                ) : (
                                                    <div className="flex items-center justify-between bg-slate-50 border border-slate-100 rounded-xl px-4 py-3">
                                                        <div className="flex items-center gap-3">
                                                            <Video className="h-5 w-5 text-purple-500" />
                                                            <div><p className="text-sm font-medium text-slate-700">{video.name}</p><p className="text-xs text-slate-400">{(video.size / 1024 / 1024).toFixed(1)} MB</p></div>
                                                        </div>
                                                        <button onClick={removeVideo} className="text-slate-400 hover:text-red-500 transition-colors"><X className="h-4 w-4" /></button>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}

                                    {/* STEP 5 - Review */}
                                    {currentStep === 5 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-green-50 flex items-center justify-center"><CheckCircle className="h-5 w-5 text-green-500" /></div>
                                                <div><h2 className="text-xl font-bold text-slate-900">{t('applyParent.step5.title')}</h2><p className="text-sm text-slate-400">{t('applyParent.step5.subtitle')}</p></div>
                                            </div>
                                            {/* Summary */}
                                            <div className="space-y-4">
                                                <div className="bg-purple-50/50 border border-purple-100 rounded-xl p-4">
                                                    <h4 className="font-semibold text-purple-800 mb-2">{t('applyParent.review.parentInfo')}</h4>
                                                    <div className="grid grid-cols-2 gap-2 text-sm"><span className="text-slate-500">{t('applyParent.labels.parentFullName')}:</span><span className="text-slate-800">{formData.parentFullName}</span><span className="text-slate-500">{t('applyParent.labels.email')}:</span><span className="text-slate-800">{formData.parentEmail}</span><span className="text-slate-500">{t('applyParent.labels.relation')}:</span><span className="text-slate-800">{formData.parentRelation}</span><span className="text-slate-500">{t('applyParent.labels.country')}:</span><span className="text-slate-800">{formData.parentCountry}</span></div>
                                                </div>
                                                <div className="bg-pink-50/50 border border-pink-100 rounded-xl p-4">
                                                    <h4 className="font-semibold text-pink-800 mb-2">{t('applyParent.review.childInfo')}</h4>
                                                    <div className="grid grid-cols-2 gap-2 text-sm"><span className="text-slate-500">{t('applyParent.labels.childName')}:</span><span className="text-slate-800">{formData.childFullName}</span><span className="text-slate-500">{t('applyParent.labels.childDob')}:</span><span className="text-slate-800">{formData.childDob} ({childAge} {t('applyParent.review.yearsOld')})</span><span className="text-slate-500">{t('applyParent.labels.schoolName')}:</span><span className="text-slate-800">{formData.schoolName}</span><span className="text-slate-500">{t('applyParent.labels.grade')}:</span><span className="text-slate-800">{formData.childGrade}</span></div>
                                                </div>
                                                <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-4">
                                                    <h4 className="font-semibold text-amber-800 mb-2">{t('applyParent.review.documents')}</h4>
                                                    <div className="text-sm text-slate-600 space-y-1">
                                                        <p>📄 {t('applyParent.labels.parentId')}: {parentIdDocs.length} {t('applyParent.review.files')}</p>
                                                        <p>📄 {t('applyParent.labels.childId')}: {childIdDocs.length} {t('applyParent.review.files')}</p>
                                                        <p>📄 {t('applyParent.labels.reportCard')}: {reportCards.length} {t('applyParent.review.files')}</p>
                                                        <p>📄 {t('applyParent.labels.enrollment')}: {enrollmentDocs.length} {t('applyParent.review.files')}</p>
                                                    </div>
                                                </div>
                                                <div className="bg-rose-50/50 border border-rose-100 rounded-xl p-4">
                                                    <h4 className="font-semibold text-rose-800 mb-2">{t('applyParent.review.storyMedia')}</h4>
                                                    <p className="text-sm text-slate-600 line-clamp-3">{formData.story}</p>
                                                    <div className="mt-2 text-sm text-slate-500">
                                                        <span>{t('app.page.text')}{formData.targetAmount} {t('app.page.text')}{photos.length} {t('applyParent.review.photos')} {t('app.page.text')}{video ? 1 : 0} {t('applyParent.review.videos')}</span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Navigation */}
                                    <div className="p-6 sm:p-8 border-t border-slate-100 flex justify-between">
                                        {currentStep > 1 ? (
                                            <Button variant="outline" onClick={prevStep} className="rounded-xl gap-2"><ArrowLeft className="h-4 w-4" /> {t('applyParent.prev')}</Button>
                                        ) : (
                                            <Button variant="outline" onClick={() => router.push('/apply')} className="rounded-xl gap-2"><ArrowLeft className="h-4 w-4" /> {t('applyParent.back')}</Button>
                                        )}
                                        {currentStep < 5 ? (
                                            <Button onClick={nextStep} className="bg-purple-600 hover:bg-purple-700 rounded-xl gap-2">{t('applyParent.next')} <ArrowRight className="h-4 w-4" /></Button>
                                        ) : (
                                            <Button onClick={handleSubmit} disabled={loading} className="bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-700 hover:to-violet-700 rounded-xl gap-2 px-8">
                                                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
                                                {loading ? t('applyParent.submitting') : t('applyParent.submit')}
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* RIGHT: Sidebar */}
                            <div className="lg:w-[35%] space-y-6">
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                                    <div className="flex items-center gap-3 mb-4">
                                        <div className="w-10 h-10 rounded-xl bg-purple-50 flex items-center justify-center"><Shield className="h-5 w-5 text-purple-500" /></div>
                                        <h3 className="font-bold text-slate-900">{t('applyParent.sidebar.title')}</h3>
                                    </div>
                                    <ul className="space-y-3">
                                        {[1, 2, 3, 4].map(i => (
                                            <li key={i} className="flex items-start gap-2 text-sm text-slate-600">
                                                <CheckCircle className="h-4 w-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                                                <span>{t(`applyParent.sidebar.point${i}`)}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                                <div className="bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl p-6 text-white">
                                    <Users className="h-8 w-8 mb-3 text-purple-200" />
                                    <h3 className="font-bold text-lg mb-2">{t('applyParent.sidebar.bannerTitle')}</h3>
                                    <p className="text-purple-100 text-sm leading-relaxed">{t('applyParent.sidebar.bannerDesc')}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </section>
            </main>
            <Footer />
        </div>
    );
}

'use client';

import { useState, useRef } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useRouter } from 'next/navigation';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { validateEmail, sanitizeInput } from '@/lib/validation';
import { toast } from 'sonner';
import {
    School,
    User,
    Mail,
    Globe,
    Phone,
    DollarSign,
    BookOpen,
    Users,
    FileText,
    Upload,
    CheckCircle,
    AlertCircle,
    Loader2,
    X,
    Shield,
    ArrowRight,
    ArrowLeft,
    HelpCircle,
    GraduationCap,
    Building,
    Hash,
    MapPin,
    ImageIcon,
    Video,
    Briefcase,
} from 'lucide-react';
import { COUNTRIES, TURKEY_CITIES } from '@/lib/constants';
type DocStatus = 'ready' | 'uploading' | 'uploaded' | 'failed';

interface DocumentItem {
    id: string;
    name: string;
    file: File;
    status: DocStatus;
    size: number;
    uploadedUrl?: string;
}

interface PhotoItem {
    id: string;
    name: string;
    file: File;
    preview: string;
}

interface VideoItem {
    id: string;
    name: string;
    file: File;
    preview: string;
    size: number;
}

const MIN_DESCRIPTION_LENGTH = 100;
const MAX_PHOTOS = 10;
const MAX_PHOTO_SIZE = 5 * 1024 * 1024; // 5 MB
const MAX_VIDEO_SIZE = 50 * 1024 * 1024; // 50 MB

const STEPS = [
    { id: 1, label: 'Okul Bilgileri', icon: School },
    { id: 2, label: 'Başvuran Bilgileri', icon: User },
    { id: 3, label: 'Proje Detayı', icon: FileText },
    { id: 4, label: 'Medya & Belgeler', icon: Upload },
    { id: 5, label: 'İnceleme', icon: CheckCircle },
];

/* ── FieldWrapper ── */
const FieldWrapper = ({
    id,
    label,
    icon: Icon,
    error,
    children,
    required = true,
}: {
    id: string;
    label: string;
    icon: any;
    error?: string;
    children: React.ReactNode;
    required?: boolean;
}) => (
    <div className="space-y-2">
        <Label htmlFor={id} className="text-sm font-semibold text-slate-700 flex items-center gap-2">
            <Icon className="h-4 w-4 text-slate-400" />
            {label}
            {required && <span className="text-red-400">*</span>}
        </Label>
        {children}
        {error && (
            <p className="text-xs text-red-500 flex items-center gap-1">
                <AlertCircle className="h-3 w-3" />
                {error}
            </p>
        )}
    </div>
);

const inputClass = (hasError: boolean) =>
    `h-12 rounded-xl border-slate-200 bg-white focus:border-amber-400 focus:ring-amber-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 ${hasError ? 'border-red-400 focus:border-red-400 focus:ring-red-400/20' : ''}`;

const selectTriggerClass = (hasError: boolean) =>
    `h-12 rounded-xl border-slate-200 bg-white focus:border-amber-400 focus:ring-amber-400/20 focus:ring-4 transition-all duration-200 ${hasError ? 'border-red-400' : ''}`;

export default function SchoolApplyPage() {
    const router = useRouter();
    const { t } = useTranslation();
    const [loading, setLoading] = useState(false);
    const [submitted, setSubmitted] = useState(false);
    const [errors, setErrors] = useState<Record<string, string>>({});
    const [currentStep, setCurrentStep] = useState(1);

    const [formData, setFormData] = useState({
        // School info
        schoolName: '',
        schoolCountry: '',
        schoolCity: '',
        schoolDistrict: '',
        schoolAddress: '',
        schoolType: '',
        studentTotal: '',
        schoolWebsite: '',
        schoolPhone: '',
        // Applicant info
        applicantFullName: '',
        applicantEmail: '',
        applicantPhone: '',
        applicantRole: '',
        applicantTitle: '',
        // Project info
        projectTitle: '',
        projectCategory: '',
        needSummary: '',
        targetAmount: '',
        beneficiaryCount: '',
    });

    // Documents
    const [documents, setDocuments] = useState<DocumentItem[]>([]);
    const [documentNameInput, setDocumentNameInput] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [dragOver, setDragOver] = useState(false);

    // Photos
    const [photos, setPhotos] = useState<PhotoItem[]>([]);
    const [photoDragOver, setPhotoDragOver] = useState(false);
    const photoInputRef = useRef<HTMLInputElement>(null);

    // Video
    const [video, setVideo] = useState<VideoItem | null>(null);
    const videoInputRef = useRef<HTMLInputElement>(null);

    const updateField = (field: string, value: string) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
        if (errors[field]) setErrors((prev) => ({ ...prev, [field]: '' }));
    };

    const validateCurrentStep = (): boolean => {
        const { t } = useTranslation();
        const newErrors: Record<string, string> = {};

        if (currentStep === 1) {
            if (!formData.schoolName.trim()) newErrors.schoolName = t('applySchool.validation.schoolName');
            if (!formData.schoolCity.trim()) newErrors.schoolCity = t('applySchool.validation.schoolCity');
            if (!formData.schoolDistrict.trim()) newErrors.schoolDistrict = t('applySchool.validation.schoolDistrict');
            if (!formData.schoolType) newErrors.schoolType = t('applySchool.validation.schoolType');
            if (!formData.studentTotal || parseInt(formData.studentTotal) < 1)
                newErrors.studentTotal = t('applySchool.validation.studentTotal');
        }

        if (currentStep === 2) {
            if (!formData.applicantFullName.trim()) newErrors.applicantFullName = t('applySchool.validation.applicantFullName');
            else if (formData.applicantFullName.trim().length < 2) newErrors.applicantFullName = t('applySchool.validation.invalidName');
            if (!formData.applicantEmail.trim()) newErrors.applicantEmail = t('applySchool.validation.email');
            else if (!validateEmail(formData.applicantEmail)) newErrors.applicantEmail = t('applySchool.validation.invalidEmail');
            if (!formData.applicantRole) newErrors.applicantRole = t('applySchool.validation.applicantRole');
        }

        if (currentStep === 3) {
            if (!formData.projectTitle.trim()) newErrors.projectTitle = t('applySchool.validation.projectTitle');
            if (!formData.projectCategory) newErrors.projectCategory = t('applySchool.validation.projectCategory');
            if (!formData.needSummary.trim()) newErrors.needSummary = t('applySchool.validation.needSummary');
            else if (formData.needSummary.trim().length < MIN_DESCRIPTION_LENGTH) {
                newErrors.needSummary = t('applySchool.validation.needSummaryMin', { min: MIN_DESCRIPTION_LENGTH });
            }
            const minTarget = formData.schoolCountry === 'TR' ? 2500 : 50;
            if (!formData.targetAmount) {
                newErrors.targetAmount = t('applySchool.validation.targetAmount');
            } else if (parseInt(formData.targetAmount) < minTarget) {
                newErrors.targetAmount = formData.schoolCountry === 'TR' ? 'Minimum 2500 TL' : 'Minimum 50 USD';
            }
            if (!formData.beneficiaryCount || parseInt(formData.beneficiaryCount) < 1) newErrors.beneficiaryCount = t('applySchool.validation.beneficiaryCount');
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const nextStep = () => {
        if (validateCurrentStep()) {
            setCurrentStep((s) => Math.min(s + 1, 5));
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const prevStep = () => {
        setCurrentStep((s) => Math.max(s - 1, 1));
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    /* ── Document handlers ── */
    const handleAddDocumentClick = () => fileInputRef.current?.click();

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        e.target.value = '';
        await processFile(file);
    };

    const processFile = async (file: File) => {
        const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png'];
        const maxSize = 10 * 1024 * 1024;
        if (!allowedTypes.includes(file.type)) { toast.error(t('apply.validation.fileType')); return; }
        if (file.size > maxSize) { toast.error(t('apply.validation.fileSize')); return; }
        const name = documentNameInput.trim() || file.name;
        const newDoc: DocumentItem = {
            id: Math.random().toString(36).substring(7),
            name,
            file,
            size: file.size,
            status: 'ready',
        };
        setDocuments((prev) => [...prev, newDoc]);
        setDocumentNameInput('');
        await simulateUpload(newDoc.id);
    };

    const handleDrop = async (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        const file = e.dataTransfer.files?.[0];
        if (file) await processFile(file);
    };

    const simulateUpload = async (docId: string) => {
        setDocuments((prev) => prev.map((d) => (d.id === docId ? { ...d, status: 'uploading' } : d)));
        try {
            await new Promise((resolve) => setTimeout(resolve, 1500));
            setDocuments((prev) => prev.map((d) => (d.id === docId ? { ...d, status: 'uploaded', uploadedUrl: `mock_url_${d.name}` } : d)));
            toast.success(t('apply.documents.status.uploaded'));
        } catch {
            setDocuments((prev) => prev.map((d) => (d.id === docId ? { ...d, status: 'failed' } : d)));
            toast.error(t('apply.documents.status.failed'));
        }
    };

    const handleRemoveDocument = (id: string) => setDocuments((prev) => prev.filter((d) => d.id !== id));

    /* ── Photo handlers ── */
    const processPhoto = (file: File) => {
        const allowedTypes = ['image/jpeg', 'image/png', 'image/webp'];
        if (!allowedTypes.includes(file.type)) { toast.error(t('applySchool.photos.typeError')); return; }
        if (file.size > MAX_PHOTO_SIZE) { toast.error(t('applySchool.photos.sizeError')); return; }
        if (photos.length >= MAX_PHOTOS) { toast.error(t('applySchool.photos.maxError')); return; }
        const newPhoto: PhotoItem = {
            id: Math.random().toString(36).substring(7),
            name: file.name,
            file,
            preview: URL.createObjectURL(file),
        };
        setPhotos((prev) => [...prev, newPhoto]);
    };

    const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;
        Array.from(files).forEach(processPhoto);
        e.target.value = '';
    };

    const handlePhotoDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setPhotoDragOver(false);
        const files = e.dataTransfer.files;
        if (files) Array.from(files).forEach(processPhoto);
    };

    const handleRemovePhoto = (id: string) => {
        setPhotos((prev) => {
            const photo = prev.find((p) => p.id === id);
            if (photo) URL.revokeObjectURL(photo.preview);
            return prev.filter((p) => p.id !== id);
        });
    };

    /* ── Video handler ── */
    const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        e.target.value = '';
        if (!['video/mp4', 'video/webm', 'video/quicktime'].includes(file.type)) {
            toast.error(t('applySchool.video.typeError'));
            return;
        }
        if (file.size > MAX_VIDEO_SIZE) {
            toast.error(t('applySchool.video.sizeError'));
            return;
        }
        if (video) URL.revokeObjectURL(video.preview);
        setVideo({
            id: Math.random().toString(36).substring(7),
            name: file.name,
            file,
            preview: URL.createObjectURL(file),
            size: file.size,
        });
    };

    const removeVideo = () => {
        if (video) {
            URL.revokeObjectURL(video.preview);
            setVideo(null);
        }
    };

    /* ── Submit ── */
    const handleSubmit = async () => {
        const { t } = useTranslation();
        if (loading || submitted) return;

        // Final validation across all steps
        if (!formData.schoolName.trim() || !formData.schoolCity.trim() || !formData.schoolType) { setCurrentStep(1); return; }
        if (!formData.applicantFullName.trim() || !formData.applicantEmail.trim() || !validateEmail(formData.applicantEmail) || !formData.applicantRole) { setCurrentStep(2); return; }
        if (!formData.projectTitle.trim() || !formData.projectCategory || !formData.needSummary.trim() || formData.needSummary.trim().length < MIN_DESCRIPTION_LENGTH) { setCurrentStep(3); return; }
        const minTarget = formData.schoolCountry === 'TR' ? 2500 : 50;
        if (!formData.targetAmount || parseInt(formData.targetAmount) < minTarget || !formData.beneficiaryCount || parseInt(formData.beneficiaryCount) < 1) { setCurrentStep(3); return; }

        const pendingDocs = documents.some((d) => d.status === 'uploading');
        if (pendingDocs) { toast.warning(t('apply.validation.waitUpload')); return; }

        setLoading(true);
        setSubmitted(true);

        try {
            const documentNames = documents.map((d) => d.name);
            const response = await fetch('/api/ops/applications', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    type: 'school',
                    // School info
                    schoolName: sanitizeInput(formData.schoolName),
                    schoolCity: sanitizeInput(formData.schoolCity),
                    schoolDistrict: sanitizeInput(formData.schoolDistrict),
                    schoolAddress: sanitizeInput(formData.schoolAddress),
                    schoolType: formData.schoolType,
                    studentTotal: parseInt(formData.studentTotal) || 0,
                    schoolWebsite: formData.schoolWebsite || null,
                    schoolPhone: formData.schoolPhone || null,
                    // Applicant info
                    fullName: sanitizeInput(formData.applicantFullName),
                    email: formData.applicantEmail.trim().toLowerCase(),
                    phone: formData.applicantPhone || null,
                    applicantRole: formData.applicantRole,
                    applicantTitle: sanitizeInput(formData.applicantTitle) || null,
                    // Project info
                    projectTitle: sanitizeInput(formData.projectTitle),
                    projectCategory: formData.projectCategory,
                    needSummary: sanitizeInput(formData.needSummary),
                    targetAmount: parseInt(formData.targetAmount) || 0,
                    beneficiaryCount: parseInt(formData.beneficiaryCount) || 0,
                    // Media
                    documents: documentNames,
                    photoCount: photos.length,
                    hasVideo: !!video,
                    country: formData.schoolCountry || 'TR',
                    city: formData.schoolCity || undefined,
                }),
            });
            const result = await response.json();
            if (!response.ok || !result.success) throw new Error(result.error || t('applySchool.submitError'));
            toast.success(t('applySchool.submitSuccess'));
            setTimeout(() => router.push('/'), 1500);
        } catch (error: any) {
            console.error('Failed to submit school application:', error);
            toast.error(error.message || t('applySchool.submitError'));
            setSubmitted(false);
        } finally {
            setLoading(false);
        }
    };

    const descriptionLength = formData.needSummary.trim().length;

    /* ── Success state ── */
    if (submitted && !loading) {
        return (
            <div className="min-h-screen flex flex-col bg-slate-50">
                <Navbar />
                <main className="flex-grow flex items-center justify-center py-20">
                    <div className="max-w-md mx-auto text-center bg-white rounded-3xl shadow-lg p-10">
                        <div className="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center mx-auto mb-6">
                            <CheckCircle className="h-10 w-10 text-green-600" />
                        </div>
                        <h2 className="text-2xl font-bold text-slate-900 mb-3">{t('applySchool.successTitle')}</h2>
                        <p className="text-slate-500 mb-6">{t('applySchool.successDesc')}</p>
                        <Button onClick={() => router.push('/')} className="bg-amber-600 hover:bg-amber-700">
                            {t('applySchool.backToHome')}
                        </Button>
                    </div>
                </main>
                <Footer />
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col bg-slate-50">
            <Navbar />
            <main className="flex-grow">

                {/* ═══════════ HERO ═══════════ */}
                <section className="relative overflow-hidden bg-gradient-to-br from-amber-600 via-orange-600 to-amber-800">
                    <div className="absolute inset-0 pointer-events-none">
                        <div className="absolute -top-24 -right-24 w-[500px] h-[500px] bg-white/5 rounded-full blur-[80px]" />
                        <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-white/5 rounded-full blur-[80px]" />
                        <div
                            className="absolute inset-0 opacity-[0.04]"
                            style={{
                                backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)',
                                backgroundSize: '32px 32px',
                            }}
                        />
                    </div>

                    <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 sm:py-20">
                        <div className="max-w-3xl mx-auto text-center">
                            <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md border border-white/20 rounded-full px-5 py-2 mb-6">
                                <School className="h-4 w-4 text-yellow-300" />
                                <span className="text-sm text-white/90 font-medium">{t('applySchool.badge')}</span>
                            </div>

                            <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-4 leading-tight">
                                {t('applySchool.heroTitle')}
                                <br />
                                <span className="bg-gradient-to-r from-yellow-200 via-amber-200 to-orange-200 bg-clip-text text-transparent">
                                    {t('applySchool.heroHighlight')}
                                </span>
                            </h1>

                            <p className="text-base sm:text-lg text-amber-100/80 leading-relaxed max-w-xl mx-auto">
                                {t('applySchool.heroDesc')}
                            </p>
                        </div>
                    </div>

                    <div className="absolute bottom-0 left-0 right-0">
                        <svg viewBox="0 0 1440 60" fill="none" className="w-full">
                            <path d="M0 60L60 52C120 44 240 28 360 24C480 20 600 28 720 32C840 36 960 36 1080 32C1200 28 1320 20 1380 16L1440 12V60H0Z" fill="#f8fafc" />
                        </svg>
                    </div>
                </section>

                {/* ═══════════ MAIN CONTENT ═══════════ */}
                <section className="py-10 sm:py-14">
                    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                        <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">
                            {/* LEFT: Form */}
                            <div className="lg:w-[65%]">

                                {/* Step Indicator */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-5 mb-8">
                                    <div className="flex items-center justify-between">
                                        {STEPS.map((step, i) => {
                                            const Icon = step.icon;
                                            const isActive = currentStep === step.id;
                                            const isCompleted = currentStep > step.id;
                                            return (
                                                <div key={step.id} className="flex items-center flex-1">
                                                    <button
                                                        type="button"
                                                        onClick={() => { if (step.id < currentStep) setCurrentStep(step.id); }}
                                                        className={`flex items-center gap-2.5 transition-all duration-300 ${isActive ? 'text-amber-600' : isCompleted ? 'text-amber-500 cursor-pointer' : 'text-slate-300'}`}
                                                    >
                                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-300 ${isActive ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/30' : isCompleted ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                                                            {isCompleted ? <CheckCircle className="h-5 w-5" /> : <Icon className="h-5 w-5" />}
                                                        </div>
                                                        <span className="text-sm font-medium hidden sm:block">{step.label}</span>
                                                    </button>
                                                    {i < STEPS.length - 1 && (
                                                        <div className="flex-1 mx-3">
                                                            <div className={`h-[2px] rounded-full transition-colors duration-300 ${isCompleted ? 'bg-amber-300' : 'bg-slate-100'}`} />
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>

                                {/* Form Card */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">

                                    {/* ══════ STEP 1 — School Info ══════ */}
                                    {currentStep === 1 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center">
                                                    <School className="h-5 w-5 text-amber-500" />
                                                </div>
                                                <div>
                                                    <h2 className="text-xl font-bold text-slate-900">{t('applySchool.step1.title')}</h2>
                                                    <p className="text-sm text-slate-400">{t('applySchool.step1.subtitle')}</p>
                                                </div>
                                            </div>

                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                                <FieldWrapper id="schoolName" label={t('applySchool.labels.schoolName')} icon={Building} error={errors.schoolName}>
                                                    <Input id="schoolName" type="text" value={formData.schoolName}
                                                        onChange={(e) => updateField('schoolName', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.schoolName')} className={inputClass(!!errors.schoolName)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolType" label={t('applySchool.labels.schoolType')} icon={GraduationCap} error={errors.schoolType}>
                                                    <Select value={formData.schoolType} onValueChange={(v) => updateField('schoolType', v)}>
                                                        <SelectTrigger className={selectTriggerClass(!!errors.schoolType)}>
                                                            <SelectValue placeholder={t('applySchool.placeholders.schoolType')} />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="ilkokul">{t('applySchool.schoolTypes.ilkokul')}</SelectItem>
                                                            <SelectItem value="ortaokul">{t('applySchool.schoolTypes.ortaokul')}</SelectItem>
                                                            <SelectItem value="lise">{t('applySchool.schoolTypes.lise')}</SelectItem>
                                                            <SelectItem value="meslek_lisesi">{t('applySchool.schoolTypes.meslek_lisesi')}</SelectItem>
                                                            <SelectItem value="universite">{t('applySchool.schoolTypes.universite')}</SelectItem>
                                                            <SelectItem value="ozel">{t('applySchool.schoolTypes.ozel')}</SelectItem>
                                                            <SelectItem value="diger">{t('applySchool.schoolTypes.diger')}</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolCountry" label={t('app.page.lke_country')} icon={Globe} error={errors.schoolCountry}>
                                                    <Select value={formData.schoolCountry} onValueChange={(v) => { updateField('schoolCountry', v); if (v !== 'TR') setFormData(prev => ({ ...prev, schoolCountry: v, schoolCity: '' })); else updateField('schoolCountry', v); }}>
                                                        <SelectTrigger className={selectTriggerClass(!!errors.schoolCountry)}>
                                                            <SelectValue placeholder={t('app.page.lke_se_iniz_select_country')} />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            {COUNTRIES.map((c, index) => (
                                                                <SelectItem key={c.value} value={c.value}>
                                                                    {c.flag} {c.labelTr}{index === 0 ? '' : ` / ${c.label}`}
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolCity" label={t('applySchool.labels.schoolCity')} icon={MapPin} error={errors.schoolCity}>
                                                    {formData.schoolCountry === 'TR' ? (
                                                        <Select value={formData.schoolCity} onValueChange={(v) => updateField('schoolCity', v)}>
                                                            <SelectTrigger className={selectTriggerClass(!!errors.schoolCity)}>
                                                                <SelectValue placeholder={t('app.page.ehir_se_iniz')} />
                                                            </SelectTrigger>
                                                            <SelectContent>
                                                                {TURKEY_CITIES.map((city) => (
                                                                    <SelectItem key={city} value={city}>{city}</SelectItem>
                                                                ))}
                                                            </SelectContent>
                                                        </Select>
                                                    ) : (
                                                        <Input id="schoolCity" type="text" value={formData.schoolCity}
                                                            onChange={(e) => updateField('schoolCity', e.target.value)}
                                                            placeholder={t('applySchool.placeholders.schoolCity')} className={inputClass(!!errors.schoolCity)} />
                                                    )}
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolDistrict" label={t('applySchool.labels.schoolDistrict')} icon={MapPin} error={errors.schoolDistrict}>
                                                    <Input id="schoolDistrict" type="text" value={formData.schoolDistrict}
                                                        onChange={(e) => updateField('schoolDistrict', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.schoolDistrict')} className={inputClass(!!errors.schoolDistrict)} />
                                                </FieldWrapper>

                                                <div className="md:col-span-2">
                                                    <FieldWrapper id="schoolAddress" label={t('applySchool.labels.schoolAddress')} icon={MapPin} error={errors.schoolAddress} required={false}>
                                                        <Input id="schoolAddress" type="text" value={formData.schoolAddress}
                                                            onChange={(e) => updateField('schoolAddress', e.target.value)}
                                                            placeholder={t('applySchool.placeholders.schoolAddress')} className={inputClass(false)} />
                                                    </FieldWrapper>
                                                </div>

                                                <FieldWrapper id="studentTotal" label={t('applySchool.labels.studentTotal')} icon={Users} error={errors.studentTotal}>
                                                    <Input id="studentTotal" type="number" min={1} value={formData.studentTotal}
                                                        onChange={(e) => updateField('studentTotal', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.studentTotal')} className={inputClass(!!errors.studentTotal)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolWebsite" label={t('applySchool.labels.schoolWebsite')} icon={Globe} error={errors.schoolWebsite} required={false}>
                                                    <Input id="schoolWebsite" type="url" value={formData.schoolWebsite}
                                                        onChange={(e) => updateField('schoolWebsite', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.schoolWebsite')} className={inputClass(false)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="schoolPhone" label={t('applySchool.labels.schoolPhone')} icon={Phone} error={errors.schoolPhone} required={false}>
                                                    <Input id="schoolPhone" type="tel" value={formData.schoolPhone}
                                                        onChange={(e) => updateField('schoolPhone', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.schoolPhone')} className={inputClass(false)} />
                                                </FieldWrapper>
                                            </div>
                                        </div>
                                    )}

                                    {/* ══════ STEP 2 — Applicant Info ══════ */}
                                    {currentStep === 2 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center">
                                                    <User className="h-5 w-5 text-blue-500" />
                                                </div>
                                                <div>
                                                    <h2 className="text-xl font-bold text-slate-900">{t('applySchool.step2.title')}</h2>
                                                    <p className="text-sm text-slate-400">{t('applySchool.step2.subtitle')}</p>
                                                </div>
                                            </div>

                                            <div className="bg-blue-50/50 border border-blue-100 rounded-xl p-4 flex items-start gap-3">
                                                <HelpCircle className="h-5 w-5 text-blue-500 flex-shrink-0 mt-0.5" />
                                                <p className="text-sm text-blue-700">{t('applySchool.step2.notice')}</p>
                                            </div>

                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                                <FieldWrapper id="applicantFullName" label={t('applySchool.labels.applicantFullName')} icon={User} error={errors.applicantFullName}>
                                                    <Input id="applicantFullName" type="text" value={formData.applicantFullName}
                                                        onChange={(e) => updateField('applicantFullName', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.applicantFullName')} className={inputClass(!!errors.applicantFullName)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="applicantRole" label={t('applySchool.labels.applicantRole')} icon={Briefcase} error={errors.applicantRole}>
                                                    <Select value={formData.applicantRole} onValueChange={(v) => updateField('applicantRole', v)}>
                                                        <SelectTrigger className={selectTriggerClass(!!errors.applicantRole)}>
                                                            <SelectValue placeholder={t('applySchool.placeholders.applicantRole')} />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="mudur">{t('applySchool.roles.mudur')}</SelectItem>
                                                            <SelectItem value="mudur_yardimcisi">{t('applySchool.roles.mudur_yardimcisi')}</SelectItem>
                                                            <SelectItem value="ogretmen">{t('applySchool.roles.ogretmen')}</SelectItem>
                                                            <SelectItem value="okul_aile_birligi">{t('applySchool.roles.okul_aile_birligi')}</SelectItem>
                                                            <SelectItem value="idari_personel">{t('applySchool.roles.idari_personel')}</SelectItem>
                                                            <SelectItem value="diger">{t('applySchool.roles.diger')}</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>

                                                <FieldWrapper id="applicantTitle" label={t('applySchool.labels.applicantTitle')} icon={Briefcase} error={errors.applicantTitle} required={false}>
                                                    <Input id="applicantTitle" type="text" value={formData.applicantTitle}
                                                        onChange={(e) => updateField('applicantTitle', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.applicantTitle')} className={inputClass(false)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="applicantEmail" label={t('applySchool.labels.applicantEmail')} icon={Mail} error={errors.applicantEmail}>
                                                    <Input id="applicantEmail" type="email" value={formData.applicantEmail}
                                                        onChange={(e) => updateField('applicantEmail', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.applicantEmail')} className={inputClass(!!errors.applicantEmail)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="applicantPhone" label={t('applySchool.labels.applicantPhone')} icon={Phone} error={errors.applicantPhone} required={false}>
                                                    <Input id="applicantPhone" type="tel" value={formData.applicantPhone}
                                                        onChange={(e) => updateField('applicantPhone', e.target.value)}
                                                        placeholder={t('app.page.90_5xx_xxx_xx_xx')} className={inputClass(false)} />
                                                </FieldWrapper>
                                            </div>
                                        </div>
                                    )}

                                    {/* ══════ STEP 3 — Project Details ══════ */}
                                    {currentStep === 3 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-purple-50 flex items-center justify-center">
                                                    <FileText className="h-5 w-5 text-purple-500" />
                                                </div>
                                                <div>
                                                    <h2 className="text-xl font-bold text-slate-900">{t('applySchool.step3.title')}</h2>
                                                    <p className="text-sm text-slate-400">{t('applySchool.step3.subtitle')}</p>
                                                </div>
                                            </div>

                                            <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-4 flex items-start gap-3">
                                                <HelpCircle className="h-5 w-5 text-amber-500 flex-shrink-0 mt-0.5" />
                                                <div className="text-sm text-amber-700 leading-relaxed">
                                                    <p className="font-medium mb-1">{t('applySchool.tips.title')}</p>
                                                    <ul className="list-disc list-inside space-y-1 text-amber-600">
                                                        <li>{t('applySchool.tips.tip1')}</li>
                                                        <li>{t('applySchool.tips.tip2')}</li>
                                                        <li>{t('applySchool.tips.tip3')}</li>
                                                        <li>{t('applySchool.tips.tip4')}</li>
                                                    </ul>
                                                </div>
                                            </div>

                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                                <FieldWrapper id="projectTitle" label={t('applySchool.labels.projectTitle')} icon={BookOpen} error={errors.projectTitle}>
                                                    <Input id="projectTitle" type="text" value={formData.projectTitle}
                                                        onChange={(e) => updateField('projectTitle', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.projectTitle')} className={inputClass(!!errors.projectTitle)} />
                                                </FieldWrapper>

                                                <FieldWrapper id="projectCategory" label={t('applySchool.labels.projectCategory')} icon={Hash} error={errors.projectCategory}>
                                                    <Select value={formData.projectCategory} onValueChange={(v) => updateField('projectCategory', v)}>
                                                        <SelectTrigger className={selectTriggerClass(!!errors.projectCategory)}>
                                                            <SelectValue placeholder={t('applySchool.placeholders.projectCategory')} />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="laboratuvar">{t('applySchool.categories.laboratuvar')}</SelectItem>
                                                            <SelectItem value="kutuphane">{t('applySchool.categories.kutuphane')}</SelectItem>
                                                            <SelectItem value="teknoloji">{t('applySchool.categories.teknoloji')}</SelectItem>
                                                            <SelectItem value="spor">{t('applySchool.categories.spor')}</SelectItem>
                                                            <SelectItem value="sanat">{t('applySchool.categories.sanat')}</SelectItem>
                                                            <SelectItem value="altyapi">{t('applySchool.categories.altyapi')}</SelectItem>
                                                            <SelectItem value="malzeme">{t('applySchool.categories.malzeme')}</SelectItem>
                                                            <SelectItem value="diger">{t('applySchool.categories.diger')}</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </FieldWrapper>

                                                <FieldWrapper id="targetAmount" label={t('applySchool.labels.targetAmount')} icon={DollarSign} error={errors.targetAmount}>
                                                    <div className="relative">
                                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-semibold text-sm">$</span>
                                                        <Input id="targetAmount" type="number" min={1} value={formData.targetAmount}
                                                            onChange={(e) => updateField('targetAmount', e.target.value)}
                                                            placeholder={t('applySchool.placeholders.targetAmount')} className={`${inputClass(!!errors.targetAmount)} pl-8`} />
                                                    </div>
                                                </FieldWrapper>

                                                <FieldWrapper id="beneficiaryCount" label={t('applySchool.labels.beneficiaryCount')} icon={Users} error={errors.beneficiaryCount}>
                                                    <Input id="beneficiaryCount" type="number" min={1} value={formData.beneficiaryCount}
                                                        onChange={(e) => updateField('beneficiaryCount', e.target.value)}
                                                        placeholder={t('applySchool.placeholders.beneficiaryCount')} className={inputClass(!!errors.beneficiaryCount)} />
                                                </FieldWrapper>
                                            </div>

                                            {/* Description */}
                                            <div className="space-y-2">
                                                <div className="flex justify-between items-center">
                                                    <Label htmlFor="needSummary" className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                                        <FileText className="h-4 w-4 text-slate-400" />
                                                        {t('applySchool.labels.needSummary')}
                                                        <span className="text-red-400">*</span>
                                                    </Label>
                                                    <div className="flex items-center gap-2">
                                                        <div className="h-1.5 w-20 rounded-full bg-slate-100 overflow-hidden">
                                                            <div
                                                                className={`h-full rounded-full transition-all duration-300 ${descriptionLength >= MIN_DESCRIPTION_LENGTH ? 'bg-emerald-500' : 'bg-amber-400'}`}
                                                                style={{ width: `${Math.min(100, (descriptionLength / MIN_DESCRIPTION_LENGTH) * 100)}%` }}
                                                            />
                                                        </div>
                                                        <span className={`text-xs font-medium ${descriptionLength < MIN_DESCRIPTION_LENGTH ? 'text-amber-500' : 'text-emerald-500'}`}>
                                                            {descriptionLength}/{MIN_DESCRIPTION_LENGTH}
                                                        </span>
                                                    </div>
                                                </div>
                                                <Textarea
                                                    id="needSummary"
                                                    value={formData.needSummary}
                                                    onChange={(e) => updateField('needSummary', e.target.value)}
                                                    placeholder={t('applySchool.placeholders.needSummary')}
                                                    rows={8}
                                                    className={`rounded-xl border-slate-200 bg-white focus:border-purple-400 focus:ring-purple-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 resize-none ${errors.needSummary ? 'border-red-400' : ''}`}
                                                />
                                                {errors.needSummary && (
                                                    <p className="text-xs text-red-500 flex items-center gap-1">
                                                        <AlertCircle className="h-3 w-3" />
                                                        {errors.needSummary}
                                                    </p>
                                                )}
                                            </div>
                                        </div>
                                    )}

                                    {/* ══════ STEP 4 — Media & Documents ══════ */}
                                    {currentStep === 4 && (
                                        <div className="p-6 sm:p-8 space-y-8">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center">
                                                    <Upload className="h-5 w-5 text-indigo-500" />
                                                </div>
                                                <div>
                                                    <h2 className="text-xl font-bold text-slate-900">{t('applySchool.step4.title')}</h2>
                                                    <p className="text-sm text-slate-400">{t('applySchool.step4.subtitle')}</p>
                                                </div>
                                            </div>

                                            {/* ── Photo Upload ── */}
                                            <div className="space-y-3">
                                                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                                    <ImageIcon className="h-4 w-4 text-slate-400" />
                                                    {t('applySchool.photos.label')}
                                                </Label>
                                                <p className="text-xs text-slate-400">{t('applySchool.photos.hint')}</p>

                                                <div
                                                    onDragOver={(e) => { e.preventDefault(); setPhotoDragOver(true); }}
                                                    onDragLeave={() => setPhotoDragOver(false)}
                                                    onDrop={handlePhotoDrop}
                                                    className={`border-2 border-dashed rounded-2xl p-6 text-center transition-all duration-300 ${photoDragOver ? 'border-amber-400 bg-amber-50/50' : 'border-slate-200 hover:border-slate-300'}`}
                                                >
                                                    <ImageIcon className="h-8 w-8 text-slate-400 mx-auto mb-2" />
                                                    <p className="text-sm text-slate-500 mb-2">{t('applySchool.photos.dropText')}</p>
                                                    <Button type="button" variant="outline" onClick={() => photoInputRef.current?.click()} className="rounded-xl text-sm">
                                                        {t('applySchool.photos.selectBtn')}
                                                    </Button>
                                                    <input
                                                        ref={photoInputRef}
                                                        type="file"
                                                        className="hidden"
                                                        accept="image/jpeg,image/png,image/webp"
                                                        multiple
                                                        onChange={handlePhotoSelect}
                                                    />
                                                    <p className="text-xs text-slate-400 mt-2">{t('app.page.jpg_png_webp_max_5_mb')}{t('applySchool.photos.maxCount')}</p>
                                                </div>

                                                {photos.length > 0 && (
                                                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                        {photos.map((photo) => (
                                                            <div key={photo.id} className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-[4/3]">
                                                                <img src={photo.preview} alt={photo.name} className="w-full h-full object-cover" />
                                                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors duration-200" />
                                                                <button
                                                                    type="button"
                                                                    onClick={() => handleRemovePhoto(photo.id)}
                                                                    className="absolute top-2 right-2 w-7 h-7 rounded-full bg-red-500/80 hover:bg-red-600 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200"
                                                                >
                                                                    <X className="h-4 w-4" />
                                                                </button>
                                                                <p className="absolute bottom-0 left-0 right-0 bg-black/50 text-white text-xs px-2 py-1 truncate">{photo.name}</p>
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>

                                            {/* ── Video Upload ── */}
                                            <div className="space-y-3">
                                                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                                    <Video className="h-4 w-4 text-slate-400" />
                                                    {t('applySchool.video.label')}
                                                </Label>
                                                <p className="text-xs text-slate-400">{t('applySchool.video.hint')}</p>

                                                {!video ? (
                                                    <div className="border-2 border-dashed rounded-2xl p-6 text-center border-slate-200 hover:border-slate-300 transition-all duration-300">
                                                        <Video className="h-8 w-8 text-slate-400 mx-auto mb-2" />
                                                        <p className="text-sm text-slate-500 mb-2">{t('applySchool.video.dropText')}</p>
                                                        <Button type="button" variant="outline" onClick={() => videoInputRef.current?.click()} className="rounded-xl text-sm">
                                                            {t('applySchool.video.selectBtn')}
                                                        </Button>
                                                        <input
                                                            ref={videoInputRef}
                                                            type="file"
                                                            className="hidden"
                                                            accept="video/mp4,video/webm,video/quicktime"
                                                            onChange={handleVideoSelect}
                                                        />
                                                        <p className="text-xs text-slate-400 mt-2">{t('app.page.mp4_webm_max_50_mb')}</p>
                                                    </div>
                                                ) : (
                                                    <div className="bg-slate-50 border border-slate-200 rounded-xl p-4">
                                                        <div className="flex items-center justify-between mb-3">
                                                            <div className="flex items-center gap-3">
                                                                <Video className="h-5 w-5 text-indigo-500" />
                                                                <div>
                                                                    <p className="text-sm font-medium text-slate-700">{video.name}</p>
                                                                    <p className="text-xs text-slate-400">{(video.size / (1024 * 1024)).toFixed(1)} MB</p>
                                                                </div>
                                                            </div>
                                                            <button onClick={removeVideo} className="text-slate-400 hover:text-red-500 transition-colors">
                                                                <X className="h-5 w-5" />
                                                            </button>
                                                        </div>
                                                        <video src={video.preview} controls className="w-full rounded-lg max-h-60" />
                                                    </div>
                                                )}
                                            </div>

                                            {/* ── Document Upload ── */}
                                            <div className="space-y-3">
                                                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                                                    <FileText className="h-4 w-4 text-slate-400" />
                                                    {t('applySchool.documents.label')}
                                                </Label>

                                                <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-4 text-sm text-amber-700">
                                                    <p className="font-medium mb-1">{t('applySchool.docTips.title')}</p>
                                                    <ul className="list-disc list-inside space-y-1 text-amber-600">
                                                        <li>{t('applySchool.docTips.tip1')}</li>
                                                        <li>{t('applySchool.docTips.tip2')}</li>
                                                        <li>{t('applySchool.docTips.tip3')}</li>
                                                    </ul>
                                                </div>

                                                <div
                                                    onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                                                    onDragLeave={() => setDragOver(false)}
                                                    onDrop={handleDrop}
                                                    className={`border-2 border-dashed rounded-2xl p-8 text-center transition-all duration-300 ${dragOver ? 'border-amber-400 bg-amber-50/50' : 'border-slate-200 hover:border-slate-300'}`}
                                                >
                                                    <Upload className="h-10 w-10 text-slate-400 mx-auto mb-3" />
                                                    <p className="text-sm text-slate-500 mb-3">{t('applySchool.docUploadText')}</p>
                                                    <Button variant="outline" onClick={handleAddDocumentClick} className="rounded-xl">
                                                        {t('applySchool.docSelectFile')}
                                                    </Button>
                                                    <input ref={fileInputRef} type="file" className="hidden" accept=".pdf,.jpg,.jpeg,.png" onChange={handleFileSelect} />
                                                    <p className="text-xs text-slate-400 mt-2">{t('app.page.pdf_jpg_png_max_10_mb')}</p>
                                                </div>

                                                {documents.length > 0 && (
                                                    <div className="space-y-2">
                                                        {documents.map((doc) => (
                                                            <div key={doc.id} className="flex items-center justify-between bg-slate-50 border border-slate-100 rounded-xl px-4 py-3">
                                                                <div className="flex items-center gap-3">
                                                                    <FileText className="h-5 w-5 text-amber-500" />
                                                                    <div>
                                                                        <p className="text-sm font-medium text-slate-700">{doc.name}</p>
                                                                        <p className="text-xs text-slate-400">{(doc.size / 1024).toFixed(1)} KB</p>
                                                                    </div>
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    {doc.status === 'uploading' && <Loader2 className="h-4 w-4 text-amber-500 animate-spin" />}
                                                                    {doc.status === 'uploaded' && <CheckCircle className="h-4 w-4 text-green-500" />}
                                                                    {doc.status === 'failed' && <AlertCircle className="h-4 w-4 text-red-500" />}
                                                                    <button onClick={() => handleRemoveDocument(doc.id)} className="text-slate-400 hover:text-red-500 transition-colors">
                                                                        <X className="h-4 w-4" />
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}

                                    {/* ══════ STEP 5 — Review ══════ */}
                                    {currentStep === 5 && (
                                        <div className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center">
                                                    <CheckCircle className="h-5 w-5 text-emerald-500" />
                                                </div>
                                                <div>
                                                    <h2 className="text-xl font-bold text-slate-900">{t('applySchool.step5.title')}</h2>
                                                    <p className="text-sm text-slate-400">{t('applySchool.step5.subtitle')}</p>
                                                </div>
                                            </div>

                                            {/* School Info Summary */}
                                            <div className="bg-slate-50 border border-slate-100 rounded-xl p-5 space-y-3">
                                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                                    <School className="h-4 w-4 text-amber-500" />
                                                    {t('applySchool.step1.title')}
                                                </h3>
                                                <div className="grid grid-cols-2 gap-3 text-sm">
                                                    <div><span className="text-slate-400">{t('applySchool.labels.schoolName')}:</span> <span className="text-slate-700 font-medium">{formData.schoolName}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.schoolType')}:</span> <span className="text-slate-700 font-medium">{formData.schoolType && t(`applySchool.schoolTypes.${formData.schoolType}`)}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.schoolCity')}:</span> <span className="text-slate-700 font-medium">{formData.schoolCity}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.schoolDistrict')}:</span> <span className="text-slate-700 font-medium">{formData.schoolDistrict}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.studentTotal')}:</span> <span className="text-slate-700 font-medium">{formData.studentTotal}</span></div>
                                                </div>
                                            </div>

                                            {/* Applicant Info Summary */}
                                            <div className="bg-slate-50 border border-slate-100 rounded-xl p-5 space-y-3">
                                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                                    <User className="h-4 w-4 text-blue-500" />
                                                    {t('applySchool.step2.title')}
                                                </h3>
                                                <div className="grid grid-cols-2 gap-3 text-sm">
                                                    <div><span className="text-slate-400">{t('applySchool.labels.applicantFullName')}:</span> <span className="text-slate-700 font-medium">{formData.applicantFullName}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.applicantRole')}:</span> <span className="text-slate-700 font-medium">{formData.applicantRole && t(`applySchool.roles.${formData.applicantRole}`)}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.applicantEmail')}:</span> <span className="text-slate-700 font-medium">{formData.applicantEmail}</span></div>
                                                    {formData.applicantPhone && (
                                                        <div><span className="text-slate-400">{t('applySchool.labels.applicantPhone')}:</span> <span className="text-slate-700 font-medium">{formData.applicantPhone}</span></div>
                                                    )}
                                                </div>
                                            </div>

                                            {/* Project Summary */}
                                            <div className="bg-slate-50 border border-slate-100 rounded-xl p-5 space-y-3">
                                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                                    <FileText className="h-4 w-4 text-purple-500" />
                                                    {t('applySchool.step3.title')}
                                                </h3>
                                                <div className="grid grid-cols-2 gap-3 text-sm">
                                                    <div><span className="text-slate-400">{t('applySchool.labels.projectTitle')}:</span> <span className="text-slate-700 font-medium">{formData.projectTitle}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.projectCategory')}:</span> <span className="text-slate-700 font-medium">{formData.projectCategory && t(`applySchool.categories.${formData.projectCategory}`)}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.targetAmount')}:</span> <span className="text-slate-700 font-medium">${formData.targetAmount}</span></div>
                                                    <div><span className="text-slate-400">{t('applySchool.labels.beneficiaryCount')}:</span> <span className="text-slate-700 font-medium">{formData.beneficiaryCount}</span></div>
                                                </div>
                                                <div className="text-sm mt-2">
                                                    <span className="text-slate-400 block mb-1">{t('applySchool.labels.needSummary')}:</span>
                                                    <p className="text-slate-700 bg-white p-3 rounded-lg border border-slate-100 whitespace-pre-wrap">{formData.needSummary}</p>
                                                </div>
                                            </div>

                                            {/* Media Summary */}
                                            <div className="bg-slate-50 border border-slate-100 rounded-xl p-5 space-y-3">
                                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                                    <Upload className="h-4 w-4 text-indigo-500" />
                                                    {t('applySchool.step4.title')}
                                                </h3>
                                                <div className="text-sm text-slate-600 space-y-1">
                                                    <p>{t('applySchool.review.photos')}: <span className="font-medium">{photos.length}</span></p>
                                                    <p>{t('applySchool.review.video')}: <span className="font-medium">{video ? t('applySchool.review.yes') : t('applySchool.review.no')}</span></p>
                                                    <p>{t('applySchool.review.documents')}: <span className="font-medium">{documents.length}</span></p>
                                                </div>
                                            </div>

                                            <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-start gap-3">
                                                <Shield className="h-5 w-5 text-amber-600 flex-shrink-0 mt-0.5" />
                                                <p className="text-sm text-amber-800">{t('applySchool.review.notice')}</p>
                                            </div>
                                        </div>
                                    )}

                                    {/* Navigation Buttons */}
                                    <div className="p-6 sm:p-8 border-t border-slate-100 flex justify-between">
                                        {currentStep > 1 ? (
                                            <Button variant="outline" onClick={prevStep} className="rounded-xl gap-2">
                                                <ArrowLeft className="h-4 w-4" /> {t('applySchool.prev')}
                                            </Button>
                                        ) : (
                                            <Button variant="outline" onClick={() => router.push('/apply')} className="rounded-xl gap-2">
                                                <ArrowLeft className="h-4 w-4" /> {t('applySchool.back')}
                                            </Button>
                                        )}

                                        {currentStep < 5 ? (
                                            <Button onClick={nextStep} className="bg-amber-600 hover:bg-amber-700 rounded-xl gap-2">
                                                {t('applySchool.next')} <ArrowRight className="h-4 w-4" />
                                            </Button>
                                        ) : (
                                            <Button onClick={handleSubmit} disabled={loading} className="bg-gradient-to-r from-amber-600 to-orange-600 hover:from-amber-700 hover:to-orange-700 rounded-xl gap-2 px-8">
                                                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
                                                {loading ? t('applySchool.submitting') : t('applySchool.submit')}
                                            </Button>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* RIGHT: Sidebar */}
                            <div className="lg:w-[35%] space-y-6">
                                {/* Info Card */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                                    <div className="flex items-center gap-3 mb-4">
                                        <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center">
                                            <Shield className="h-5 w-5 text-amber-500" />
                                        </div>
                                        <h3 className="font-bold text-slate-900">{t('applySchool.sidebar.title')}</h3>
                                    </div>
                                    <ul className="space-y-3">
                                        <li className="flex items-start gap-2 text-sm text-slate-600">
                                            <CheckCircle className="h-4 w-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                                            <span>{t('applySchool.sidebar.point1')}</span>
                                        </li>
                                        <li className="flex items-start gap-2 text-sm text-slate-600">
                                            <CheckCircle className="h-4 w-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                                            <span>{t('applySchool.sidebar.point2')}</span>
                                        </li>
                                        <li className="flex items-start gap-2 text-sm text-slate-600">
                                            <CheckCircle className="h-4 w-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                                            <span>{t('applySchool.sidebar.point3')}</span>
                                        </li>
                                        <li className="flex items-start gap-2 text-sm text-slate-600">
                                            <CheckCircle className="h-4 w-4 text-emerald-500 flex-shrink-0 mt-0.5" />
                                            <span>{t('applySchool.sidebar.point4')}</span>
                                        </li>
                                    </ul>
                                </div>

                                {/* School Campaign Banner */}
                                <div className="bg-gradient-to-br from-amber-500 to-orange-600 rounded-2xl p-6 text-white">
                                    <School className="h-8 w-8 mb-3 text-amber-200" />
                                    <h3 className="font-bold text-lg mb-2">{t('applySchool.sidebar.bannerTitle')}</h3>
                                    <p className="text-amber-100 text-sm leading-relaxed">{t('applySchool.sidebar.bannerDesc')}</p>
                                </div>

                                {/* Progress */}
                                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                                    <h3 className="font-bold text-slate-900 mb-4">{t('applySchool.sidebar.progressTitle')}</h3>
                                    <div className="space-y-3">
                                        {STEPS.map((step) => {
                                            const isActive = currentStep === step.id;
                                            const isDone = currentStep > step.id;
                                            return (
                                                <div key={step.id} className="flex items-center gap-3">
                                                    <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${isDone ? 'bg-emerald-100 text-emerald-600' : isActive ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                                                        {isDone ? <CheckCircle className="h-4 w-4" /> : step.id}
                                                    </div>
                                                    <span className={`text-sm ${isDone ? 'text-emerald-600 font-medium' : isActive ? 'text-amber-600 font-medium' : 'text-slate-400'}`}>
                                                        {step.label}
                                                    </span>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </section>
            </main>
            <Footer />
        </div>
    );
}

'use client';

import { useState, useRef } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useRouter } from 'next/navigation';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { validateEmail, sanitizeInput } from '@/lib/validation';
import { toast } from 'sonner';
import {
  GraduationCap,
  User,
  Mail,
  Globe,
  DollarSign,
  BookOpen,
  Calendar,
  Building,
  Layers,
  FileText,
  Upload,
  CheckCircle,
  AlertCircle,
  Loader2,
  X,
  Shield,
  Clock,
  Eye,
  Heart,
  ArrowRight,
  ArrowLeft,
  Sparkles,
  FileCheck,
  HelpCircle,
  Zap,
  Star,
  Camera,
  ImagePlus,
  Film,
  GripVertical,
  ChevronUp,
  ChevronDown,
  UserCircle,
  MapPin,
  Tag,
} from 'lucide-react';
import { COUNTRIES, FUNDING_CATEGORIES, TURKEY_CITIES } from '@/lib/constants';
type DocStatus = 'ready' | 'uploading' | 'uploaded' | 'failed';

interface DocumentItem {
  id: string;
  name: string;
  file: File;
  status: DocStatus;
  size: number;
  uploadedUrl?: string;
}

interface PhotoItem {
  id: string;
  file: File;
  previewUrl: string;
  label: string;
  uploadedUrl?: string;
  status: DocStatus;
}

interface VideoItem {
  id: string;
  file: File;
  previewUrl: string;
  label: string;
  uploadedUrl?: string;
  status: DocStatus;
}

const CLASS_YEAR_KEYS = [
  'prep', '1', '2', '3', '4', '5', '6', 'grad', 'master', 'phd'
];

const EDUCATION_LEVEL_KEYS = [
  'highSchool', 'undergrad', 'master', 'phd', 'vocational'
];

const MIN_DESCRIPTION_LENGTH = 100;

/* ── Step config ── */
const STEPS = [
  { id: 1, label: 'Kişisel Bilgiler', icon: User },
  { id: 2, label: 'Eğitim Bilgileri', icon: GraduationCap },
  { id: 3, label: 'İhtiyaç Detayı', icon: FileText },
  { id: 4, label: 'Belgeler', icon: Upload },
];

/* ── Field helper component (MUST be outside ApplyPage to avoid remounting on every keystroke) ── */
const FieldWrapper = ({
  id,
  label,
  icon: Icon,
  error,
  children,
  required = true,
}: {
  id: string;
  label: string;
  icon: any;
  error?: string;
  children: React.ReactNode;
  required?: boolean;
}) => (
  <div className="space-y-2">
    <Label htmlFor={id} className="text-sm font-semibold text-slate-700 flex items-center gap-2">
      <Icon className="h-4 w-4 text-slate-400" />
      {label}
      {required && <span className="text-red-400">*</span>}
    </Label>
    {children}
    {error && (
      <p className="text-xs text-red-500 flex items-center gap-1">
        <AlertCircle className="h-3 w-3" />
        {error}
      </p>
    )}
  </div>
);

const inputClass = (hasError: boolean) =>
  `h-12 rounded-xl border-slate-200 bg-white focus:border-blue-400 focus:ring-blue-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 ${hasError ? 'border-red-400 focus:border-red-400 focus:ring-red-400/20' : ''}`;

const selectTriggerClass = (hasError: boolean) =>
  `h-12 rounded-xl border-slate-200 bg-white focus:border-blue-400 focus:ring-blue-400/20 focus:ring-4 transition-all duration-200 ${hasError ? 'border-red-400' : ''}`;

export default function ApplyPage() {
  const router = useRouter();
  const { t } = useTranslation();
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [currentStep, setCurrentStep] = useState(1);

  // Form State
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    country: '',
    city: '',
    gender: '',
    educationLevel: '',
    category: '',
    needSummary: '',
    targetAmount: '',
    classYear: '',
    faculty: '',
    department: '',
    campaignTitle: '',
  });

  const GENDER_OPTIONS = [
    { value: 'female', labelKey: 'apply.options.gender.female' },
    { value: 'male', labelKey: 'apply.options.gender.male' },
    { value: 'other', labelKey: 'apply.options.gender.other' },
    { value: 'prefer_not_to_say', labelKey: 'apply.options.gender.preferNotToSay' },
  ];

  // Document State
  const [documentNameInput, setDocumentNameInput] = useState('');
  const [documents, setDocuments] = useState<DocumentItem[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragOver, setDragOver] = useState(false);

  // Photo State (step 3 optional)
  const [photos, setPhotos] = useState<PhotoItem[]>([]);
  const photoInputRef = useRef<HTMLInputElement>(null);
  const [photoDragOver, setPhotoDragOver] = useState(false);

  // Video State (step 3 optional)
  const [videos, setVideos] = useState<VideoItem[]>([]);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const [videoDragOver, setVideoDragOver] = useState(false);

  const validateForm = (): boolean => {
      const { t } = useTranslation();
    const newErrors: Record<string, string> = {};

    if (!formData.fullName.trim()) {
      newErrors.fullName = t('apply.validation.fullName');
    } else if (formData.fullName.trim().length < 2) {
      newErrors.fullName = t('apply.validation.invalidName');
    }

    if (!formData.email.trim()) {
      newErrors.email = t('apply.validation.email');
    } else if (!validateEmail(formData.email)) {
      newErrors.email = t('apply.validation.invalidEmail');
    }

    if (!formData.country) {
      newErrors.country = t('apply.validation.country');
    }

    if (!formData.gender) {
      newErrors.gender = t('apply.validation.gender');
    }

    if (!formData.educationLevel) {
      newErrors.educationLevel = t('apply.validation.educationLevel');
    }

    const minTarget = formData.country === 'TR' ? 2500 : 50;
    if (!formData.targetAmount) {
      newErrors.targetAmount = t('apply.validation.targetAmount');
    } else if (parseInt(formData.targetAmount) < minTarget) {
      newErrors.targetAmount = formData.country === 'TR' ? 'Minimum 2500 TL' : 'Minimum 50 USD';
    }

    if (!formData.classYear) {
      newErrors.classYear = t('apply.validation.classYear');
    }

    if (!formData.faculty.trim()) {
      newErrors.faculty = t('apply.validation.faculty');
    }

    if (!formData.department.trim()) {
      newErrors.department = t('apply.validation.department');
    }

    if (!formData.needSummary.trim()) {
      newErrors.needSummary = t('apply.validation.needSummary');
    } else if (formData.needSummary.trim().length < MIN_DESCRIPTION_LENGTH) {
      const remaining = MIN_DESCRIPTION_LENGTH - formData.needSummary.trim().length;
      newErrors.needSummary = t('apply.validation.needSummaryMin', {
        min: MIN_DESCRIPTION_LENGTH,
        remaining: remaining,
      });
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateCurrentStep = (): boolean => {
      const { t } = useTranslation();
    const newErrors: Record<string, string> = {};

    if (currentStep === 1) {
      if (!formData.fullName.trim()) newErrors.fullName = t('apply.validation.fullName');
      else if (formData.fullName.trim().length < 2) newErrors.fullName = t('apply.validation.invalidName');
      if (!formData.email.trim()) newErrors.email = t('apply.validation.email');
      else if (!validateEmail(formData.email)) newErrors.email = t('apply.validation.invalidEmail');
      if (!formData.country) newErrors.country = t('apply.validation.country');
      if (!formData.gender) newErrors.gender = t('apply.validation.gender');
    }

    if (currentStep === 2) {
      if (!formData.educationLevel) newErrors.educationLevel = t('apply.validation.educationLevel');
      if (!formData.classYear) newErrors.classYear = t('apply.validation.classYear');
      if (!formData.faculty.trim()) newErrors.faculty = t('apply.validation.faculty');
      if (!formData.department.trim()) newErrors.department = t('apply.validation.department');
      const minTarget = formData.country === 'TR' ? 2500 : 50;
      if (!formData.targetAmount) newErrors.targetAmount = t('apply.validation.targetAmount');
      else if (parseInt(formData.targetAmount) < minTarget) newErrors.targetAmount = formData.country === 'TR' ? 'Minimum 2500 TL' : 'Minimum 50 USD';
    }

    if (currentStep === 3) {
      if (!formData.needSummary.trim()) newErrors.needSummary = t('apply.validation.needSummary');
      else if (formData.needSummary.trim().length < MIN_DESCRIPTION_LENGTH) {
        const remaining = MIN_DESCRIPTION_LENGTH - formData.needSummary.trim().length;
        newErrors.needSummary = t('apply.validation.needSummaryMin', { min: MIN_DESCRIPTION_LENGTH, remaining });
      }
    }

    // Step 4 has no required validation (documents are optional)

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const nextStep = () => {
    if (validateCurrentStep()) {
      setCurrentStep((s) => Math.min(s + 1, 4));
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const prevStep = () => {
    setCurrentStep((s) => Math.max(s - 1, 1));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  /* ── Document handlers ── */
  const handleAddDocumentClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    e.target.value = '';
    await processFile(file);
  };

  const processFile = async (file: File) => {
    const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png'];
    const maxSize = 10 * 1024 * 1024;

    if (!allowedTypes.includes(file.type)) {
      toast.error(t('apply.validation.fileType'));
      return;
    }

    if (file.size > maxSize) {
      toast.error(t('apply.validation.fileSize'));
      return;
    }

    const name = documentNameInput.trim() || file.name;

    const newDoc: DocumentItem = {
      id: Math.random().toString(36).substring(7),
      name: name,
      file: file,
      size: file.size,
      status: 'ready',
    };

    const updatedDocs = [...documents, newDoc];
    setDocuments(updatedDocs);
    setDocumentNameInput('');
    await uploadFile(newDoc.id!, file, 'document');
  };

  const handleDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files?.[0];
    if (file) await processFile(file);
  };

  const uploadFile = async (docId: string, file: File, type: 'document' | 'photo' = 'document') => {
    setDocuments((prev) => prev.map((d) => (d.id === docId ? { ...d, status: 'uploading' } : d)));
    try {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('type', type);

      const res = await fetch('/api/upload', { method: 'POST', body: fd });
      const json = await res.json();

      if (!res.ok || !json.success) {
        throw new Error(json.error || 'Upload failed');
      }

      setDocuments((prev) =>
        prev.map((d) => (d.id === docId ? { ...d, status: 'uploaded', uploadedUrl: json.data.url } : d))
      );
      toast.success(t('apply.documents.status.uploaded'));
    } catch (err: any) {
      setDocuments((prev) => prev.map((d) => (d.id === docId ? { ...d, status: 'failed' } : d)));
      toast.error(err.message || t('apply.documents.status.failed'));
    }
  };

  const handleRemoveDocument = (id: string) => {
    setDocuments((prev) => prev.filter((d) => d.id !== id));
  };

  /* ── Photo upload helper ── */
  const uploadPhoto = async (photoId: string, file: File) => {
    setPhotos((prev) => prev.map((p) => (p.id === photoId ? { ...p, status: 'uploading' as DocStatus } : p)));
    try {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('type', 'photo');

      const res = await fetch('/api/upload', { method: 'POST', body: fd });
      const json = await res.json();

      if (!res.ok || !json.success) {
        throw new Error(json.error || 'Upload failed');
      }

      setPhotos((prev) =>
        prev.map((p) => (p.id === photoId ? { ...p, status: 'uploaded' as DocStatus, uploadedUrl: json.data.url } : p))
      );
    } catch {
      setPhotos((prev) => prev.map((p) => (p.id === photoId ? { ...p, status: 'failed' as DocStatus } : p)));
      toast.error('Fotoğraf yüklenemedi.');
    }
  };

  /* ── Video upload helper ── */
  const uploadVideo = async (videoId: string, file: File) => {
    setVideos((prev) => prev.map((v) => (v.id === videoId ? { ...v, status: 'uploading' as DocStatus } : v)));
    try {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('type', 'video');

      const res = await fetch('/api/upload', { method: 'POST', body: fd });
      const json = await res.json();

      if (!res.ok || !json.success) {
        throw new Error(json.error || 'Upload failed');
      }

      setVideos((prev) =>
        prev.map((v) => (v.id === videoId ? { ...v, status: 'uploaded' as DocStatus, uploadedUrl: json.data.url } : v))
      );
    } catch {
      setVideos((prev) => prev.map((v) => (v.id === videoId ? { ...v, status: 'failed' as DocStatus } : v)));
      toast.error('Video yüklenemedi.');
    }
  };

  /* ── Photo handlers (step 3) ── */
  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    e.target.value = '';

    Array.from(files).forEach((file) => {
      if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) {
        toast.error('Sadece JPEG, PNG veya WebP formatında fotoğraf yükleyebilirsiniz.');
        return;
      }
      if (file.size > 5 * 1024 * 1024) {
        toast.error('Fotoğraf boyutu maksimum 5 MB olabilir.');
        return;
      }
      if (photos.length >= 5) {
        toast.error('En fazla 5 fotoğraf yükleyebilirsiniz.');
        return;
      }

      const previewUrl = URL.createObjectURL(file);
      const newPhoto: PhotoItem = {
        id: Math.random().toString(36).substring(7),
        file,
        previewUrl,
        label: file.name,
        status: 'ready',
      };
      setPhotos((prev) => [...prev, newPhoto]);
      uploadPhoto(newPhoto.id, file);
    });
  };

  const handlePhotoDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setPhotoDragOver(false);
    const files = e.dataTransfer.files;
    if (!files) return;

    Array.from(files).forEach((file) => {
      if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) return;
      if (file.size > 5 * 1024 * 1024) return;
      if (photos.length >= 5) return;

      const previewUrl = URL.createObjectURL(file);
      const newPhoto: PhotoItem = {
        id: Math.random().toString(36).substring(7),
        file,
        previewUrl,
        label: file.name,
        status: 'ready',
      };
      setPhotos((prev) => [...prev, newPhoto]);
      uploadPhoto(newPhoto.id, file);
    });
  };

  const handleRemovePhoto = (id: string) => {
    setPhotos((prev) => {
      const photo = prev.find((p) => p.id === id);
      if (photo) URL.revokeObjectURL(photo.previewUrl);
      return prev.filter((p) => p.id !== id);
    });
  };

  /* ── Submit handler (no form tag) ── */
  const handleSubmit = async () => {
      const { t } = useTranslation();
    if (loading || submitted) return;

    if (!validateForm()) {
      toast.error(t('apply.validation.fixErrors'));
      const newErrors: Record<string, string> = {};
      // Re-validate to get current errors
      if (!formData.fullName.trim() || formData.fullName.trim().length < 2) { setCurrentStep(1); return; }
      if (!formData.email.trim() || !validateEmail(formData.email)) { setCurrentStep(1); return; }
      if (!formData.country) { setCurrentStep(1); return; }
      const minTarget = formData.country === 'TR' ? 2500 : 50;
      if (!formData.educationLevel || !formData.classYear || !formData.faculty.trim() || !formData.department.trim() || !formData.targetAmount || parseInt(formData.targetAmount) < minTarget) { setCurrentStep(2); return; }
      if (!formData.needSummary.trim() || formData.needSummary.trim().length < MIN_DESCRIPTION_LENGTH) { setCurrentStep(3); return; }
      return;
    }

    const pendingDocs = documents.some((d) => d.status === 'uploading');
    const failedDocs = documents.some((d) => d.status === 'failed');
    const pendingPhotos = photos.some((p) => p.status === 'uploading');
    const failedPhotos = photos.some((p) => p.status === 'failed');
    const pendingVideos = videos.some((v) => v.status === 'uploading');
    const failedVideos = videos.some((v) => v.status === 'failed');

    if (pendingDocs || pendingPhotos || pendingVideos) {
      toast.warning(t('apply.validation.waitUpload'));
      return;
    }
    if (failedDocs || failedPhotos || failedVideos) {
      toast.error(t('apply.validation.removeFailed'));
      return;
    }

    setLoading(true);
    setSubmitted(true);

    try {
      // Build document objects with name + URL
      const documentData = documents
        .filter((d) => d.status === 'uploaded' && d.uploadedUrl)
        .map((d) => ({ name: d.name, url: d.uploadedUrl! }));

      // Build photo URLs
      const photoUrls = photos
        .filter((p) => p.status === 'uploaded' && p.uploadedUrl)
        .map((p) => p.uploadedUrl!);

      const videoUrls = videos
        .filter((v) => v.status === 'uploaded' && v.uploadedUrl)
        .map((v) => v.uploadedUrl!);

      const response = await fetch('/api/ops/applications', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: sanitizeInput(formData.fullName),
          email: formData.email.trim().toLowerCase(),
          country: formData.country,
          city: formData.city || undefined,
          gender: formData.gender,
          educationLevel: formData.educationLevel,
          category: formData.category || undefined,
          needSummary: sanitizeInput(formData.needSummary),
          documents: documentData,
          photos: photoUrls,
          videos: videoUrls,
          targetAmount: parseInt(formData.targetAmount) || 0,
          classYear: formData.classYear,
          faculty: sanitizeInput(formData.faculty),
          department: sanitizeInput(formData.department),
          campaignTitle: sanitizeInput(formData.campaignTitle || ''),
        }),
      });
      const result = await response.json();
      if (!response.ok || !result.success) throw new Error(result.error || t('apply.validation.error'));
      toast.success(t('apply.validation.success'));
      setTimeout(() => router.push(`/student/status?id=${result.data.id}`), 500);
    } catch (error: any) {
      console.error('Failed to submit application:', error);
      toast.error(error.message || t('apply.validation.error'));
      setSubmitted(false);
    } finally {
      setLoading(false);
    }
  };

  const descriptionLength = formData.needSummary.trim().length;

  const movePhoto = (index: number, direction: 'up' | 'down') => {
    setPhotos((prev) => {
      const newArr = [...prev];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;
      if (targetIndex < 0 || targetIndex >= newArr.length) return prev;
      const temp = newArr[index];
      newArr[index] = newArr[targetIndex];
      newArr[targetIndex] = temp;
      return newArr;
    });
  };

  const moveVideo = (index: number, direction: 'up' | 'down') => {
    setVideos((prev) => {
      const newArr = [...prev];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;
      if (targetIndex < 0 || targetIndex >= newArr.length) return prev;
      const temp = newArr[index];
      newArr[index] = newArr[targetIndex];
      newArr[targetIndex] = temp;
      return newArr;
    });
  };

  /* ───────────────────────
     RENDER
     ─────────────────────── */
  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar />
      <main className="flex-grow">

        {/* ═══════════ HERO ═══════════ */}
        <section className="relative overflow-hidden bg-gradient-to-br from-emerald-600 via-teal-600 to-cyan-700">
          <div className="absolute inset-0 pointer-events-none">
            <div className="absolute -top-24 -right-24 w-[500px] h-[500px] bg-white/5 rounded-full blur-[80px]" />
            <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-white/5 rounded-full blur-[80px]" />
            <div
              className="absolute inset-0 opacity-[0.04]"
              style={{
                backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)',
                backgroundSize: '32px 32px',
              }}
            />
          </div>

          <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 sm:py-20">
            <div className="max-w-3xl mx-auto text-center">
              <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md border border-white/20 rounded-full px-5 py-2 mb-6">
                <GraduationCap className="h-4 w-4 text-yellow-300" />
                <span className="text-sm text-white/90 font-medium">{t('app.page.renci_ba_vuru_formu')}</span>
              </div>

              <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-4 leading-tight">
                {t('app.page.e_itim_hayallerinize')}<br />
                <span className="bg-gradient-to-r from-yellow-200 via-amber-200 to-orange-200 bg-clip-text text-transparent">
                  {t('app.page.birlikte_ula_al_m')}</span>
              </h1>

              <p className="text-base sm:text-lg text-emerald-100/80 leading-relaxed max-w-xl mx-auto">
                {t('app.page.ba_vurunuzu_tamamlay_n_do_rula')}</p>
            </div>
          </div>

          <div className="absolute bottom-0 left-0 right-0">
            <svg viewBox="0 0 1440 60" fill="none" className="w-full">
              <path d="M0 60L60 52C120 44 240 28 360 24C480 20 600 28 720 32C840 36 960 36 1080 32C1200 28 1320 20 1380 16L1440 12V60H0Z" fill="#f8fafc" />
            </svg>
          </div>
        </section>

        {/* ═══════════ MAIN CONTENT ═══════════ */}
        <section className="py-10 sm:py-14">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex flex-col lg:flex-row gap-8 lg:gap-12">

              {/* ──── LEFT: Form ──── */}
              <div className="lg:w-[65%]">

                {/* Step Indicator */}
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-5 mb-8">
                  <div className="flex items-center justify-between">
                    {STEPS.map((step, i) => {
                      const Icon = step.icon;
                      const isActive = currentStep === step.id;
                      const isCompleted = currentStep > step.id;
                      return (
                        <div key={step.id} className="flex items-center flex-1">
                          <button
                            type="button"
                            onClick={() => {
                              if (step.id < currentStep) setCurrentStep(step.id);
                            }}
                            className={`flex items-center gap-2.5 transition-all duration-300 ${isActive
                              ? 'text-emerald-600'
                              : isCompleted
                                ? 'text-emerald-500 cursor-pointer'
                                : 'text-slate-300'
                              }`}
                          >
                            <div
                              className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-300 ${isActive
                                ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30'
                                : isCompleted
                                  ? 'bg-emerald-100 text-emerald-600'
                                  : 'bg-slate-100 text-slate-400'
                                }`}
                            >
                              {isCompleted ? (
                                <CheckCircle className="h-5 w-5" />
                              ) : (
                                <Icon className="h-5 w-5" />
                              )}
                            </div>
                            <span className="text-sm font-medium hidden sm:block">{step.label}</span>
                          </button>
                          {i < STEPS.length - 1 && (
                            <div className="flex-1 mx-3">
                              <div className={`h-[2px] rounded-full transition-colors duration-300 ${isCompleted ? 'bg-emerald-300' : 'bg-slate-100'}`} />
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Form Card — NO <form> tag to prevent accidental submission */}
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">

                  {/* STEP 1 — Personal Info */}
                  {currentStep === 1 && (
                    <div className="p-6 sm:p-8 space-y-6">
                      <div className="flex items-center gap-3 mb-2">
                        <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center">
                          <User className="h-5 w-5 text-blue-500" />
                        </div>
                        <div>
                          <h2 className="text-xl font-bold text-slate-900">{t('app.page.ki_isel_bilgiler')}</h2>
                          <p className="text-sm text-slate-400">{t('app.page.temel_kimlik_ve_ileti_im_bilgi')}</p>
                        </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <FieldWrapper id="fullName" label={t('apply.labels.fullName')} icon={User} error={errors.fullName}>
                          <Input
                            id="fullName"
                            type="text"
                            value={formData.fullName}
                            onChange={(e) => {
                              setFormData({ ...formData, fullName: e.target.value });
                              if (errors.fullName) setErrors({ ...errors, fullName: '' });
                            }}
                            placeholder={t('apply.placeholders.fullName')}
                            className={inputClass(!!errors.fullName)}
                          />
                        </FieldWrapper>

                        <FieldWrapper id="email" label={t('apply.labels.email')} icon={Mail} error={errors.email}>
                          <Input
                            id="email"
                            type="email"
                            value={formData.email}
                            onChange={(e) => {
                              setFormData({ ...formData, email: e.target.value });
                              if (errors.email) setErrors({ ...errors, email: '' });
                            }}
                            placeholder={t('apply.placeholders.email')}
                            className={inputClass(!!errors.email)}
                          />
                        </FieldWrapper>

                        <FieldWrapper id="country" label={t('apply.labels.country')} icon={Globe} error={errors.country}>
                          <Select
                            value={formData.country}
                            onValueChange={(value) => {
                              setFormData({ ...formData, country: value, city: '' });
                              if (errors.country) setErrors({ ...errors, country: '' });
                            }}
                          >
                            <SelectTrigger id="country" className={selectTriggerClass(!!errors.country)}>
                              <SelectValue placeholder={t('apply.placeholders.country')} />
                            </SelectTrigger>
                            <SelectContent>
                              {COUNTRIES.map((c, index) => (
                                <SelectItem key={c.value} value={c.value}>
                                  {c.flag} {c.labelTr}{index === 0 ? '' : ` / ${c.label}`}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FieldWrapper>

                        {formData.country === 'TR' && (
                          <FieldWrapper id="city" label={t('app.page.ehir_city')} icon={MapPin} error={errors.city} required={false}>
                            <Select
                              value={formData.city}
                              onValueChange={(value) => {
                                setFormData({ ...formData, city: value });
                              }}
                            >
                              <SelectTrigger id="city" className={selectTriggerClass(false)}>
                                <SelectValue placeholder={t('app.page.ehir_se_iniz')} />
                              </SelectTrigger>
                              <SelectContent>
                                {TURKEY_CITIES.map((city) => (
                                  <SelectItem key={city} value={city}>
                                    {city}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </FieldWrapper>
                        )}

                        <FieldWrapper id="gender" label={t('apply.labels.gender')} icon={UserCircle} error={errors.gender}>
                          <Select
                            value={formData.gender}
                            onValueChange={(value) => {
                              setFormData({ ...formData, gender: value });
                              if (errors.gender) setErrors({ ...errors, gender: '' });
                            }}
                          >
                            <SelectTrigger id="gender" className={selectTriggerClass(!!errors.gender)}>
                              <SelectValue placeholder={t('apply.placeholders.selectGender')} />
                            </SelectTrigger>
                            <SelectContent>
                              {GENDER_OPTIONS.map((opt) => (
                                <SelectItem key={opt.value} value={opt.value}>
                                  {t(opt.labelKey)}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FieldWrapper>
                      </div>
                    </div>
                  )}

                  {/* STEP 2 — Education Info */}
                  {currentStep === 2 && (
                    <div className="p-6 sm:p-8 space-y-6">
                      <div className="flex items-center gap-3 mb-2">
                        <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center">
                          <GraduationCap className="h-5 w-5 text-emerald-500" />
                        </div>
                        <div>
                          <h2 className="text-xl font-bold text-slate-900">{t('app.page.e_itim_bilgileri')}</h2>
                          <p className="text-sm text-slate-400">{t('app.page.e_itim_durumunuz_ve_hedef_b_t_')}</p>
                        </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <FieldWrapper id="educationLevel" label={t('apply.labels.educationLevel')} icon={BookOpen} error={errors.educationLevel}>
                          <Select
                            value={formData.educationLevel}
                            onValueChange={(value) => {
                              setFormData({ ...formData, educationLevel: value });
                              if (errors.educationLevel) setErrors({ ...errors, educationLevel: '' });
                            }}
                          >
                            <SelectTrigger id="educationLevel" className={selectTriggerClass(!!errors.educationLevel)}>
                              <SelectValue placeholder={t('apply.placeholders.select')} />
                            </SelectTrigger>
                            <SelectContent>
                              {EDUCATION_LEVEL_KEYS.map((key) => (
                                <SelectItem key={key} value={t(`apply.options.educationLevel.${key}`)}>
                                  {t(`apply.options.educationLevel.${key}`)}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FieldWrapper>

                        <FieldWrapper id="classYear" label={t('apply.labels.classYear')} icon={Calendar} error={errors.classYear}>
                          <Select
                            value={formData.classYear}
                            onValueChange={(value) => {
                              setFormData({ ...formData, classYear: value });
                              if (errors.classYear) setErrors({ ...errors, classYear: '' });
                            }}
                          >
                            <SelectTrigger id="classYear" className={selectTriggerClass(!!errors.classYear)}>
                              <SelectValue placeholder={t('apply.placeholders.select')} />
                            </SelectTrigger>
                            <SelectContent>
                              {CLASS_YEAR_KEYS.map((key) => (
                                <SelectItem key={key} value={t(`apply.options.classYear.${key}`)}>
                                  {t(`apply.options.classYear.${key}`)}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FieldWrapper>

                        <FieldWrapper id="faculty" label={t('apply.labels.faculty')} icon={Building} error={errors.faculty}>
                          <Input
                            id="faculty"
                            type="text"
                            value={formData.faculty}
                            onChange={(e) => {
                              setFormData({ ...formData, faculty: e.target.value });
                              if (errors.faculty) setErrors({ ...errors, faculty: '' });
                            }}
                            placeholder={t('apply.placeholders.faculty')}
                            className={inputClass(!!errors.faculty)}
                          />
                        </FieldWrapper>

                        <FieldWrapper id="department" label={t('apply.labels.department')} icon={Layers} error={errors.department}>
                          <Input
                            id="department"
                            type="text"
                            value={formData.department}
                            onChange={(e) => {
                              setFormData({ ...formData, department: e.target.value });
                              if (errors.department) setErrors({ ...errors, department: '' });
                            }}
                            placeholder={t('apply.placeholders.department')}
                            className={inputClass(!!errors.department)}
                          />
                        </FieldWrapper>

                        <FieldWrapper id="category" label={t('app.page.htiya_kategorisi_need_category')} icon={Tag} error={errors.category} required={false}>
                          <Select
                            value={formData.category}
                            onValueChange={(value) => {
                              setFormData({ ...formData, category: value });
                              if (errors.category) setErrors({ ...errors, category: '' });
                            }}
                          >
                            <SelectTrigger id="category" className={selectTriggerClass(!!errors.category)}>
                              <SelectValue placeholder={t('app.page.kategori_se_iniz_select_catego')} />
                            </SelectTrigger>
                            <SelectContent>
                              {FUNDING_CATEGORIES.map((cat) => (
                                <SelectItem key={cat.value} value={cat.value}>
                                  {cat.labelTr} / {cat.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FieldWrapper>

                        <div className="md:col-span-2">
                          <FieldWrapper id="targetAmount" label={t('apply.labels.targetAmount')} icon={DollarSign} error={errors.targetAmount}>
                            <div className="relative">
                              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-semibold text-sm">$</span>
                              <Input
                                id="targetAmount"
                                type="number"
                                min={1}
                                value={formData.targetAmount}
                                onChange={(e) => {
                                  setFormData({ ...formData, targetAmount: e.target.value });
                                  if (errors.targetAmount) setErrors({ ...errors, targetAmount: '' });
                                }}
                                placeholder={t('apply.placeholders.targetAmount')}
                                className={`${inputClass(!!errors.targetAmount)} pl-8`}
                              />
                            </div>
                          </FieldWrapper>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* STEP 3 — Need Summary + Optional Photos */}
                  {currentStep === 3 && (
                    <div className="p-6 sm:p-8 space-y-6">
                      <div className="flex items-center gap-3 mb-2">
                        <div className="w-10 h-10 rounded-xl bg-purple-50 flex items-center justify-center">
                          <FileText className="h-5 w-5 text-purple-500" />
                        </div>
                        <div>
                          <h2 className="text-xl font-bold text-slate-900">{t('app.page.htiya_detay')}</h2>
                          <p className="text-sm text-slate-400">{t('app.page.durumunuzu_ve_ihtiya_lar_n_z_a')}</p>
                        </div>
                      </div>

                      <div className="bg-blue-50/50 border border-blue-100 rounded-xl p-4 flex items-start gap-3">
                        <HelpCircle className="h-5 w-5 text-blue-500 flex-shrink-0 mt-0.5" />
                        <div className="text-sm text-blue-700 leading-relaxed">
                          <p className="font-medium mb-1">{t('app.page.pu_lar')}</p>
                          <ul className="list-disc list-inside space-y-1 text-blue-600">
                            <li>{t('app.page.e_itim_durumunuzu_ve_maddi_iht')}</li>
                            <li>{t('app.page.ba_lar_n_sizi_daha_iyi_tan_mas')}</li>
                            <li>{t('app.page.neye_ihtiyac_n_z_oldu_unu_kita')}</li>
                          </ul>
                        </div>
                      </div>

                      {/* Description + Custom Campaign Title */}
                      <div className="space-y-2">
                        <div className="flex justify-between items-center">
                          <Label htmlFor="needSummary" className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                            <FileText className="h-4 w-4 text-slate-400" />
                            {t('apply.labels.needSummary', { min: MIN_DESCRIPTION_LENGTH })}
                            <span className="text-red-400">*</span>
                          </Label>
                          <div className="flex items-center gap-2">
                            <div className="h-1.5 w-20 rounded-full bg-slate-100 overflow-hidden">
                              <div
                                className={`h-full rounded-full transition-all duration-300 ${descriptionLength >= MIN_DESCRIPTION_LENGTH ? 'bg-emerald-500' : 'bg-amber-400'
                                  }`}
                                style={{ width: `${Math.min(100, (descriptionLength / MIN_DESCRIPTION_LENGTH) * 100)}%` }}
                              />
                            </div>
                            <span className={`text-xs font-medium ${descriptionLength < MIN_DESCRIPTION_LENGTH ? 'text-amber-500' : 'text-emerald-500'}`}>
                              {descriptionLength}/{MIN_DESCRIPTION_LENGTH}
                            </span>
                          </div>
                        </div>
                        <Textarea
                          id="needSummary"
                          value={formData.needSummary}
                          onChange={(e) => {
                            setFormData({ ...formData, needSummary: e.target.value });
                            if (errors.needSummary) setErrors({ ...errors, needSummary: '' });
                          }}
                          placeholder={t('apply.placeholders.needSummary')}
                          rows={8}
                          className={`rounded-xl border-slate-200 bg-white focus:border-purple-400 focus:ring-purple-400/20 focus:ring-4 transition-all duration-200 text-slate-800 placeholder:text-slate-300 resize-none ${errors.needSummary ? 'border-red-400' : ''
                            }`}
                        />
                        {errors.needSummary && (
                          <p className="text-xs text-red-500 flex items-center gap-1">
                            <AlertCircle className="h-3 w-3" />
                            {errors.needSummary}
                          </p>
                        )}
                      </div>

                      {/* Optional custom campaign title (used as headline when approved) */}
                      <div className="space-y-2 pt-2">
                        <Label htmlFor="campaignTitle" className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                          <FileText className="h-4 w-4 text-slate-400" />
                          {t('app.page.kampanya_ba_l_opsiyonel')}</Label>
                        <Input
                          id="campaignTitle"
                          type="text"
                          value={formData.campaignTitle}
                          onChange={(e) => {
                            setFormData({ ...formData, campaignTitle: e.target.value });
                          }}
                          placeholder={t('app.page.rn_mehmet_in_bilgisayar_m_hend')}
                          className={inputClass(false)}
                          maxLength={200}
                        />
                        <p className="text-xs text-slate-400">
                          {t('app.page.bu_alan_doldurursan_z_kampanya')}</p>
                      </div>

                      {/* ── Optional Photo Upload ── */}
                      <div className="space-y-3 pt-2">
                        <div className="flex items-center justify-between">
                          <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                            <Camera className="h-4 w-4 text-slate-400" />
                            {t('app.page.foto_raflar')}<span className="text-xs font-normal text-slate-400 ml-1">(Opsiyonel)</span>
                          </Label>
                          <span className="text-xs text-slate-400">{photos.length}/5</span>
                        </div>

                        <div className="bg-purple-50/50 border border-purple-100 rounded-xl p-3.5 flex items-start gap-2.5">
                          <Camera className="h-4 w-4 text-purple-400 flex-shrink-0 mt-0.5" />
                          <p className="text-xs text-purple-600 leading-relaxed">
                            {t('app.page.kendinizin_okulunuzun_veya_e_i')}</p>
                        </div>

                        <input
                          type="file"
                          ref={photoInputRef}
                          className="hidden"
                          accept="image/jpeg,image/png,image/webp"
                          multiple
                          onChange={handlePhotoSelect}
                        />

                        {/* Photo grid */}
                        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                          {photos.map((photo, index) => (
                            <div key={photo.id} className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-[4/3] flex flex-col">
                              <div className="relative flex-1 w-full">
                                <img
                                  src={photo.previewUrl}
                                  alt={photo.label}
                                  className="w-full h-full object-cover"
                                />
                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors duration-200" />
                                {/* Upload status overlay */}
                                {photo.status === 'uploading' && (
                                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                                    <Loader2 className="h-6 w-6 text-white animate-spin" />
                                  </div>
                                )}
                                {photo.status === 'uploaded' && (
                                  <div className="absolute top-2 left-2">
                                    <div className="w-6 h-6 rounded-full bg-emerald-500 flex items-center justify-center shadow-sm">
                                      <CheckCircle className="h-3.5 w-3.5 text-white" />
                                    </div>
                                  </div>
                                )}
                                {photo.status === 'failed' && (
                                  <div className="absolute inset-0 bg-red-500/20 flex items-center justify-center">
                                    <div className="bg-red-500 text-white text-[10px] px-2 py-1 rounded-full font-medium">
                                      {t('app.page.y_kleme_ba_ar_s_z')}</div>
                                  </div>
                                )}
                                <button
                                  type="button"
                                  onClick={() => handleRemovePhoto(photo.id)}
                                  className="absolute top-2 right-2 w-7 h-7 rounded-full bg-black/50 backdrop-blur-sm flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity duration-200 hover:bg-red-500"
                                >
                                  <X className="h-3.5 w-3.5" />
                                </button>
                                <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/60 to-transparent p-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                                  <p className="text-[10px] text-white truncate">{photo.label}</p>
                                </div>
                              </div>

                              {/* Order controls */}
                              <div className="flex items-center justify-between px-2 py-1.5 bg-slate-900/80 text-white text-[10px]">
                                <div className="flex items-center gap-1">
                                  <GripVertical className="h-3 w-3 text-slate-400" />
                                  <span className="font-medium">{t('app.page.foto_raf')}{index + 1}</span>
                                </div>
                                <div className="flex items-center gap-1">
                                  <button
                                    type="button"
                                    onClick={() => movePhoto(index, 'up')}
                                    disabled={index === 0}
                                    className="disabled:opacity-40 hover:text-emerald-300 transition-colors"
                                  >
                                    <ChevronUp className="h-3 w-3" />
                                  </button>
                                  <button
                                    type="button"
                                    onClick={() => movePhoto(index, 'down')}
                                    disabled={index === photos.length - 1}
                                    className="disabled:opacity-40 hover:text-emerald-300 transition-colors"
                                  >
                                    <ChevronDown className="h-3 w-3" />
                                  </button>
                                </div>
                              </div>
                            </div>
                          ))}

                          {/* Add photo button */}
                          {photos.length < 5 && (
                            <div
                              onClick={() => photoInputRef.current?.click()}
                              onDragOver={(e) => { e.preventDefault(); setPhotoDragOver(true); }}
                              onDragLeave={() => setPhotoDragOver(false)}
                              onDrop={handlePhotoDrop}
                              className={`aspect-[4/3] rounded-xl border-2 border-dashed flex flex-col items-center justify-center cursor-pointer transition-all duration-200 ${photoDragOver
                                ? 'border-purple-400 bg-purple-50'
                                : 'border-slate-200 hover:border-purple-300 hover:bg-purple-50/50 bg-slate-50/50'
                                }`}
                            >
                              <ImagePlus className={`h-7 w-7 mb-1.5 transition-colors ${photoDragOver ? 'text-purple-500' : 'text-slate-300'}`} />
                              <span className="text-xs text-slate-400 font-medium">{t('app.page.foto_raf_ekle')}</span>
                              <span className="text-[10px] text-slate-300 mt-0.5">{t('app.page.jpeg_png_webp')}</span>
                            </div>
                          )}
                        </div>
                      </div>

                      {/* ── Optional Video Upload ── */}
                      <div className="space-y-3 pt-4">
                        <div className="flex items-center justify-between">
                          <Label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                            <Film className="h-4 w-4 text-slate-400" />
                            {t('app.page.videolar')}<span className="text-xs font-normal text-slate-400 ml-1">(Opsiyonel)</span>
                          </Label>
                          <span className="text-xs text-slate-400">{videos.length}/2</span>
                        </div>

                        <input
                          type="file"
                          ref={videoInputRef}
                          className="hidden"
                          accept="video/mp4,video/quicktime,video/webm"
                          multiple
                          onChange={(e) => {
                            const files = e.target.files;
                            if (!files) return;
                            e.target.value = '';

                            Array.from(files).forEach((file) => {
                              if (!file.type.startsWith('video/')) {
                                toast.error('Sadece video dosyaları yükleyebilirsiniz.');
                                return;
                              }
                              if (file.size > 50 * 1024 * 1024) {
                                toast.error('Video boyutu maksimum 50 MB olabilir.');
                                return;
                              }
                              if (videos.length >= 2) {
                                toast.error('En fazla 2 video yükleyebilirsiniz.');
                                return;
                              }

                              const previewUrl = URL.createObjectURL(file);
                              const newVideo: VideoItem = {
                                id: Math.random().toString(36).substring(7),
                                file,
                                previewUrl,
                                label: file.name,
                                status: 'ready',
                              };
                              setVideos((prev) => [...prev, newVideo]);
                              uploadVideo(newVideo.id, file);
                            });
                          }}
                        />

                        <div
                          onClick={() => videoInputRef.current?.click()}
                          onDragOver={(e) => {
                            e.preventDefault();
                            setVideoDragOver(true);
                          }}
                          onDragLeave={() => setVideoDragOver(false)}
                          onDrop={(e) => {
                            e.preventDefault();
                            setVideoDragOver(false);
                            const files = e.dataTransfer.files;
                            if (!files) return;

                            Array.from(files).forEach((file) => {
                              if (!file.type.startsWith('video/')) return;
                              if (file.size > 50 * 1024 * 1024) return;
                              if (videos.length >= 2) return;

                              const previewUrl = URL.createObjectURL(file);
                              const newVideo: VideoItem = {
                                id: Math.random().toString(36).substring(7),
                                file,
                                previewUrl,
                                label: file.name,
                                status: 'ready',
                              };
                              setVideos((prev) => [...prev, newVideo]);
                              uploadVideo(newVideo.id, file);
                            });
                          }}
                          className={`rounded-xl border-2 border-dashed flex flex-col items-center justify-center p-4 text-center cursor-pointer transition-all duration-200 ${videoDragOver
                              ? 'border-blue-400 bg-blue-50'
                              : 'border-slate-200 hover:border-blue-300 hover:bg-blue-50/40 bg-slate-50/50'
                            }`}
                        >
                          <Film className={`h-7 w-7 mb-1.5 ${videoDragOver ? 'text-blue-500' : 'text-slate-300'}`} />
                          <span className="text-xs text-slate-500 font-medium">{t('app.page.video_ekle_veya_b_rak')}</span>
                          <span className="text-[10px] text-slate-300 mt-0.5">{t('app.page.mp4_webm_quicktime_maks_50_mb')}</span>
                        </div>

                        {videos.length > 0 && (
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            {videos.map((video, index) => (
                              <div key={video.id} className="relative rounded-xl border border-slate-200 overflow-hidden bg-black">
                                <div className="aspect-video relative">
                                  <video
                                    src={video.previewUrl}
                                    className="w-full h-full object-contain bg-black"
                                    controls
                                  />
                                  {video.status === 'uploading' && (
                                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                                      <Loader2 className="h-6 w-6 text-white animate-spin" />
                                    </div>
                                  )}
                                  {video.status === 'failed' && (
                                    <div className="absolute inset-0 bg-red-500/30 flex items-center justify-center">
                                      <div className="bg-red-500 text-white text-[10px] px-2 py-1 rounded-full font-medium">
                                        {t('app.page.y_kleme_ba_ar_s_z')}</div>
                                    </div>
                                  )}
                                  <button
                                    type="button"
                                    onClick={() => {
                                      setVideos((prev) => {
                                        const found = prev.find((v) => v.id === video.id);
                                        if (found) URL.revokeObjectURL(found.previewUrl);
                                        return prev.filter((v) => v.id !== video.id);
                                      });
                                    }}
                                    className="absolute top-2 right-2 w-7 h-7 rounded-full bg-black/50 backdrop-blur-sm flex items-center justify-center text-white hover:bg-red-500"
                                  >
                                    <X className="h-3.5 w-3.5" />
                                  </button>
                                </div>
                                <div className="flex items-center justify-between px-2 py-1.5 bg-slate-900/80 text-white text-[10px]">
                                  <div className="flex items-center gap-1">
                                    <GripVertical className="h-3 w-3 text-slate-400" />
                                    <span className="font-medium">{t('app.page.video')}{index + 1}</span>
                                  </div>
                                  <div className="flex items-center gap-1">
                                    <button
                                      type="button"
                                      onClick={() => moveVideo(index, 'up')}
                                      disabled={index === 0}
                                      className="disabled:opacity-40 hover:text-emerald-300 transition-colors"
                                    >
                                      <ChevronUp className="h-3 w-3" />
                                    </button>
                                    <button
                                      type="button"
                                      onClick={() => moveVideo(index, 'down')}
                                      disabled={index === videos.length - 1}
                                      className="disabled:opacity-40 hover:text-emerald-300 transition-colors"
                                    >
                                      <ChevronDown className="h-3 w-3" />
                                    </button>
                                  </div>
                                </div>
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  )}

                  {/* STEP 4 — Documents */}
                  {currentStep === 4 && (
                    <div className="p-6 sm:p-8 space-y-6">
                      <div className="flex items-center gap-3 mb-2">
                        <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center">
                          <Upload className="h-5 w-5 text-amber-500" />
                        </div>
                        <div>
                          <h2 className="text-xl font-bold text-slate-900">{t('app.page.belgeler')}</h2>
                          <p className="text-sm text-slate-400">{t('app.page.kimlik_ve_e_itim_belgelerinizi')}</p>
                        </div>
                      </div>

                      <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-4 flex items-start gap-3">
                        <FileCheck className="h-5 w-5 text-amber-500 flex-shrink-0 mt-0.5" />
                        <div className="text-sm text-amber-700">
                          <p>{t('apply.documents.help')}</p>
                          <p className="text-xs text-amber-500 mt-1">{t('app.page.pdf_jpeg_png_maks_10_mb')}</p>
                        </div>
                      </div>

                      <input
                        type="file"
                        ref={fileInputRef}
                        className="hidden"
                        accept="application/pdf,image/jpeg,image/png"
                        onChange={handleFileSelect}
                      />

                      {/* Drag & Drop Zone */}
                      <div
                        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                        onDragLeave={() => setDragOver(false)}
                        onDrop={handleDrop}
                        className={`border-2 border-dashed rounded-2xl p-8 text-center transition-all duration-300 cursor-pointer ${dragOver ? 'border-emerald-400 bg-emerald-50' : 'border-slate-200 hover:border-slate-300 bg-slate-50/50'
                          }`}
                        onClick={handleAddDocumentClick}
                      >
                        <div className="w-14 h-14 mx-auto mb-4 rounded-2xl bg-white border border-slate-200 flex items-center justify-center shadow-sm">
                          <Upload className={`h-7 w-7 transition-colors ${dragOver ? 'text-emerald-500' : 'text-slate-400'}`} />
                        </div>
                        <p className="text-sm font-medium text-slate-600 mb-1">
                          {dragOver ? 'Dosyayı bırakın...' : 'Dosyaları sürükleyip bırakın'}
                        </p>
                        <p className="text-xs text-slate-400">{t('app.page.veya_t_klayarak_dosya_se_in')}</p>
                      </div>

                      {/* Optional name input */}
                      <div className="flex gap-2">
                        <Input
                          type="text"
                          value={documentNameInput}
                          onChange={(e) => setDocumentNameInput(e.target.value)}
                          placeholder={t('apply.placeholders.documentName')}
                          className="flex-1 h-11 rounded-xl border-slate-200 bg-white focus:border-blue-400 focus:ring-blue-400/20 focus:ring-4"
                        />
                        <Button
                          type="button"
                          variant="outline"
                          onClick={handleAddDocumentClick}
                          className="h-11 rounded-xl border-slate-200 hover:bg-slate-50"
                        >
                          <Upload className="h-4 w-4 mr-2" />
                          {t('apply.documents.add')}
                        </Button>
                      </div>

                      {/* Document List */}
                      {documents.length > 0 && (
                        <div className="space-y-2.5">
                          {documents.map((doc) => (
                            <div
                              key={doc.id}
                              className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-200 ${doc.status === 'uploaded'
                                ? 'bg-emerald-50/50 border-emerald-100'
                                : doc.status === 'failed'
                                  ? 'bg-red-50/50 border-red-100'
                                  : 'bg-white border-slate-100'
                                }`}
                            >
                              <div className="flex items-center gap-3 min-w-0">
                                {doc.status === 'uploading' && <Loader2 className="h-5 w-5 text-blue-500 animate-spin flex-shrink-0" />}
                                {doc.status === 'uploaded' && <CheckCircle className="h-5 w-5 text-emerald-500 flex-shrink-0" />}
                                {doc.status === 'failed' && <AlertCircle className="h-5 w-5 text-red-500 flex-shrink-0" />}
                                {doc.status === 'ready' && <FileText className="h-5 w-5 text-slate-400 flex-shrink-0" />}
                                <div className="min-w-0">
                                  <p className="text-sm font-medium text-slate-800 truncate">{doc.name}</p>
                                  <p className="text-xs text-slate-400">
                                    {(doc.size / 1024 / 1024).toFixed(2)} {t('app.page.mb')}{' '}
                                    <span className={
                                      doc.status === 'uploaded'
                                        ? 'text-emerald-500'
                                        : doc.status === 'uploading'
                                          ? 'text-blue-500'
                                          : doc.status === 'failed'
                                            ? 'text-red-500'
                                            : 'text-slate-400'
                                    }>
                                      {doc.status === 'uploaded'
                                        ? t('apply.documents.status.uploaded')
                                        : doc.status === 'uploading'
                                          ? t('apply.documents.status.uploading')
                                          : t('apply.documents.status.failed')}
                                    </span>
                                  </p>
                                </div>
                              </div>
                              <button
                                type="button"
                                onClick={() => handleRemoveDocument(doc.id)}
                                className="w-8 h-8 rounded-lg flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors flex-shrink-0"
                              >
                                <X className="h-4 w-4" />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )}

                  {/* ── Navigation Buttons — outside form, pure onClick ── */}
                  <div className="border-t border-slate-100 px-6 sm:px-8 py-5 flex items-center justify-between bg-slate-50/50">
                    <div>
                      {currentStep > 1 && (
                        <Button
                          type="button"
                          variant="ghost"
                          onClick={prevStep}
                          className="h-11 rounded-xl text-slate-600 hover:text-slate-900 hover:bg-slate-100"
                        >
                          <ArrowLeft className="h-4 w-4 mr-2" />
                          {t('app.page.geri')}</Button>
                      )}
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-xs text-slate-400 hidden sm:block">
                        {t('app.page.ad_m')}{currentStep}/{STEPS.length}
                      </span>
                      {currentStep < 4 ? (
                        <Button
                          type="button"
                          onClick={nextStep}
                          className="h-11 px-7 rounded-xl bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-400 hover:to-teal-500 text-white shadow-lg shadow-emerald-500/20 font-semibold"
                        >
                          {t('app.page.devam_et')}<ArrowRight className="h-4 w-4 ml-2" />
                        </Button>
                      ) : (
                        <Button
                          type="button"
                          disabled={loading || submitted}
                          onClick={handleSubmit}
                          className="h-11 px-8 rounded-xl bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-400 hover:to-teal-500 text-white shadow-lg shadow-emerald-500/20 font-semibold disabled:opacity-50"
                        >
                          {loading ? (
                            <>
                              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                              {t('app.page.g_nderiliyor')}</>
                          ) : (
                            <>
                              <Sparkles className="h-4 w-4 mr-2" />
                              {t('apply.submit.default')}
                            </>
                          )}
                        </Button>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              {/* ──── RIGHT: Sidebar ──── */}
              <div className="lg:w-[35%] space-y-6">

                {/* Process Card */}
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
                  <h3 className="text-lg font-bold text-slate-900 mb-5 flex items-center gap-2">
                    <Zap className="h-5 w-5 text-amber-500" />
                    {t('app.page.ba_vuru_s_reci')}</h3>
                  <div className="space-y-4">
                    {[
                      { num: 1, label: 'Formu doldurun', desc: 'Bilgilerinizi ve ihtiyaçlarınızı paylaşın', color: 'bg-blue-500' },
                      { num: 2, label: 'Belgelerinizi yükleyin', desc: 'Kimlik ve öğrenim belgelerinizi ekleyin', color: 'bg-emerald-500' },
                      { num: 3, label: 'Doğrulama', desc: 'Ekibimiz başvurunuzu inceleyecek', color: 'bg-purple-500' },
                      { num: 4, label: 'Bağışçılarla buluşun', desc: 'Profiliniz yayınlanır, destek başlar', color: 'bg-amber-500' },
                    ].map((item) => (
