                                                            ? `$${getDiscountedPrice(tiers.find(t => t.id === selectedTier)?.price || 0)}/ay — Satın Al & Kayıt Ol`
                                                            : 'Satın Al & Kayıt Ol'
                                                        : 'Başvuru Gönder'
                                                    }
                                                    <ArrowRight className="ml-2 h-4.5 w-4.5" />
                                                </>
                                            )}
                                        </Button>
                                    </form>

                                    <div className="mt-6 pt-6 border-t border-white/10">
