                            <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center flex-shrink-0">
                                <Sparkles className="h-6 w-6 text-blue-600" />
                            </div>
                            <div className="flex-1">
                                <h4 className="font-semibold text-gray-900 mb-1">{t('app.page.daha_fazla_zellik_mi_istiyorsu')}</h4>
                                <p className="text-sm text-gray-600 mb-3">
                                    {currentTierKey === 'starter'
                                        ? 'Growth/Pro planına yükselterek aylık raporlar, gelişmiş kanıt yönetimi ve 5 kullanıcı hakkı elde edin.'
                                        : 'Enterprise planına yükselterek denetim paketi, SSO, API erişimi ve sınırsız kampanya hakkı elde edin.'
                                    }
                                </p>
                                <Button
                                    onClick={() => setShowUpgradeModal(true)}
                                    size="sm"
                                    className="gap-2 bg-blue-600 hover:bg-blue-700 text-white"
                                >
                                    <ArrowUpRight className="h-4 w-4" />
                                    {t('app.page.planlar_kar_la_t_r')}</Button>
                            </div>
                        </div>
                    </div>
                )}

                {/* ═══════════════════════════════════════════════════════ */}
                {/* END SUBSCRIPTION MANAGEMENT SECTION */}
                {/* ═══════════════════════════════════════════════════════ */}

                {/* Profile Settings */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
                    <h3 className="text-lg font-semibold text-gray-900 mb-6 flex items-center gap-2">
                        <Users className="h-5 w-5" />
                        {t('corporate.settings.profileSettings')}
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <Label>{t('corporate.settings.fullName')}</Label>
                            <Input
                                value={userName}
                                onChange={(e) => setUserName(e.target.value)}
                                className="mt-1"
                            />
                        </div>
                        <div>
                            <Label>{t('corporate.settings.email')}</Label>
                            <Input
                                type="email"
                                value={userEmail}
                                onChange={(e) => setUserEmail(e.target.value)}
                                className="mt-1"
                            />
                        </div>
                    </div>
                </div>

                {/* Team Members */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
                    <div className="flex items-center justify-between mb-6">
                        <h3 className="text-lg font-semibold text-gray-900 flex items-center gap-2">
                            <Users className="h-5 w-5" />
                            {t('corporate.settings.teamMembers')}
                        </h3>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setShowInviteModal(true)}
                        >
                            <UserPlus className="h-4 w-4 mr-2" />
                            {t('corporate.settings.inviteMember')}
                        </Button>
                    </div>
                    <div className="space-y-4">
                        {teamMembers.map((member) => (
                            <div
                                key={member.email}
                                className="flex items-center justify-between py-3 border-b border-gray-100 last:border-0"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-medium">
                                        {member.name.split(' ').map(n => n[0]).join('')}
                                    </div>
                                    <div>
                                        <p className="font-medium text-gray-900">{member.name}</p>
                                        <p className="text-sm text-gray-500">{member.email}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    {getRoleBadge(member.role)}
                                    <Select defaultValue={member.role}>
                                        <SelectTrigger className="w-36">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="viewer">{t('corporate.settings.viewer')}</SelectItem>
                                            <SelectItem value="editor">{t('corporate.settings.editor')}</SelectItem>
                                            <SelectItem value="payment_admin">{t('corporate.settings.paymentAdmin')}</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Security */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
                    <h3 className="text-lg font-semibold text-gray-900 mb-6 flex items-center gap-2">
                        <Shield className="h-5 w-5" />
                        {t('corporate.settings.security')}
                    </h3>
                    <div className="space-y-4">
                        <div className="flex items-center justify-between py-3 border-b border-gray-100">
                            <div className="flex items-center gap-3">
                                <Key className="h-5 w-5 text-gray-400" />
                                <div>
                                    <p className="font-medium text-gray-900">{t('corporate.settings.changePassword')}</p>
                                    <p className="text-sm text-gray-500">{t('corporate.settings.lastChanged')}</p>
                                </div>
                            </div>
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => setShowPasswordModal(true)}
                            >
                                {t('corporate.settings.change')}
                            </Button>
                        </div>
                        <div className="flex items-center justify-between py-3">
                            <div className="flex items-center gap-3">
                                <Smartphone className="h-5 w-5 text-gray-400" />
                                <div>
                                    <p className="font-medium text-gray-900">{t('corporate.settings.twoFactorAuth')}</p>
                                    <p className="text-sm text-gray-500">{t('corporate.settings.extraSecurity')}</p>
                                </div>
                            </div>
                            <Button
                                variant={twoFactorEnabled ? 'default' : 'outline'}
                                size="sm"
                                onClick={() => twoFactorEnabled ? setTwoFactorEnabled(false) : setShow2FAModal(true)}
                            >
                                {twoFactorEnabled ? (
                                    <>
                                        <Check className="h-4 w-4 mr-1" />
                                        {t('corporate.settings.active')}
                                    </>
                                ) : t('corporate.settings.enable')}
                            </Button>
                        </div>
                    </div>
                </div>

                {/* Notification Preferences */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
                    <h3 className="text-lg font-semibold text-gray-900 mb-6 flex items-center gap-2">
                        <Bell className="h-5 w-5" />
                        {t('corporate.settings.notificationPrefs')}
                    </h3>
                    <div className="space-y-4">
                        <label className="flex items-center gap-3 cursor-pointer">
                            <Checkbox defaultChecked />
                            <div>
                                <p className="font-medium text-gray-900">{t('corporate.settings.studentUpdates')}</p>
                                <p className="text-sm text-gray-500">{t('corporate.settings.studentUpdatesDesc')}</p>
                            </div>
                        </label>
                        <label className="flex items-center gap-3 cursor-pointer">
                            <Checkbox defaultChecked />
                            <div>
                                <p className="font-medium text-gray-900">{t('corporate.settings.thankYouMessages')}</p>
                                <p className="text-sm text-gray-500">{t('corporate.settings.thankYouMessagesDesc')}</p>
                            </div>
                        </label>
                        <label className="flex items-center gap-3 cursor-pointer">
                            <Checkbox defaultChecked />
                            <div>
                                <p className="font-medium text-gray-900">{t('corporate.settings.newCampaigns')}</p>
                                <p className="text-sm text-gray-500">{t('corporate.settings.newCampaignsDesc')}</p>
                            </div>
                        </label>
                        <label className="flex items-center gap-3 cursor-pointer">
                            <Checkbox />
                            <div>
                                <p className="font-medium text-gray-900">{t('corporate.settings.monthlySummary')}</p>
                                <p className="text-sm text-gray-500">{t('corporate.settings.monthlySummaryDesc')}</p>
                            </div>
                        </label>
                    </div>
                </div>

                {/* Save Button */}
                <div className="flex justify-end">
                    <Button size="lg" className="gap-2">
                        <Save className="h-5 w-5" />
                        {t('corporate.settings.saveChanges')}
                    </Button>
                </div>
            </div>

            {/* Invite Member Modal */}
            {showInviteModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50" onClick={() => setShowInviteModal(false)} />
                    <div className="relative bg-white rounded-xl shadow-xl max-w-md w-full p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="font-semibold text-lg flex items-center gap-2">
                                <Mail className="h-5 w-5 text-blue-600" />
                                {t('corporate.settings.inviteMember')}
                            </h3>
                            <Button variant="ghost" size="icon" onClick={() => setShowInviteModal(false)}>
                                <X className="h-4 w-4" />
                            </Button>
                        </div>
                        <p className="text-sm text-gray-500 mb-4">
                            {t('corporate.settings.inviteDesc')}
                        </p>
                        <div className="space-y-4">
                            <div>
                                <Label>{t('corporate.settings.emailAddress')}</Label>
                                <Input
                                    type="email"
                                    placeholder={t('corporate.settings.emailPlaceholder')}
                                    value={inviteEmail}
                                    onChange={(e) => setInviteEmail(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                            <div>
                                <Label>{t('corporate.settings.role')}</Label>
                                <Select value={inviteRole} onValueChange={setInviteRole}>
                                    <SelectTrigger className="mt-1">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="viewer">{t('corporate.settings.viewerDesc')}</SelectItem>
                                        <SelectItem value="editor">{t('corporate.settings.editorDesc')}</SelectItem>
                                        <SelectItem value="payment_admin">{t('corporate.settings.paymentAdminDesc')}</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>
                        <div className="flex gap-3 mt-6">
                            <Button variant="outline" className="flex-1" onClick={() => setShowInviteModal(false)}>
                                {t('corporate.settings.cancel')}
                            </Button>
                            <Button className="flex-1 gap-2" onClick={handleInvite}>
                                <Mail className="h-4 w-4" />
                                {t('corporate.settings.sendInvite')}
                            </Button>
                        </div>
                    </div>
                </div>
            )}

            {/* Password Change Modal */}
            {showPasswordModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50" onClick={() => setShowPasswordModal(false)} />
                    <div className="relative bg-white rounded-xl shadow-xl max-w-md w-full p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="font-semibold text-lg flex items-center gap-2">
                                <Key className="h-5 w-5 text-blue-600" />
                                {t('corporate.settings.changePassword')}
                            </h3>
                            <Button variant="ghost" size="icon" onClick={() => setShowPasswordModal(false)}>
                                <X className="h-4 w-4" />
                            </Button>
                        </div>
                        <div className="space-y-4">
                            <div>
                                <Label>{t('corporate.settings.currentPassword')}</Label>
                                <div className="relative mt-1">
                                    <Input
                                        type={showPassword ? 'text' : 'password'}
                                        value={currentPassword}
                                        onChange={(e) => setCurrentPassword(e.target.value)}
                                    />
                                    <button
                                        type="button"
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400"
                                        onClick={() => setShowPassword(!showPassword)}
                                    >
                                        {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <Label>{t('corporate.settings.newPassword')}</Label>
                                <Input
                                    type={showPassword ? 'text' : 'password'}
                                    value={newPassword}
                                    onChange={(e) => setNewPassword(e.target.value)}
                                    className="mt-1"
                                />
                                <p className="text-xs text-gray-500 mt-1">{t('corporate.settings.minChars')}</p>
                            </div>
                            <div>
                                <Label>{t('corporate.settings.confirmPassword')}</Label>
                                <Input
                                    type={showPassword ? 'text' : 'password'}
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                        </div>
                        <div className="flex gap-3 mt-6">
                            <Button variant="outline" className="flex-1" onClick={() => setShowPasswordModal(false)}>
                                {t('corporate.settings.cancel')}
                            </Button>
                            <Button className="flex-1" onClick={handlePasswordChange}>
                                {t('corporate.settings.changePasswordBtn')}
                            </Button>
                        </div>
                    </div>
                </div>
            )}

            {/* 2FA Setup Modal */}
            {show2FAModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50" onClick={() => setShow2FAModal(false)} />
                    <div className="relative bg-white rounded-xl shadow-xl max-w-md w-full p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="font-semibold text-lg flex items-center gap-2">
                                <Smartphone className="h-5 w-5 text-blue-600" />
                                {t('corporate.settings.twoFASetup')}
                            </h3>
                            <Button variant="ghost" size="icon" onClick={() => setShow2FAModal(false)}>
                                <X className="h-4 w-4" />
                            </Button>
                        </div>
                        <div className="text-center mb-6">
                            <div className="w-48 h-48 bg-gray-100 rounded-xl mx-auto mb-4 flex items-center justify-center">
                                <div className="text-center">
                                    <Smartphone className="h-12 w-12 text-gray-400 mx-auto mb-2" />
                                    <p className="text-xs text-gray-500">{t('corporate.settings.qrCode')}</p>
                                </div>
                            </div>
                            <p className="text-sm text-gray-600 mb-4">
                                {t('corporate.settings.scanQR')}
                            </p>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-4 mb-4">
                            <Label className="text-xs text-gray-500">{t('corporate.settings.secretKey')}</Label>
                            <div className="flex items-center gap-2 mt-1">
                                <code className="flex-1 bg-white px-3 py-2 rounded border text-sm font-mono">
                                    JBSWY3DPEHPK3PXP
                                </code>
                                <Button variant="outline" size="icon" onClick={copySecretKey}>
                                    {qrCodeCopied ? <Check className="h-4 w-4 text-green-600" /> : <Copy className="h-4 w-4" />}
                                </Button>
                            </div>
                        </div>
                        <div className="flex gap-3">
                            <Button variant="outline" className="flex-1" onClick={() => setShow2FAModal(false)}>
                                {t('corporate.settings.cancel')}
                            </Button>
                            <Button className="flex-1" onClick={handle2FAEnable}>
                                {t('corporate.settings.enable')}
                            </Button>
                        </div>
                    </div>
                </div>
            )}

            {/* ═══════ Upgrade Plan Modal ═══════ */}
            {showUpgradeModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setShowUpgradeModal(false)} />
                    <div className="relative bg-white rounded-2xl shadow-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto">
                        {/* Modal Header */}
                        <div className="sticky top-0 bg-white border-b border-gray-100 px-6 py-4 flex items-center justify-between z-10 rounded-t-2xl">
                            <div>
                                <h3 className="font-bold text-lg text-gray-900 flex items-center gap-2">
                                    <TrendingUp className="h-5 w-5 text-blue-600" />
                                    {t('app.page.plan_y_kselt')}</h3>
                                <p className="text-sm text-gray-500 mt-0.5">
                                    {t('app.page.mevcut_plan_n_z')}<span className="font-semibold">{currentTier.name}</span>
                                </p>
                            </div>
                            <Button variant="ghost" size="icon" onClick={() => setShowUpgradeModal(false)}>
                                <X className="h-5 w-5" />
                            </Button>
                        </div>

                        {/* Plan Comparison */}
                        <div className="p-6">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                {Object.entries(subscriptionTiers)
                                    .filter(([key]) => key !== 'pending')
                                    .map(([key, tier]) => {
                                        const { t } = useTranslation();
                                        const isCurrentPlan = key === currentTierKey;
                                        const isUpgrade = ['starter', 'growth', 'enterprise'].indexOf(key) > ['starter', 'growth', 'enterprise'].indexOf(currentTierKey);
                                        const PlanIcon = tier.icon;
                                        return (
                                            <div
                                                key={key}
                                                className={`relative rounded-xl border-2 p-5 transition-all ${
                                                    isCurrentPlan
                                                        ? `${tier.ringColor} ring-2 border-transparent bg-gray-50`
                                                        : isUpgrade
                                                        ? 'border-gray-200 hover:border-blue-300 hover:shadow-md cursor-pointer'
                                                        : 'border-gray-100 opacity-60'
                                                }`}
                                            >
                                                {isCurrentPlan && (
                                                    <div className="absolute -top-2.5 left-1/2 -translate-x-1/2 px-3 py-0.5 bg-blue-600 text-white text-xs font-semibold rounded-full">
                                                        {t('app.page.mevcut_plan')}</div>
                                                )}
                                                {key === 'growth' && !isCurrentPlan && (
                                                    <div className="absolute -top-2.5 left-1/2 -translate-x-1/2 px-3 py-0.5 bg-emerald-500 text-white text-xs font-semibold rounded-full">
                                                        {t('app.page.pop_ler')}</div>
                                                )}
                                                <div className="text-center mb-4">
                                                    <div className={`w-12 h-12 mx-auto rounded-xl bg-gradient-to-br ${tier.color} flex items-center justify-center mb-3`}>
                                                        <PlanIcon className="h-6 w-6 text-white" />
                                                    </div>
                                                    <h4 className="font-bold text-gray-900">{tier.name}</h4>
                                                    <div className="mt-2">
                                                        <span className="text-3xl font-bold text-gray-900">{formatAmount(tier.price)}</span>
                                                        <span className="text-gray-500 text-sm">/ay</span>
                                                    </div>
                                                </div>

                                                <ul className="space-y-2 mb-5">
                                                    {tier.features.slice(0, 6).map((feature, i) => (
                                                        <li key={i} className="flex items-start gap-2 text-xs text-gray-600">
                                                            <Check className={`h-3.5 w-3.5 flex-shrink-0 mt-0.5 ${tier.accentColor}`} />
                                                            <span>{feature}</span>
                                                        </li>
                                                    ))}
                                                    {tier.features.length > 6 && (
                                                        <li className="text-xs text-gray-400 pl-5">
                                                            +{tier.features.length - 6} {t('app.page.daha_fazla_zellik')}</li>
                                                    )}
                                                </ul>

                                                {isCurrentPlan ? (
                                                    <Button disabled className="w-full" variant="outline">
                                                        {t('app.page.mevcut_plan_n_z')}</Button>
                                                ) : isUpgrade ? (
                                                    <Button
                                                        className={`w-full gap-2 bg-gradient-to-r ${tier.color} text-white hover:opacity-90`}
                                                        onClick={() => {
                                                            alert(`${tier.name} planına yükseltme talebi gönderildi!`);
                                                            setShowUpgradeModal(false);
                                                        }}
                                                    >
                                                        <ArrowUpRight className="h-4 w-4" />
                                                        {t('app.page.y_kselt')}</Button>
                                                ) : (
                                                    <Button disabled className="w-full" variant="outline">
                                                        {t('app.page.d_rme')}</Button>
                                                )}
                                            </div>
                                        );
                                    })}
                            </div>

                            {/* Upgrade Info */}
                            <div className="mt-6 bg-blue-50 border border-blue-100 rounded-xl p-4 flex items-start gap-3">
                                <Shield className="h-5 w-5 text-blue-600 flex-shrink-0 mt-0.5" />
                                <div className="text-sm text-blue-800">
                                    <p className="font-medium mb-1">{t('app.page.y_kseltme_bilgileri')}</p>
                                    <ul className="list-disc list-inside space-y-1 text-blue-700 text-xs">
                                        <li>{t('app.page.plan_y_kseltmeleri_an_nda_devr')}</li>
                                        <li>{t('app.page.mevcut_d_nem_i_in_kalan_s_re_o')}</li>
                                        <li>{t('app.page.t_m_verileriniz_ve_ayarlar_n_z')}</li>
                                        <li>{t('app.page.30_g_n_i_inde_eski_plana_geri_')}</li>
                                    </ul>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* ═══════ Cancel Subscription Modal ═══════ */}
            {showCancelModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setShowCancelModal(false)} />
                    <div className="relative bg-white rounded-2xl shadow-2xl max-w-md w-full p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="font-bold text-lg text-gray-900 flex items-center gap-2">
                                <AlertTriangle className="h-5 w-5 text-red-500" />
                                {t('app.page.aboneli_i_ptal_et')}</h3>
                            <Button variant="ghost" size="icon" onClick={() => setShowCancelModal(false)}>
                                <X className="h-5 w-5" />
                            </Button>
                        </div>

                        <div className="bg-red-50 border border-red-100 rounded-xl p-4 mb-4">
                            <p className="text-sm text-red-800 font-medium mb-2">
                                {t('app.page.dikkat_aboneli_inizi_iptal_ede')}</p>
                            <ul className="text-xs text-red-700 space-y-1.5 list-disc list-inside">
                                <li>{t('app.page.mevcut_fatura_d_neminizin_sonu')}</li>
                                <li>{t('app.page.t_m_kampanyalar_n_z_ve_raporla')}</li>
                                <li>{t('app.page.ekip_yelerinizin_eri_imi_kald_')}</li>
                                <li>{t('app.page.verileriniz_30_g_n_boyunca_sak')}</li>
                            </ul>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <Label className="text-sm text-gray-700">{t('app.page.ptal_nedeniniz_nedir')}</Label>
                                <Select value={cancelReason} onValueChange={setCancelReason}>
                                    <SelectTrigger className="mt-1">
                                        <SelectValue placeholder={t('app.page.l_tfen_bir_neden_se_in')} />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="too_expensive">{t('app.page.ok_pahal')}</SelectItem>
                                        <SelectItem value="not_using">{t('app.page.yeterince_kullanm_yoruz')}</SelectItem>
                                        <SelectItem value="missing_features">{t('app.page.stedi_imiz_zellikler_eksik')}</SelectItem>
                                        <SelectItem value="switching">{t('app.page.ba_ka_bir_platform_tercih_ediy')}</SelectItem>
                                        <SelectItem value="temporary">{t('app.page.ge_ici_olarak_duraklatmak_isti')}</SelectItem>
                                        <SelectItem value="other">{t('app.page.di_er')}</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div>
                                <Label className="text-sm text-gray-700">
                                    {t('app.page.onaylamak_i_in')}<span className="font-mono font-bold text-red-600">{t('app.page.quot_ptal_et_quot')}</span> {t('app.page.yaz_n')}</Label>
                                <Input
                                    value={cancelConfirmText}
                                    onChange={(e) => setCancelConfirmText(e.target.value)}
                                    placeholder={t('app.page.ptal_et')}
                                    className="mt-1 border-red-200 focus:border-red-400 focus:ring-red-200"
                                />
                            </div>
                        </div>

                        <div className="flex gap-3 mt-6">
                            <Button
                                variant="outline"
                                className="flex-1"
                                onClick={() => {
                                    setShowCancelModal(false);
                                    setCancelReason('');
                                    setCancelConfirmText('');
                                }}
                            >
                                {t('app.page.vazge')}</Button>
                            <Button
                                className="flex-1 bg-red-600 hover:bg-red-700 text-white"
                                disabled={cancelConfirmText !== 'İPTAL ET' || !cancelReason}
                                onClick={() => {
                                    alert('Abonelik iptal talebi gönderildi. Dönem sonuna kadar erişiminiz devam edecektir.');
                                    setShowCancelModal(false);
                                    setCancelReason('');
                                    setCancelConfirmText('');
                                }}
                            >
                                {t('app.page.aboneli_i_ptal_et')}</Button>
                        </div>

                        {cancelReason === 'too_expensive' && (
                            <div className="mt-4 bg-blue-50 border border-blue-100 rounded-xl p-4">
                                <p className="text-sm text-blue-800 font-medium flex items-center gap-2">
                                    <Sparkles className="h-4 w-4" />
                                    {t('app.page.zel_teklif')}</p>
                                <p className="text-xs text-blue-700 mt-1">
                                    {t('app.page.sizi_kaybetmek_istemeyiz_sonra')}</p>
                                <Button
                                    size="sm"
                                    className="mt-3 bg-blue-600 hover:bg-blue-700 text-white gap-1"
                                    onClick={() => {
                                        alert('%30 indirim uygulandı! Sonraki 3 ay indirimli fiyattan devam edeceksiniz.');
                                        setShowCancelModal(false);
                                        setCancelReason('');
                                        setCancelConfirmText('');
                                    }}
                                >
                                    <Check className="h-3 w-3" />
                                    {t('app.page.ndirimi_kabul_et')}</Button>
                            </div>
                        )}

                        {cancelReason === 'temporary' && (
                            <div className="mt-4 bg-amber-50 border border-amber-100 rounded-xl p-4">
                                <p className="text-sm text-amber-800 font-medium flex items-center gap-2">
                                    <Clock className="h-4 w-4" />
                                    {t('app.page.aboneli_i_duraklat_n')}</p>
                                <p className="text-xs text-amber-700 mt-1">
                                    {t('app.page.ptal_yerine_aboneli_inizi_3_ay')}</p>
                                <Button
                                    size="sm"
                                    className="mt-3 bg-amber-600 hover:bg-amber-700 text-white gap-1"
                                    onClick={() => {
                                        alert('Abonelik 3 ay süreyle duraklatıldı.');
                                        setShowCancelModal(false);
                                        setCancelReason('');
                                        setCancelConfirmText('');
                                    }}
                                >
                                    <Clock className="h-3 w-3" />
                                    {t('app.page.duraklat')}</Button>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { Search, Filter, GraduationCap, ChevronRight } from 'lucide-react';
import CorporateHeader from '@/components/corporate/Header';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { mockStudents } from '@/lib/corporate/mock-data';
import { Progress } from '@/components/ui/progress';
import { useTranslation } from '@/lib/i18n/context';

export default function StudentsPage() {
    const { t } = useTranslation();
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [facultyFilter, setFacultyFilter] = useState('all');

    const filteredStudents = mockStudents.filter((student) => {
        const matchesSearch =
            student.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            student.university.toLowerCase().includes(searchQuery.toLowerCase()) ||
            student.department.toLowerCase().includes(searchQuery.toLowerCase());

        const matchesStatus =
            statusFilter === 'all' || student.status === statusFilter;

        const matchesFaculty =
            facultyFilter === 'all' || student.faculty === facultyFilter;

        return matchesSearch && matchesStatus && matchesFaculty;
    });

    const formatCurrency = (value: number) => {
        return new Intl.NumberFormat('tr-TR', {
            style: 'currency',
            currency: 'USD',
            minimumFractionDigits: 0,
        }).format(value);
    };

    const getStatusBadge = (status: string) => {
        const { t } = useTranslation();
        switch (status) {
            case 'active':
                return <Badge className="bg-green-100 text-green-700 hover:bg-green-100">{t('corporate.students.active')}</Badge>;
            case 'graduated':
                return <Badge className="bg-blue-100 text-blue-700 hover:bg-blue-100">{t('corporate.students.graduated')}</Badge>;
            case 'dropped':
                return <Badge className="bg-red-100 text-red-700 hover:bg-red-100">{t('corporate.students.dropped')}</Badge>;
            default:
                return null;
        }
    };

    const faculties = [...new Set(mockStudents.map((s) => s.faculty))];

    return (
        <div className="min-h-screen">
            <CorporateHeader
                title={t('corporate.students.title')}
                subtitle={t('corporate.students.subtitle')}
            />

            <div className="p-6">
                {/* Filters */}
                <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 mb-6">
                    <div className="flex flex-col md:flex-row gap-4">
                        <div className="relative flex-1">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
                            <Input
                                type="search"
                                placeholder={t('corporate.students.searchPlaceholder')}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="pl-10"
                            />
                        </div>
                        <Select value={statusFilter} onValueChange={setStatusFilter}>
                            <SelectTrigger className="w-full md:w-40">
                                <SelectValue placeholder={t('corporate.students.status')} />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">{t('corporate.students.allStatuses')}</SelectItem>
                                <SelectItem value="active">{t('corporate.students.active')}</SelectItem>
                                <SelectItem value="graduated">{t('corporate.students.graduated')}</SelectItem>
                                <SelectItem value="dropped">{t('corporate.students.dropped')}</SelectItem>
                            </SelectContent>
                        </Select>
                        <Select value={facultyFilter} onValueChange={setFacultyFilter}>
                            <SelectTrigger className="w-full md:w-48">
                                <SelectValue placeholder={t('corporate.students.faculty')} />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">{t('corporate.students.allFaculties')}</SelectItem>
                                {faculties.map((faculty) => (
                                    <SelectItem key={faculty} value={faculty}>
                                        {faculty}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                </div>

                {/* Students Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredStudents.map((student) => (
                        <Link
                            key={student.id}
                            href={`/corporate/students/${student.id}`}
                            className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow group"
                        >
                            <div className="flex items-start gap-4">
                                <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center flex-shrink-0">
                                    <GraduationCap className="h-8 w-8 text-blue-600" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2">
                                        <h3 className="font-semibold text-gray-900 truncate">
                                            {student.name}
                                        </h3>
                                        {getStatusBadge(student.status)}
                                    </div>
                                    <p className="text-sm text-gray-500 truncate mt-1">
                                        {student.university}
                                    </p>
                                    <p className="text-sm text-gray-400 truncate">
                                        {student.department}
                                    </p>
                                </div>
                                <ChevronRight className="h-5 w-5 text-gray-300 group-hover:text-blue-600 transition-colors" />
                            </div>

                            <div className="mt-4">
                                <div className="flex justify-between text-sm mb-2">
                                    <span className="text-gray-500">{t('corporate.students.progress')}</span>
                                    <span className="font-medium text-gray-900">
                                        {Math.round((student.total_donated / student.goal_amount) * 100)}%
                                    </span>
                                </div>
                                <Progress
                                    value={(student.total_donated / student.goal_amount) * 100}
                                    className="h-2"
                                />
                                <div className="flex justify-between text-sm mt-2 text-gray-500">
                                    <span>{formatCurrency(student.total_donated)}</span>
                                    <span>{formatCurrency(student.goal_amount)}</span>
                                </div>
                            </div>

                            <div className="mt-4 pt-4 border-t border-gray-100 flex items-center justify-between">
                                <div className="flex items-center gap-2 text-sm text-gray-500">
                                    <span>{t('corporate.students.target')}: {student.target_year}</span>
                                </div>
                                <div className="flex items-center gap-2 text-sm text-gray-500">
                                    <span>{student.country}</span>
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>

                {filteredStudents.length === 0 && (
                    <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
                        <GraduationCap className="h-12 w-12 text-gray-300 mx-auto mb-4" />
                        <h3 className="text-lg font-medium text-gray-900 mb-2">
                            {t('corporate.students.notFound')}
                        </h3>
                        <p className="text-gray-500">
                            {t('corporate.students.notFoundDesc')}
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useRouter, useSearchParams } from 'next/navigation';
import { Suspense } from 'react';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

import { validateAmount, sanitizeInput, validateEmail } from '@/lib/validation';
import { toast } from 'sonner';
import { useCurrency } from '@/lib/currency-context';
import { getCampaign } from '@/lib/api';
import { censorSurname } from '@/lib/privacy';
import {
  Heart,
  Shield,
  Lock,
  User,
  Mail,
  DollarSign,
  ArrowRight,
  CheckCircle,
  Sparkles,
  GraduationCap,
  Globe,
  TrendingUp,
  Gift,
  Clock,
  Loader2,
  ArrowLeft,
} from 'lucide-react';
function DonatePageContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { t } = useTranslation();
  const { currencySymbol, presetAmounts, formatAmount, toUSD, currency } = useCurrency();
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [selectedQuickAmount, setSelectedQuickAmount] = useState<number | null>(null);
  const [interval, setInterval] = useState<'one-time' | 'month' | 'week'>('one-time');
  const [formData, setFormData] = useState({
    amount: '',
    target: 'Support a verified student' as 'Support a verified student' | 'General education fund' | 'Monthly student scholarship',
    donorName: '',
    donorEmail: '',
  });

  // Campaign-specific state
  const [campaignData, setCampaignData] = useState<any>(null);
  const [campaignLoading, setCampaignLoading] = useState(false);
  const campaignId = searchParams.get('campaign_id');

  // Platform tip state
  const [platformTipPercent, setPlatformTipPercent] = useState(2);
  const [customTip, setCustomTip] = useState('');
  const [useCustomTip, setUseCustomTip] = useState(false);

  // Computed tip values
  const donationAmount = parseFloat(formData.amount) || 0;
  const effectiveTipPercent = useCustomTip
    ? Math.max(2, parseFloat(customTip) || 2)
    : Math.max(2, platformTipPercent);
  const tipAmount = parseFloat(((donationAmount * effectiveTipPercent) / 100).toFixed(2));
  const totalCharge = parseFloat((donationAmount + tipAmount).toFixed(2));

  // Read URL params
  useEffect(() => {
    const amountParam = searchParams.get('amount');
    const campaignParam = searchParams.get('campaign');
    if (amountParam) {
      setFormData(prev => ({ ...prev, amount: amountParam }));
      const num = parseInt(amountParam);
      if ([10, 25, 50, 100, 250, 500].includes(num)) {
        setSelectedQuickAmount(num);
      }
    }
    if (campaignParam === 'education-equality') {
      setFormData(prev => ({ ...prev, target: 'General education fund' }));
    }
  }, [searchParams]);

  // Fetch campaign data if campaign_id is provided
  useEffect(() => {
    if (!campaignId) return;
    const loadCampaign = async () => {
      setCampaignLoading(true);
      try {
        const response = await getCampaign(campaignId);
        if (response.success) {
          setCampaignData(response.data);
        }
      } catch {
        // Campaign not found, continue with general donation
      } finally {
        setCampaignLoading(false);
      }
    };
    loadCampaign();
  }, [campaignId]);

  const handleQuickAmount = (amount: number) => {
    setSelectedQuickAmount(amount);
    setFormData({ ...formData, amount: amount.toString() });
    if (errors.amount) setErrors({ ...errors, amount: '' });
  };

  const handleSubmit = async (e: React.FormEvent) => {
      const { t } = useTranslation();
    e.preventDefault();

    if (loading || submitted) {
      return;
    }

    const newErrors: Record<string, string> = {};
    const amount = parseFloat(formData.amount);
    const amountValidation = validateAmount(amount, currency);

    if (!amountValidation.valid) {
      newErrors.amount = amountValidation.error || t('common.error');
    }

    if (effectiveTipPercent < 2) {
      newErrors.amount = 'Platform desteği en az %2 olmalıdır.';
    }

    if (formData.donorEmail && !validateEmail(formData.donorEmail)) {
      newErrors.donorEmail = t('donation.invalidEmail');
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      toast.error(t('common.error'));
      return;
    }

    setLoading(true);
    setSubmitted(true);

    try {
      // Calculate tip in USD
      const tipAmountUSD = currency === 'TRY' ? toUSD(tipAmount) : tipAmount;
      const totalChargeUSD = currency === 'TRY' ? toUSD(totalCharge) : totalCharge;

      // Use real API endpoint for donation
      const res = await fetch('/api/donations/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          campaign_id: campaignId || searchParams.get('campaign') || 'general',
          amount: Math.round(totalChargeUSD * 100) / 100,
          donor_name: formData.donorName ? sanitizeInput(formData.donorName) : 'Anonymous',
          donor_email: formData.donorEmail ? formData.donorEmail.trim().toLowerCase() : undefined,
          anonymous: !formData.donorName,
          interval: interval !== 'one-time' ? interval : undefined,
          platform_tip_percent: effectiveTipPercent,
          platform_tip_amount: Math.round(tipAmountUSD * 100) / 100,
        }),
      });

      const data = await res.json();

      if (data.success && data.data?.url) {
        toast.success(t('donation.success'));
        window.location.href = data.data.url;
      } else {
        // Fallback: if iyzico is not configured, redirect to donor dashboard
        toast.success(t('donation.success'));
        setTimeout(() => {
          router.push('/donor/dashboard');
        }, 500);
      }
    } catch (error) {
      console.error('Failed to process donation:', error);
      toast.error(t('donation.error'));
      setSubmitted(false);
    } finally {
      setLoading(false);
    }
  };

  const quickAmounts = presetAmounts;

  return (
    <div className="min-h-screen flex flex-col bg-gradient-to-b from-slate-50 to-white">
      <Navbar />
      <main className="flex-grow">

        {/* Hero Banner */}
        <section className="relative bg-gradient-to-br from-blue-600 via-indigo-600 to-purple-700 overflow-hidden">
          {/* Decorative elements */}
          <div className="absolute inset-0 pointer-events-none">
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-white/5 rounded-full -translate-y-1/2 translate-x-1/4" />
            <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-white/5 rounded-full translate-y-1/2 -translate-x-1/4" />
            <div className="absolute inset-0 opacity-10" style={{
              backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)',
              backgroundSize: '32px 32px',
            }} />
          </div>

          <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 sm:py-20">
            <div className="text-center max-w-3xl mx-auto">
              <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md border border-white/20 rounded-full px-5 py-2 mb-6">
                <Heart className="h-4 w-4 text-pink-300" />
                <span className="text-sm text-white/90 font-medium">{t('donation.heroBadge')}</span>
              </div>
              <h1 className="text-4xl sm:text-5xl font-bold text-white mb-4 leading-tight">
                {t('donation.title')}
              </h1>
              <p className="text-lg text-blue-100/80 leading-relaxed max-w-xl mx-auto">
                {t('donation.heroSubtitle')}
              </p>
            </div>
          </div>

          {/* Wave separator */}
          <div className="absolute bottom-0 left-0 right-0">
            <svg viewBox="0 0 1440 80" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-full">
              <path d="M0 80L60 74.7C120 69 240 59 360 53.3C480 48 600 48 720 53.3C840 59 960 69 1080 69.3C1200 69 1320 59 1380 53.3L1440 48V80H1380C1320 80 1200 80 1080 80C960 80 840 80 720 80C600 80 480 80 360 80C240 80 120 80 60 80H0Z" fill="#f8fafc" />
            </svg>
          </div>
        </section>

        {/* Main Content */}
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 -mt-4 pb-20">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">

            {/* ─── LEFT: Donation Form ─── */}
            <div className="lg:col-span-3">

              {/* Campaign Info Card - shown when campaign_id is provided */}
              {campaignLoading && (
                <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 mb-6 flex items-center justify-center">
                  <Loader2 className="h-6 w-6 animate-spin text-blue-600" />
                </div>
              )}
              {campaignData && (
                <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 mb-6">
                  <Button variant="ghost" size="sm" onClick={() => router.push(`/campaign/${campaignId}`)} className="mb-4 -ml-2 gap-2">
                    <ArrowLeft className="h-4 w-4" /> {t('app.page.kampanyaya_d_n')}</Button>
                  <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xl shrink-0">
                      {censorSurname(campaignData.student?.name || campaignData.studentName || 'Öğrenci').charAt(0)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <h2 className="text-lg font-bold text-gray-900 truncate">{campaignData.title}</h2>
                      <p className="text-sm text-gray-500">
                        {censorSurname(campaignData.student?.name || campaignData.studentName || 'Öğrenci')}
                        {(campaignData.country || campaignData.student?.country) && ` · ${campaignData.country || campaignData.student?.country}`}
                      </p>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="text-lg font-bold text-gray-900">{formatAmount(campaignData.raised_amount || 0)}</p>
                      <p className="text-xs text-gray-500">/ {formatAmount(campaignData.goal_amount || 0)} hedef</p>
                    </div>
                  </div>
                  {/* Mini progress */}
                  <div className="mt-4 h-2 bg-gray-100 rounded-full overflow-hidden">
                    <div
                      className="h-full bg-blue-600 rounded-full transition-all"
                      style={{ width: `${Math.min((campaignData.raised_amount / (campaignData.goal_amount || 1)) * 100, 100)}%` }}
                    />
                  </div>
                </div>
              )}

              <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">

                {/* Quick Amount Selection */}
                <div className="p-6 sm:p-8 border-b border-slate-100">
                  <div className="flex items-center gap-3 mb-5">
                    <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/20">
                      <DollarSign className="h-5 w-5 text-white" />
                    </div>
                    <div>
                      <h2 className="text-lg font-bold text-slate-900">{t('donation.amount')}</h2>
                      <p className="text-sm text-slate-400">{t('donation.amountSubtitle')}</p>
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2.5 mb-5">
                    {quickAmounts.map((amount) => (
                      <button
                        key={amount}
                        type="button"
                        onClick={() => handleQuickAmount(amount)}
                        className={`flex-1 min-w-[75px] sm:min-w-[85px] relative py-3.5 px-1 rounded-xl font-bold text-sm sm:text-base transition-all duration-200 border-2 ${selectedQuickAmount === amount
                          ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-500/30 scale-[1.02]'
                          : 'bg-slate-50 text-slate-700 border-slate-100 hover:border-blue-300 hover:bg-blue-50'
                          }`}
                      >
                        {currencySymbol}{amount.toLocaleString()}
                      </button>
                    ))}
                  </div>

                  <div className="relative">
                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-semibold text-lg">{currencySymbol}</span>
                    <Input
                      id="amount"
                      type="number"
                      step="0.01"
                      min="1"
                      max="1000000"
                      required
                      value={formData.amount}
                      onChange={(e) => {
                        setFormData({ ...formData, amount: e.target.value });
                        setSelectedQuickAmount(null);
                        if (errors.amount) setErrors({ ...errors, amount: '' });
                      }}
                      placeholder={t('donation.customPlaceholder')}
                      className={`pl-9 h-14 text-lg font-medium rounded-xl border-2 bg-slate-50 focus:bg-white transition-colors ${errors.amount ? 'border-red-400 focus:border-red-500' : 'border-slate-100 focus:border-blue-500'
                        }`}
                    />
                  </div>
                  {errors.amount && (
                    <p className="text-sm text-red-500 mt-2 flex items-center gap-1.5">
                      <span className="w-1 h-1 bg-red-500 rounded-full" />
                      {errors.amount}
                    </p>
                  )}
                </div>

                {/* Form Fields */}
                <form onSubmit={handleSubmit}>
                  <div className="p-6 sm:p-8 space-y-6">

                    {/* Category - hidden when donating to a specific campaign */}
                    {!campaignData && (
                      <div className="space-y-2">
