import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import MobileHeader from '@/components/MobileHeader';
import {
    MentorCard,
    MentorDetailSheet,
    BookingModal,
    MentorApplicationModal,
    mockMentors,
    type MentorProfile,
} from '@/components/MentorConnect';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';
import { useTranslation } from "@/lib/i18n/context";

const categories = [
    { label: '🔵 Yazılım', value: 'Yazılım' },
    { label: '🟢 Finans', value: 'Finans' },
    { label: '🟣 Pazarlama', value: 'Pazarlama' },
    { label: '🟡 Ürün Yönetimi', value: 'Ürün Yönetimi' },
    { label: '🔴 Kariyer Koçluğu', value: 'Kariyer Koçluğu' },
];

const sectors = ['Tümü', 'Yazılım', 'Finans', 'Pazarlama', 'Ürün Yönetimi', 'Kariyer Koçluğu'];
const experienceLevels = ['Tümü', '1-5 yıl', '6-10 yıl', '10+ yıl'];
const ratingOptions = ['Tümü', '4.0+', '4.5+', '4.8+'];

const testimonials = [
    { id: 't1', name: 'Emre Koç', before: 'Jr. Developer', after: 'Sr. Developer @ Google', quote: 'Ali Bey\'in mentorluk desteği olmasa bu kadar hızlı ilerleyemezdim. Sistem tasarımı ve mülakat stratejileri konusunda inanılmaz rehberlik aldım.', mentor: 'Ali Yılmaz', photo: null },
    { id: 't2', name: 'Selin Tekin', before: 'Stajyer', after: 'Investment Analyst @ Goldman Sachs', quote: 'Zeynep Hanım ile çalışmak kariyerimde dönüm noktası oldu. Finans dünyasının kapıları mentorluk sayesinde aralandı.', mentor: 'Zeynep Kara', photo: null },
    { id: 't3', name: 'Burak Arslan', before: 'Yazılım Mühendisi', after: 'Product Manager @ Spotify', quote: 'Sektör geçişi yapabilmek cesaret istiyordu. Doğru mentorun rehberliğinde bu geçişi başarıyla tamamladım.', mentor: 'Mehmet Demir', photo: null },
];

const howItWorks = [
    { icon: Search, title: 'Mentor Keşfet', desc: 'Uzmanlık alanına göre filtrele ve incele', color: 'from-blue-500 to-blue-600' },
    { icon: Target, title: 'Başvurunu Yap', desc: 'Hedeflerini belirt ve randevu talep et', color: 'from-emerald-500 to-emerald-600' },
    { icon: Handshake, title: 'Eşleş ve Görüş', desc: 'Onaylanan tarihte görüntülü görüşme yap', color: 'from-blue-500 to-emerald-500' },
    { icon: Rocket, title: 'Gelişimi Takip Et', desc: 'Aksiyonları uygula ve geri bildirim al', color: 'from-purple-500 to-blue-500' },
];

export default function MentorsPage() {
    const { t } = useTranslation();
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedSector, setSelectedSector] = useState('Tümü');
    const [selectedExp, setSelectedExp] = useState('Tümü');
    const [selectedRating, setSelectedRating] = useState('Tümü');
    const [availableOnly, setAvailableOnly] = useState(false);
    const [showCount, setShowCount] = useState(6);

    const [detailMentor, setDetailMentor] = useState<MentorProfile | null>(null);
    const [bookingMentor, setBookingMentor] = useState<MentorProfile | null>(null);
    const [showApplyModal, setShowApplyModal] = useState(false);
    const [showMobileFilters, setShowMobileFilters] = useState(false);

    const filteredMentors = useMemo(() => {
        const { t } = useTranslation();
        return mockMentors.filter(m => {
            const { t } = useTranslation();
            if (searchQuery) {
                const q = searchQuery.toLowerCase();
                if (!m.name.toLowerCase().includes(q) && !m.company.toLowerCase().includes(q) && !m.skills.some(s => s.toLowerCase().includes(q))) return false;
            }
            if (selectedSector !== 'Tümü' && m.sector !== selectedSector) return false;
            if (selectedExp !== 'Tümü') {
                if (selectedExp === '1-5 yıl' && m.experienceYears > 5) return false;
                if (selectedExp === '6-10 yıl' && (m.experienceYears < 6 || m.experienceYears > 10)) return false;
                if (selectedExp === '10+ yıl' && m.experienceYears < 10) return false;
            }
            if (selectedRating !== 'Tümü') {
                const minRating = parseFloat(selectedRating);
                if (m.rating < minRating) return false;
            }
            if (availableOnly && m.availability !== 'available') return false;
            return true;
        });
    }, [searchQuery, selectedSector, selectedExp, selectedRating, availableOnly]);

    const clearFilters = () => {
        setSearchQuery('');
        setSelectedSector('Tümü');
        setSelectedExp('Tümü');
        setSelectedRating('Tümü');
        setAvailableOnly(false);
    };

    const hasActiveFilters = searchQuery || selectedSector !== 'Tümü' || selectedExp !== 'Tümü' || selectedRating !== 'Tümü' || availableOnly;

    return (
        <div className="min-h-screen bg-slate-50">
            <MobileHeader transparent backHref="/" />

            {/* ─── HERO ─── */}
            <section className="relative overflow-hidden bg-gradient-to-br from-blue-600 via-blue-500 to-emerald-500 text-white -mt-14 pt-14">
                {/* Animated mesh pattern */}
                <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(circle at 25% 25%, white 1px, transparent 1px), radial-gradient(circle at 75% 75%, white 1px, transparent 1px)', backgroundSize: '50px 50px' }} />
                <div className="absolute inset-0 bg-gradient-to-b from-transparent to-blue-600/20" />

                <div className="container mx-auto px-4 py-20 md:py-28 relative z-10">
                    <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6 }} className="text-center max-w-3xl mx-auto">
                        <Badge className="bg-white/20 text-white border-white/30 backdrop-blur-sm mb-6 text-sm px-4 py-1.5">
                            <Sparkles className="w-4 h-4 mr-1.5" /> {t('app.page.funded_mentor_program')}</Badge>
                        <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold mb-6 leading-tight">
                            {t('app.page.kariyerinizi_uzmanlarla')}<br />
                            <span className="text-emerald-300">{t('app.page.ekillendirin')}</span>
                        </h1>
                        <p className="text-lg md:text-xl text-blue-100 mb-10 max-w-2xl mx-auto">
                            {t('app.page.funded_mentor_program_ile_dene')}</p>
                        <div className="flex flex-col sm:flex-row gap-4 justify-center">
                            <Button size="lg" className="bg-white text-blue-600 hover:bg-blue-50 rounded-xl px-8 h-14 text-base font-semibold shadow-lg shadow-blue-900/20" onClick={() => document.getElementById('mentors-grid')?.scrollIntoView({ behavior: 'smooth' })}>
                                <Search className="w-5 h-5 mr-2" /> {t('app.page.mentor_bul')}</Button>
                            <Button size="lg" variant="outline" className="border-2 border-white/50 text-white hover:bg-white/10 rounded-xl px-8 h-14 text-base font-semibold backdrop-blur-sm bg-transparent" onClick={() => setShowApplyModal(true)}>
                                <Award className="w-5 h-5 mr-2" /> {t('app.page.mentor_ol')}</Button>
                        </div>
                    </motion.div>

                    {/* Stats */}
                    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6, delay: 0.3 }} className="flex flex-wrap justify-center gap-8 md:gap-16 mt-14 text-center">
                        {[
                            { icon: Users, num: '0', label: 'Aktif Mentor' },
                            { icon: Handshake, num: '0', label: 'Başarılı Eşleşme' },
                            { icon: Star, num: '-', label: 'Ortalama Puan' },
                        ].map((s, i) => (
                            <div key={i} className="flex items-center gap-3">
                                <div className="w-12 h-12 rounded-xl bg-white/15 backdrop-blur-sm flex items-center justify-center">
                                    <s.icon className="w-6 h-6" />
                                </div>
                                <div className="text-left">
                                    <p className="text-2xl font-bold">{s.num}</p>
                                    <p className="text-sm text-blue-200">{s.label}</p>
                                </div>
                            </div>
                        ))}
                    </motion.div>
                </div>
            </section>

            {/* ─── FILTER BAR ─── */}
            <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-slate-200/50 shadow-sm">
                <div className="container mx-auto px-4 py-4">
                    {/* Main row */}
                    <div className="flex items-center gap-3">
                        <div className="relative flex-1 max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <Input value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder={t('app.page.sim_irket_veya_uzmanl_k_ara')} className="pl-10 rounded-xl border-slate-200 h-10" />
                        </div>

                        {/* Desktop filters */}
                        <div className="hidden md:flex items-center gap-2">
                            <select value={selectedSector} onChange={e => setSelectedSector(e.target.value)} className="h-10 rounded-xl border border-slate-200 px-3 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer">
                                {sectors.map(s => <option key={s}>{s}</option>)}
                            </select>
                            <select value={selectedExp} onChange={e => setSelectedExp(e.target.value)} className="h-10 rounded-xl border border-slate-200 px-3 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer">
                                <option value="Tümü">{t('app.page.deneyim')}</option>
                                {experienceLevels.slice(1).map(l => <option key={l}>{l}</option>)}
                            </select>
                            <select value={selectedRating} onChange={e => setSelectedRating(e.target.value)} className="h-10 rounded-xl border border-slate-200 px-3 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer">
                                <option value="Tümü">{t('app.page.rating')}</option>
                                {ratingOptions.slice(1).map(r => <option key={r}>{r}</option>)}
                            </select>

                            {/* Availability toggle */}
                            <button onClick={() => setAvailableOnly(!availableOnly)} className={cn("flex items-center gap-2 h-10 px-4 rounded-xl border text-sm transition-all", availableOnly ? "bg-emerald-50 border-emerald-300 text-emerald-700" : "bg-white border-slate-200 text-slate-600 hover:border-emerald-300")}>
                                <span className={cn("w-3 h-3 rounded-full transition-colors", availableOnly ? "bg-emerald-500" : "bg-slate-300")} />
                                {t('app.page.m_sait')}</button>

                            {hasActiveFilters && (
                                <button onClick={clearFilters} className="text-sm text-slate-500 hover:text-blue-600 underline underline-offset-2">{t('app.page.temizle')}</button>
                            )}
                        </div>

                        {/* Mobile filter toggle */}
                        <Button variant="outline" size="sm" className="md:hidden rounded-xl" onClick={() => setShowMobileFilters(!showMobileFilters)}>
                            <Filter className="w-4 h-4" />
                        </Button>
                    </div>

                    {/* Mobile filters */}
                    <AnimatePresence>
                        {showMobileFilters && (
                            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="md:hidden overflow-hidden">
                                <div className="pt-3 flex flex-col gap-2">
                                    <select value={selectedSector} onChange={e => setSelectedSector(e.target.value)} className="h-10 rounded-xl border border-slate-200 px-3 text-sm bg-white">{sectors.map(s => <option key={s}>{s}</option>)}</select>
                                    <select value={selectedExp} onChange={e => setSelectedExp(e.target.value)} className="h-10 rounded-xl border border-slate-200 px-3 text-sm bg-white"><option value="Tümü">{t('app.page.deneyim')}</option>{experienceLevels.slice(1).map(l => <option key={l}>{l}</option>)}</select>
                                    <button onClick={() => setAvailableOnly(!availableOnly)} className={cn("flex items-center gap-2 h-10 px-4 rounded-xl border text-sm", availableOnly ? "bg-emerald-50 border-emerald-300 text-emerald-700" : "border-slate-200")}>
                                        <span className={cn("w-3 h-3 rounded-full", availableOnly ? "bg-emerald-500" : "bg-slate-300")} /> {t('app.page.sadece_m_sait')}</button>
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* Category pills */}
                    <div className="flex gap-2 mt-3 overflow-x-auto pb-1 scrollbar-hide">
                        {categories.map(c => (
                            <button key={c.value} onClick={() => setSelectedSector(selectedSector === c.value ? 'Tümü' : c.value)} className={cn("whitespace-nowrap px-4 py-1.5 rounded-full text-sm font-medium border transition-all flex-shrink-0", selectedSector === c.value ? "bg-blue-600 text-white border-blue-600" : "bg-white text-slate-600 border-slate-200 hover:border-blue-300")}>
                                {c.label}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* ─── MENTORS GRID ─── */}
            <section id="mentors-grid" className="container mx-auto px-4 py-10">
                <div className="flex items-center justify-between mb-6">
                    <p className="text-sm text-slate-500">{filteredMentors.length} {t('app.page.mentor_bulundu')}</p>
                </div>

                {filteredMentors.length === 0 ? (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-20">
                        <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Search className="w-8 h-8 text-slate-400" />
                        </div>
                        <h3 className="text-xl font-semibold text-slate-700 mb-2">{t('app.page.sonu_bulunamad')}</h3>
                        <p className="text-slate-500 mb-4">{t('app.page.farkl_filtreler_deneyebilir_ve')}</p>
                        <Button variant="outline" className="rounded-xl" onClick={clearFilters}>{t('app.page.filtreleri_temizle')}</Button>
                    </motion.div>
                ) : (
                    <>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            <AnimatePresence mode="popLayout">
                                {filteredMentors.slice(0, showCount).map(m => (
                                    <MentorCard key={m.id} mentor={m} onViewProfile={setDetailMentor} onBook={setBookingMentor} />
                                ))}
                            </AnimatePresence>
                        </div>
                        {filteredMentors.length > showCount && (
                            <div className="text-center mt-10">
                                <Button variant="outline" size="lg" className="rounded-xl px-8" onClick={() => setShowCount(s => s + 6)}>
                                    <ChevronDown className="w-4 h-4 mr-2" /> {t('app.page.daha_fazla_g_ster')}</Button>
                            </div>
                        )}
                    </>
                )}
            </section>

            {/* ─── HOW IT WORKS ─── */}
            <section className="container mx-auto px-4 py-16">
                <motion.div initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} className="text-center mb-12">
                    <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-3">{t('app.page.nas_l_al_r')}</h2>
                    <p className="text-slate-500 max-w-xl mx-auto">{t('app.page.d_rt_basit_ad_mda_mentorunuzla')}</p>
                </motion.div>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6 relative">
                    {/* Connecting line (desktop) */}
                    <div className="hidden md:block absolute top-12 left-[12.5%] right-[12.5%] h-0.5 bg-gradient-to-r from-blue-200 via-emerald-200 to-blue-200" />
                    {howItWorks.map((step, i) => (
                        <motion.div key={i} initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} transition={{ delay: i * 0.15 }} className="text-center relative">
                            <div className={cn("w-16 h-16 mx-auto mb-4 rounded-2xl bg-gradient-to-br flex items-center justify-center text-white shadow-lg relative z-10", step.color)}>
                                <step.icon className="w-7 h-7" />
                            </div>
                            <h3 className="font-bold text-slate-900 mb-1">{step.title}</h3>
                            <p className="text-sm text-slate-500">{step.desc}</p>
                        </motion.div>
                    ))}
                </div>
            </section>

            {/* ─── SUCCESS STORIES ─── */}
            <section className="bg-white py-16">
                <div className="container mx-auto px-4">
                    <motion.div initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} className="text-center mb-12">
                        <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-3">{t('app.page.mentorluk_ile_kariyer_de_i_tir')}</h2>
                        <p className="text-slate-500">{t('app.page.funded_mentorlar_ile_ba_ar_ya_')}</p>
                    </motion.div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        {testimonials.map((testm, i) => (
                            <motion.div key={testm.id} initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} transition={{ delay: i * 0.1 }} className="bg-gradient-to-br from-slate-50 to-white rounded-2xl p-6 border border-slate-100 shadow-sm">
                                {/* Before → After */}
                                <div className="flex items-center gap-2 mb-4">
                                    <Badge className="bg-slate-200 text-slate-600 text-xs">{testm.before}</Badge>
                                    <ChevronRight className="w-4 h-4 text-emerald-500" />
                                    <Badge className="bg-emerald-50 text-emerald-700 border-emerald-200 text-xs">{testm.after}</Badge>
                                </div>
                                {/* Quote */}
                                <div className="relative mb-4">
                                    <span className="text-5xl text-blue-100 font-serif absolute -top-2 -left-1">&ldquo;</span>
                                    <p className="text-sm text-slate-600 leading-relaxed pl-6">{testm.quote}</p>
                                </div>
                                {/* Author */}
                                <div className="flex items-center gap-3 pt-4 border-t border-slate-100">
                                    <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-sm">
                                        {testm.name.split(' ').map((n: string) => n[0]).join('')}
                                    </div>
                                    <div>
                                        <p className="font-medium text-sm text-slate-800">{testm.name}</p>
                                        <p className="text-xs text-slate-400">{t('app.page.te_ekk_r')}<span className="text-blue-600">{testm.mentor}</span></p>
                                    </div>
                                </div>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </section>

            {/* ─── CTA SECTION ─── */}
            <section className="container mx-auto px-4 py-16">
                <div className="bg-gradient-to-br from-blue-600 to-emerald-500 rounded-3xl p-10 md:p-16 text-center text-white relative overflow-hidden">
                    <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(circle, white 1px, transparent 1px)', backgroundSize: '30px 30px' }} />
                    <div className="relative z-10">
                        <h2 className="text-3xl md:text-4xl font-bold mb-4">{t('app.page.deneyimlerinizi_payla_mak_ster')}</h2>
                        <p className="text-blue-100 text-lg mb-8 max-w-2xl mx-auto">{t('app.page.mentor_olarak_toplulu_umuza_ka')}</p>
                        <Button size="lg" className="bg-white text-blue-600 hover:bg-blue-50 rounded-xl px-8 h-14 text-base font-semibold" onClick={() => setShowApplyModal(true)}>
                            <Award className="w-5 h-5 mr-2" /> {t('app.page.mentor_olarak_ba_vur')}</Button>
                    </div>
                </div>
            </section>

            {/* ─── Floating Help ─── */}
            <button className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 text-white rounded-full shadow-lg shadow-blue-600/30 flex items-center justify-center hover:bg-blue-700 transition-colors z-30" onClick={() => { /* chat */ }}>
                <HelpCircle className="w-6 h-6" />
            </button>

            {/* ─── Modals ─── */}
            <MentorDetailSheet mentor={detailMentor} open={!!detailMentor} onClose={() => setDetailMentor(null)} onBook={(m) => { setDetailMentor(null); setBookingMentor(m); }} />
            <BookingModal mentor={bookingMentor} open={!!bookingMentor} onClose={() => setBookingMentor(null)} />
            <MentorApplicationModal open={showApplyModal} onClose={() => setShowApplyModal(false)} />
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback, Suspense } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useSession } from 'next-auth/react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { useCurrency } from '@/lib/currency-context';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import {
  Heart,
  Users,
  Calendar,
  Search,
  Download,
  FileText,
  ChevronLeft,
  ChevronRight,
  Filter,
  X,
  TrendingUp,
  DollarSign,
  Eye,
  FileSpreadsheet,
  Receipt,
  Loader2,
  ArrowUpDown,
} from 'lucide-react';

interface Donation {
  donation_id: string;
  campaign_id: string;
  amount: number;
  currency: string;
  created_at: string;
  payment_status: string;
  donor_name: string;
  campaign: {
    campaign_id: string;
    title: string;
    category: string;
    status: string;
  } | null;
  student: {
    name: string;
    image: string | null;
    university: string;
    department: string;
  } | null;
}

interface Summary {
  totalAmount: number;
  totalDonations: number;
  supportedStudents: number;
  lastDonationDate: string | null;
}

interface Pagination {
  page: number;
  limit: number;
  total: number;
  totalPages: number;
}

function MyDonationsContent() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const searchParams = useSearchParams();
  const { t } = useTranslation();
  const { formatAmount } = useCurrency();

  const [donations, setDonations] = useState<Donation[]>([]);
  const [summary, setSummary] = useState<Summary>({ totalAmount: 0, totalDonations: 0, supportedStudents: 0, lastDonationDate: null });
  const [pagination, setPagination] = useState<Pagination>({ page: 1, limit: 20, total: 0, totalPages: 0 });
  const [loading, setLoading] = useState(true);
  const [exporting, setExporting] = useState(false);

  // Filters
  const [searchQuery, setSearchQuery] = useState('');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [amountMin, setAmountMin] = useState('');
  const [amountMax, setAmountMax] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  const currentPage = parseInt(searchParams.get('page') || '1');

  // Redirect to login if not authenticated
  useEffect(() => {
    if (status === 'unauthenticated') {
      router.replace('/login?callbackUrl=/my-donations');
    }
  }, [status, router]);

  const fetchDonations = useCallback(async (page: number) => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set('page', page.toString());
      params.set('limit', '20');
      if (searchQuery) params.set('search', searchQuery);
      if (dateFrom) params.set('dateFrom', dateFrom);
      if (dateTo) params.set('dateTo', dateTo);
      if (amountMin) params.set('amountMin', amountMin);
      if (amountMax) params.set('amountMax', amountMax);

      const res = await fetch(`/api/donations/my?${params.toString()}`);
      const data = await res.json();

      if (data.success) {
        setDonations(data.data.donations || []);
        setSummary(data.data.summary || { totalAmount: 0, totalDonations: 0, supportedStudents: 0, lastDonationDate: null });
        setPagination(data.data.pagination || { page: 1, limit: 20, total: 0, totalPages: 0 });
      }
    } catch (error) {
      console.error('Failed to fetch donations:', error);
    } finally {
      setLoading(false);
    }
  }, [searchQuery, dateFrom, dateTo, amountMin, amountMax]);

  useEffect(() => {
    if (status === 'authenticated') {
      fetchDonations(currentPage);
    }
  }, [status, currentPage, fetchDonations]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchDonations(1);
  };

  const clearFilters = () => {
    setSearchQuery('');
    setDateFrom('');
    setDateTo('');
    setAmountMin('');
    setAmountMax('');
    setShowFilters(false);
    fetchDonations(1);
  };

  const handleExport = async (format: 'csv' | 'excel' | 'pdf') => {
    setExporting(true);
    try {
      if (format === 'csv') {
        const res = await fetch('/api/donations/my/export?format=csv');
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `bagislarim_${new Date().toISOString().split('T')[0]}.csv`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        window.URL.revokeObjectURL(url);
      } else if (format === 'excel') {
        const res = await fetch('/api/donations/my/export?format=json');
        const data = await res.json();
        if (data.success && data.data) {
          const XLSX = (await import('xlsx')).default;
          const ws = XLSX.utils.json_to_sheet(data.data.map((d: any) => ({
            [t('myDonationsPage.detail.donationId')]: d.donation_id,
            [t('myDonationsPage.campaign')]: d.campaign_title,
            [t('myDonationsPage.amount')]: d.amount,
            [t('myDonationsPage.detail.donationDate')]: d.date,
            [t('myDonationsPage.status')]: d.status,
          })));
          const wb = XLSX.utils.book_new();
          XLSX.utils.book_append_sheet(wb, ws, t('myDonationsPage.title'));
          XLSX.writeFile(wb, `bagislarim_${new Date().toISOString().split('T')[0]}.xlsx`);
        }
      } else if (format === 'pdf') {
        const res = await fetch('/api/donations/my/export?format=json');
        const data = await res.json();
        if (data.success && data.data) {
          const { jsPDF } = await import('jspdf');
          const doc = new jsPDF();

          // Header
          doc.setFontSize(20);
          doc.setTextColor(37, 99, 235);
          doc.text(`FundEd - ${t('myDonationsPage.title')}`, 14, 22);

          doc.setFontSize(10);
          doc.setTextColor(100, 100, 100);
          doc.text(`${t('myDonationsPage.date')}: ${new Date().toLocaleDateString('tr-TR')}`, 14, 32);
          doc.text(`${t('myDonationsPage.totalDonation')}: ${formatAmount(summary.totalAmount)}`, 14, 38);
          doc.text(`${t('myDonationsPage.donationCount')}: ${summary.totalDonations}`, 14, 44);

          // Table Header
          let y = 56;
          doc.setFontSize(9);
          doc.setTextColor(0, 0, 0);
          doc.setFont('helvetica', 'bold');
          doc.text(t('myDonationsPage.campaign'), 14, y);
          doc.text(t('myDonationsPage.amount'), 100, y);
          doc.text(t('myDonationsPage.date'), 130, y);
          doc.text(t('myDonationsPage.status'), 170, y);

          doc.setDrawColor(200, 200, 200);
          doc.line(14, y + 2, 196, y + 2);

          // Table Rows
          doc.setFont('helvetica', 'normal');
          y += 10;
          data.data.forEach((d: any) => {
            if (y > 270) {
              doc.addPage();
              y = 20;
            }
            const title = d.campaign_title.length > 40 ? d.campaign_title.substring(0, 40) + '...' : d.campaign_title;
            doc.text(title, 14, y);
            doc.text(formatAmount(d.amount), 100, y);
            doc.text(new Date(d.date).toLocaleDateString('tr-TR'), 130, y);
            doc.text(d.status === 'paid' || d.status === 'completed' ? t('myDonationsPage.completed') : d.status, 170, y);
            y += 7;
          });

          doc.save(`bagislarim_${new Date().toISOString().split('T')[0]}.pdf`);
        }
      }
    } catch (error) {
      console.error('Export failed:', error);
    } finally {
      setExporting(false);
    }
  };

  const handleReceiptDownload = async (donationId: string) => {
    try {
      const res = await fetch(`/api/donations/my/${donationId}/receipt`);
      const data = await res.json();
      if (data.success && data.data.receipt) {
        const receipt = data.data.receipt;
        const { jsPDF } = await import('jspdf');
        const doc = new jsPDF();

        // Receipt PDF
        doc.setFontSize(24);
        doc.setTextColor(37, 99, 235);
        doc.text('FundEd', 14, 25);

        doc.setFontSize(10);
        doc.setTextColor(100, 100, 100);
        doc.text('Educational Crowdfunding Platform', 14, 32);

        doc.setDrawColor(37, 99, 235);
        doc.setLineWidth(0.5);
        doc.line(14, 36, 196, 36);

        doc.setFontSize(16);
        doc.setTextColor(0, 0, 0);
        doc.text(t('myDonationsPage.detail.receiptTitle'), 14, 48);

        doc.setFontSize(10);
        doc.setTextColor(80, 80, 80);

        const fields = [
          [`${t('myDonationsPage.detail.receiptNo')}:`, receipt.receipt_number],
          [`${t('myDonationsPage.detail.donor')}:`, receipt.donor_name],
          ['E-posta:', receipt.donor_email],
          [`${t('myDonationsPage.campaign')}:`, receipt.campaign_title],
          [`${t('myDonationsPage.amount')}:`, formatAmount(receipt.amount)],
          [`${t('myDonationsPage.date')}:`, new Date(receipt.date).toLocaleDateString('tr-TR')],
          [`${t('myDonationsPage.status')}:`, receipt.payment_status === 'paid' || receipt.payment_status === 'completed' ? t('myDonationsPage.completed') : receipt.payment_status],
        ];

        let y = 58;
        fields.forEach(([label, value]) => {
          doc.setFont('helvetica', 'bold');
          doc.text(label, 14, y);
          doc.setFont('helvetica', 'normal');
          doc.text(String(value), 60, y);
          y += 8;
        });

        doc.setDrawColor(200, 200, 200);
        doc.line(14, y + 4, 196, y + 4);

        y += 14;
        doc.setFontSize(8);
        doc.setTextColor(120, 120, 120);
        doc.text(t('myDonationsPage.detail.receiptFooter'), 14, y);
        doc.text(t('myDonationsPage.detail.receiptTax'), 14, y + 6);

        doc.save(`makbuz_${receipt.receipt_number}.pdf`);
      }
    } catch (error) {
      console.error('Receipt download failed:', error);
    }
  };

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '-';
    return new Date(dateStr).toLocaleDateString('tr-TR', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  const getStatusBadge = (status: string) => {
      const { t } = useTranslation();
    if (status === 'paid' || status === 'completed') {
      return <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-100">{t('myDonationsPage.completed')}</Badge>;
    }
    if (status === 'pending' || status === 'initiated') {
      return <Badge className="bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-100">{t('myDonationsPage.pending')}</Badge>;
    }
    return <Badge className="bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-100">{status}</Badge>;
  };

  if (status === 'loading') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="h-12 w-12 animate-spin mx-auto text-blue-600 mb-4 border-4 border-blue-200 border-t-blue-600 rounded-full" />
          <p className="text-gray-600">{t('common.loading')}</p>
        </div>
      </div>
    );
  }

  if (!session?.user) return null;

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <Navbar />
      <main className="flex-grow">
        {/* Hero Header */}
