                            </TableCell>
                            <TableCell>
                              <Badge variant="outline" className="bg-amber-50 text-amber-800 border-amber-200">
                                {app.projectCategory || '—'}
                              </Badge>
                            </TableCell>
                            <TableCell><StatusBadge status={app.status} /></TableCell>
                            <TableCell className="text-gray-500 text-sm">
                              {new Date(app.createdAt).toLocaleDateString('tr-TR', {
                                year: 'numeric', month: 'short', day: 'numeric',
                              })}
                            </TableCell>
                            <TableCell className="text-right">
                              <div className="flex items-center justify-end gap-1.5" onClick={(e) => e.stopPropagation()}>
                                {isPending && (
                                  <>
                                    <button
                                      disabled={isBusy}
                                      onClick={() => handleSchoolAction(app.id, 'Approved')}
                                      className="inline-flex items-center gap-1 rounded-md bg-green-600 hover:bg-green-700 text-white px-2.5 py-1 text-xs font-medium transition-colors disabled:opacity-50"
                                      title={t('app.page.onayla')}
                                    >
                                      <CheckCircle className="h-3.5 w-3.5" />
                                      {t('app.page.onayla')}</button>
                                    <button
                                      disabled={isBusy}
                                      onClick={() => handleSchoolAction(app.id, 'Rejected')}
                                      className="inline-flex items-center gap-1 rounded-md bg-red-600 hover:bg-red-700 text-white px-2.5 py-1 text-xs font-medium transition-colors disabled:opacity-50"
                                      title={t('app.page.reddet')}
                                    >
                                      <XCircle className="h-3.5 w-3.5" />
                                      {t('app.page.reddet')}</button>
                                  </>
                                )}
                                <button
                                  onClick={() => router.push(`/ops/applications/${app.id}`)}
                                  className="text-amber-600 hover:text-amber-800 text-xs font-medium underline underline-offset-2"
                                >
                                  {t('app.page.detay')}</button>
                              </div>
                            </TableCell>
                          </TableRow>
                        );
                      })}
                    </TableBody>
                  </TableComponent>
                </div>
              )}

              <div className="mt-4 flex items-center justify-between text-xs text-gray-400">
                <span>{t('app.page.g_sterilen')}{schoolApps.length} {t('app.page.okul_ba_vurusu')}</span>
                <span>{t('app.page.son_g_ncelleme')}{new Date().toLocaleTimeString('tr-TR')}</span>
              </div>
            </>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { MessageSquare, Play, Quote, Send, X, Loader2 } from 'lucide-react';
import { ThankYouCard, mockThankYouMessages } from '@/components/ThankYouMessage';
import MobileHeader from '@/components/MobileHeader';
import { useCurrency } from '@/lib/currency-context';
import { censorSurname } from '@/lib/privacy';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';

interface SuccessStory {
    story_id: string;
    user_name: string;
    title: string;
    quote: string;
    university: string;
    field: string;
    funded_amount: number;
    created_at: string;
}

// Hardcoded fallback stories (shown when DB has none)
const fallbackStories: SuccessStory[] = [
    {
        story_id: 'demo-1',
        user_name: 'Ayşe Yılmaz',
        title: 'Hayallerime Kavuştum',
        university: 'Boğaziçi Üniversitesi',
        field: 'Bilgisayar Mühendisliği',
        quote: "FundEd sayesinde hayallerime kavuştum. Şimdi Google'da staj yapıyorum!",
        funded_amount: 0,
        created_at: new Date().toISOString(),
    },
    {
        story_id: 'demo-2',
        user_name: 'Mehmet Kaya',
        title: 'Ailem Destekleyemiyordu',
        university: 'ODTU',
        field: 'Elektrik Elektronik',
        quote: 'Ailem beni destekleyemiyordu. FundEd ailesi olmasa burada olamazdım.',
        funded_amount: 0,
        created_at: new Date().toISOString(),
    },
    {
        story_id: 'demo-3',
        user_name: 'Zeynep Demir',
        title: 'Maddi ve Moral Destek',
        university: 'ITU',
        field: 'Mimarlık',
        quote: 'Bağışçıların desteği sadece maddi değil, moral olarak da çok değerli.',
        funded_amount: 0,
        created_at: new Date().toISOString(),
    },
];

export default function StoriesPage() {
    const { t } = useTranslation();
    const { formatAmount } = useCurrency();
    const { data: session } = useSession();
    const router = useRouter();
    const [stories, setStories] = useState<SuccessStory[]>(fallbackStories);
    const [showForm, setShowForm] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [formData, setFormData] = useState({
        title: '',
        quote: '',
        university: '',
        field: '',
        funded_amount: '',
    });

    useEffect(() => {
        loadStories();
    }, []);

    const loadStories = async () => {
        try {
            const res = await fetch('/api/stories');
            if (res.ok) {
                const data = await res.json();
                if (data.success && data.data?.stories?.length > 0) {
                    setStories(data.data.stories);
                }
                // else keep fallback stories
            }
        } catch {
            // Keep fallback stories on error
        }
    };

    const handleOpenForm = () => {
        if (!session?.user) {
            toast.error('Hikaye paylaşmak için giriş yapmalısınız');
            router.push('/login');
            return;
        }
        setShowForm(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        const { t } = useTranslation();
        e.preventDefault();
        if (submitting) return;

        if (formData.quote.trim().length < 10) {
            toast.error('Hikayeniz en az 10 karakter olmalıdır');
            return;
        }
        if (!formData.university.trim() || !formData.field.trim()) {
            toast.error('Üniversite ve bölüm bilgisi gereklidir');
            return;
        }

        setSubmitting(true);
        try {
            const res = await fetch('/api/stories', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    title: formData.title || 'Başarı Hikayem',
                    quote: formData.quote,
                    university: formData.university,
                    field: formData.field,
                    funded_amount: parseFloat(formData.funded_amount) || 0,
                }),
            });

            const data = await res.json();
            if (data.success) {
                toast.success('Hikayeniz gönderildi! Onaylandıktan sonra yayınlanacaktır. 🎉');
                setShowForm(false);
                setFormData({ title: '', quote: '', university: '', field: '', funded_amount: '' });
            } else {
                toast.error(data.error?.message || 'Bir hata oluştu');
            }
        } catch {
            toast.error('Bağlantı hatası. Lütfen tekrar deneyin.');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-gray-50 to-pink-50">
            {/* Mobile Header */}
            <MobileHeader transparent backHref="/" />

            {/* Hero */}
            <div className="bg-gradient-to-r from-pink-600 to-rose-700 text-white py-16 -mt-14 pt-20">
                <div className="container mx-auto px-4 text-center">
                    <div className="flex items-center justify-center gap-3 mb-4">
                        <MessageSquare className="h-10 w-10" />
                        <h1 className="text-4xl font-bold">{t('pages.stories.title')}</h1>
                    </div>
                    <p className="text-pink-100 text-lg max-w-2xl mx-auto mb-8">
                        {t('pages.stories.subtitle')}
                    </p>

                    {/* CTA: Share Your Story */}
                    <button
                        onClick={handleOpenForm}
                        className="inline-flex items-center gap-2 bg-white text-pink-600 px-8 py-3 rounded-full font-semibold text-lg hover:bg-pink-50 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5"
                    >
                        <Send className="h-5 w-5" />
                        {t('app.page.ba_ar_hikayeni_payla')}</button>
                </div>
            </div>

            <div className="container mx-auto px-4 py-8">
                {/* Demo Notice */}
                <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-8 flex items-center gap-3">
                    <span className="text-amber-600 font-bold text-lg">⚠️</span>
                    <p className="text-amber-800 text-sm font-medium">{t('common.demoStories')}</p>
                </div>

                {/* Success Stories */}
                <div className="grid md:grid-cols-3 gap-8 mb-12">
                    {stories.map((story) => (
                        <div key={story.story_id} className="bg-white rounded-xl shadow-sm border overflow-hidden hover:shadow-lg transition-shadow">
                            <div className="h-48 bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
                                <div className="w-24 h-24 bg-white/20 rounded-full flex items-center justify-center">
                                    <span className="text-4xl">🎓</span>
                                </div>
                            </div>
                            <div className="p-6">
                                <h3 className="font-bold text-xl text-gray-900">{censorSurname(story.user_name)}</h3>
                                <p className="text-blue-600 text-sm mb-2">{story.university}</p>
                                <p className="text-gray-500 text-sm mb-4">{story.field}</p>

                                <div className="bg-gray-50 rounded-lg p-4 mb-4">
                                    <Quote className="h-5 w-5 text-gray-400 mb-2" />
                                    <p className="text-gray-700 italic">{story.quote}</p>
                                </div>

                                <div className="flex items-center justify-between text-sm">
                                    <span className="text-gray-500">{t('pages.stories.collected')}:</span>
                                    <span className="font-bold text-green-600">{formatAmount(story.funded_amount)}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Thank You Messages */}
                <div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-6">{t('pages.stories.thankYouMessages')}</h2>
                    <div className="grid md:grid-cols-2 gap-6">
                        {mockThankYouMessages.map((message) => (
                            <ThankYouCard
                                key={message.id}
                                message={message}
                                onMarkRead={(id) => console.log('Marked read:', id)}
                            />
                        ))}
                    </div>
                </div>

                {/* Video CTA */}
                <div className="mt-12 bg-gradient-to-r from-purple-600 to-pink-600 rounded-xl p-8 text-center text-white">
                    <Play className="h-12 w-12 mx-auto mb-4 bg-white/20 p-3 rounded-full" />
                    <h3 className="text-2xl font-bold mb-2">{t('pages.stories.watchVideos')}</h3>
                    <p className="text-purple-100 mb-4">
                        {t('pages.stories.watchVideosDesc')}
                    </p>
                    <button className="bg-white text-purple-600 px-6 py-2 rounded-lg font-medium hover:bg-purple-50 transition-colors">
                        {t('pages.stories.watchNow')}
                    </button>
                </div>
            </div>

            {/* Submit Story Modal */}
            {showForm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
                        {/* Modal Header */}
                        <div className="flex items-center justify-between p-6 border-b border-gray-100">
                            <div className="flex items-center gap-3">
                                <div className="bg-pink-100 p-2 rounded-lg">
                                    <Send className="h-5 w-5 text-pink-600" />
                                </div>
                                <div>
                                    <h2 className="text-xl font-bold text-gray-900">{t('app.page.ba_ar_hikayeni_payla')}</h2>
                                    <p className="text-sm text-gray-500">{t('app.page.hikayeniz_onayland_ktan_sonra_')}</p>
                                </div>
                            </div>
                            <button
                                onClick={() => setShowForm(false)}
                                className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                                aria-label="Kapat"
                            >
                                <X className="h-5 w-5 text-gray-400" />
                            </button>
                        </div>

                        {/* Form */}
                        <form onSubmit={handleSubmit} className="p-6 space-y-5">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                    {t('app.page.ba_l_k')}<span className="text-gray-400">(opsiyonel)</span>
                                </label>
                                <input
                                    type="text"
                                    value={formData.title}
                                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    placeholder={t('app.page.rn_hayallerime_kavu_tum')}
                                    maxLength={200}
                                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-pink-500 focus:border-pink-500 outline-none transition-all"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                    {t('app.page.hikayeniz')}<span className="text-red-500">*</span>
                                </label>
                                <textarea
                                    value={formData.quote}
                                    onChange={(e) => setFormData({ ...formData, quote: e.target.value })}
                                    placeholder={t('app.page.funded_size_nas_l_yard_mc_oldu')}
                                    maxLength={1000}
                                    rows={4}
                                    required
                                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-pink-500 focus:border-pink-500 outline-none transition-all resize-none"
                                />
                                <p className="text-xs text-gray-400 mt-1">{formData.quote.length}/1000</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                        {t('app.page.niversite')}<span className="text-red-500">*</span>
                                    </label>
                                    <input
                                        type="text"
                                        value={formData.university}
                                        onChange={(e) => setFormData({ ...formData, university: e.target.value })}
                                        placeholder={t('app.page.rn_bo_azi_i_niversitesi')}
                                        maxLength={200}
                                        required
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-pink-500 focus:border-pink-500 outline-none transition-all"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                        {t('app.page.b_l_m')}<span className="text-red-500">*</span>
                                    </label>
                                    <input
                                        type="text"
                                        value={formData.field}
                                        onChange={(e) => setFormData({ ...formData, field: e.target.value })}
                                        placeholder={t('app.page.rn_bilgisayar_m_hendisli_i')}
                                        maxLength={200}
                                        required
                                        className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-pink-500 focus:border-pink-500 outline-none transition-all"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                    {t('app.page.toplanan_destek')}<span className="text-gray-400">(opsiyonel)</span>
                                </label>
                                <input
                                    type="number"
                                    value={formData.funded_amount}
                                    onChange={(e) => setFormData({ ...formData, funded_amount: e.target.value })}
                                    placeholder="0"
                                    min="0"
                                    step="0.01"
                                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-pink-500 focus:border-pink-500 outline-none transition-all"
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={submitting}
                                className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-pink-600 to-rose-600 text-white py-3.5 rounded-xl font-semibold hover:from-pink-700 hover:to-rose-700 transition-all disabled:opacity-60 disabled:cursor-not-allowed shadow-lg"
                            >
                                {submitting ? (
                                    <>
                                        <Loader2 className="h-5 w-5 animate-spin" />
                                        {t('app.page.g_nderiliyor')}</>
                                ) : (
                                    <>
                                        <Send className="h-5 w-5" />
                                        {t('app.page.hikayemi_g_nder')}</>
                                )}
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Skeleton } from '@/components/ui/skeleton';
import { StatCard } from '@/components/ui/StatCard';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { Wallet, TrendingUp, Clock, DollarSign, Plus, ExternalLink } from 'lucide-react';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface BalanceData {
  totalEarned: number;
  totalWithdrawn: number;
  available: number;
  pending: number;
}

interface CampaignItem {
  campaign_id: string;
  title: string;
  status: string;
  raised_amount: number;
  goal_amount: number;
  donor_count: number;
  created_at: string;
}

interface DonationItem {
  donation_id: string;
  amount: number;
  donor_name: string;
  anonymous: boolean;
  created_at: string;
  campaign_id: string;
}

export default function StudentDashboardPage() {
    const { t } = useTranslation();
  const { data: session, status: authStatus } = useSession();
  const router = useRouter();
  const { formatAmount } = useCurrency();

  const [balance, setBalance] = useState<BalanceData | null>(null);
  const [campaigns, setCampaigns] = useState<CampaignItem[]>([]);
  const [recentDonations, setRecentDonations] = useState<DonationItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [balRes, campRes] = await Promise.all([
        fetch('/api/student/balance'),
        fetch('/api/campaigns/my'),
      ]);

      if (!balRes.ok) throw new Error('Bakiye yüklenemedi');
      if (!campRes.ok) throw new Error('Kampanyalar yüklenemedi');

      const balData = await balRes.json();
      const campData = await campRes.json();

      setBalance(balData.data);
      setCampaigns(campData.data ?? []);

      // Fetch recent donations across user's campaigns
      const campaignIds: string[] = (campData.data ?? []).map((c: CampaignItem) => c.campaign_id);
      if (campaignIds.length > 0) {
        try {
          const donRes = await fetch(`/api/donations/my`);
          if (donRes.ok) {
            const donData = await donRes.json();
            setRecentDonations((donData.data ?? []).slice(0, 10));
          }
        } catch {
          // non-critical
        }
      }
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Veri yüklenemedi';
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (authStatus === 'loading') return;
    if (!session) {
      router.replace('/login');
      return;
    }
    fetchData();
  }, [session, authStatus, router, fetchData]);

  if (authStatus === 'loading') {
    return <DashboardSkeleton />;
  }

  if (!session) return null;

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center px-4">
        <div className="text-center max-w-md">
          <p className="text-red-600 font-medium mb-4">{error}</p>
          <Button onClick={fetchData}>{t('app.page.yeniden_dene')}</Button>
        </div>
      </div>
    );
  }

  const statusColor: Record<string, string> = {
    published: 'bg-green-100 text-green-800',
    draft: 'bg-gray-100 text-gray-800',
    completed: 'bg-blue-100 text-blue-800',
    suspended: 'bg-red-100 text-red-800',
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8">
          <h1 className="text-3xl font-bold text-gray-900">{t('app.page.renci_paneli')}</h1>
          <div className="flex gap-2 mt-4 sm:mt-0">
            <Link href="/student/dashboard/payout">
              <Button variant="outline" size="sm"><Wallet className="h-4 w-4 mr-1" /> {t('app.page.deme_y_ntemleri')}</Button>
            </Link>
            <Link href="/campaigns/new">
              <Button size="sm"><Plus className="h-4 w-4 mr-1" /> {t('app.page.yeni_kampanya')}</Button>
            </Link>
          </div>
        </div>

        {/* Balance Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <StatCard
            title={t('app.page.toplam_kazan')}
            value={formatAmount(balance?.totalEarned ?? 0)}
            icon={<TrendingUp className="h-5 w-5" />}
            loading={loading}
            valueClassName="text-green-600"
          />
          <StatCard
            title={t('app.page.kullan_labilir_bakiye')}
            value={formatAmount(balance?.available ?? 0)}
            icon={<DollarSign className="h-5 w-5" />}
            loading={loading}
            valueClassName="text-blue-600"
          />
          <StatCard
            title={t('app.page.beklemede')}
            value={formatAmount(balance?.pending ?? 0)}
            subtitle="(son 14 gün)"
            icon={<Clock className="h-5 w-5" />}
            loading={loading}
            valueClassName="text-yellow-600"
          />
          <StatCard
            title={t('app.page.ekilen_toplam')}
            value={formatAmount(balance?.totalWithdrawn ?? 0)}
            icon={<Wallet className="h-5 w-5" />}
            loading={loading}
          />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Campaigns */}
          <div className="lg:col-span-2">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('app.page.kampanyalar_m')}</h2>
            {loading ? (
              <div className="space-y-3">
                {[1, 2, 3].map((i) => (
                  <div key={i} className="bg-white rounded-lg shadow p-4">
                    <Skeleton className="h-5 w-2/3 mb-2" />
                    <Skeleton className="h-4 w-1/3 mb-2" />
                    <Skeleton className="h-3 w-full" />
                  </div>
                ))}
              </div>
            ) : campaigns.length === 0 ? (
              <div className="bg-white rounded-lg shadow p-12 text-center">
                <p className="text-gray-500 mb-4">{t('app.page.hen_z_kampanyan_z_yok')}</p>
                <Link href="/campaigns/new">
                  <Button><Plus className="h-4 w-4 mr-1" /> {t('app.page.lk_kampanyan_z_olu_turun')}</Button>
                </Link>
              </div>
            ) : (
              <div className="space-y-3">
                {campaigns.map((c) => {
                    const { t } = useTranslation();
                  const pct = c.goal_amount > 0 ? Math.min(100, Math.round((c.raised_amount / c.goal_amount) * 100)) : 0;
                  return (
                    <Link key={c.campaign_id} href={`/campaign/${c.campaign_id}`} className="block">
                      <div className="bg-white rounded-lg shadow p-4 hover:shadow-md transition-shadow">
                        <div className="flex items-start justify-between">
                          <div className="flex-1 min-w-0">
                            <h3 className="font-medium text-gray-900 truncate">{c.title}</h3>
                            <p className="text-sm text-gray-500 mt-1">
                              {formatAmount(c.raised_amount)} / {formatAmount(c.goal_amount)} &middot; {c.donor_count} {t('app.page.ba')}</p>
                          </div>
                          <Badge className={statusColor[c.status] ?? 'bg-gray-100 text-gray-800'}>
                            {c.status}
                          </Badge>
                        </div>
                        <div className="mt-3 w-full bg-gray-200 rounded-full h-2">
                          <div className="bg-blue-600 h-2 rounded-full transition-all" style={{ width: `${pct}%` }} />
                        </div>
                      </div>
                    </Link>
                  );
                })}
              </div>
            )}
          </div>

          {/* Recent Donations */}
          <div>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('app.page.son_ba_lar')}</h2>
            {loading ? (
              <div className="space-y-3">
                {[1, 2, 3, 4, 5].map((i) => (
                  <div key={i} className="bg-white rounded-lg shadow p-3">
                    <Skeleton className="h-4 w-1/2 mb-1" />
                    <Skeleton className="h-3 w-1/3" />
                  </div>
                ))}
              </div>
            ) : recentDonations.length === 0 ? (
              <div className="bg-white rounded-lg shadow p-8 text-center">
                <p className="text-gray-500">{t('app.page.hen_z_ba_yok')}</p>
              </div>
            ) : (
              <div className="space-y-2">
                {recentDonations.map((d) => (
                  <div key={d.donation_id} className="bg-white rounded-lg shadow p-3 flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-gray-900">
                        {d.anonymous ? 'Anonim' : d.donor_name}
                      </p>
                      <p className="text-xs text-gray-500">
                        {new Date(d.created_at).toLocaleDateString('tr-TR')}
                      </p>
                    </div>
                    <span className="text-sm font-semibold text-green-600">
                      +{formatAmount(d.amount)}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function DashboardSkeleton() {
  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 py-8">
        <Skeleton className="h-9 w-48 mb-8" />
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          {[1, 2, 3, 4].map((i) => (
            <div key={i} className="bg-white rounded-lg shadow p-6">
              <Skeleton className="h-4 w-28 mb-3" />
              <Skeleton className="h-8 w-24 mb-1" />
              <Skeleton className="h-4 w-32" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useState, useCallback } from 'react';
import Link from 'next/link';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import {
  ArrowLeft,
  Plus,
  Users,
  TrendingUp,
  MessageCircle,
  Eye,
} from 'lucide-react';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface DonorInfo {
  donor_id: string;
  donor_name: string;
  amount: number;
  anonymous: boolean;
  created_at: string;
}

interface CampaignDetail {
  campaign_id: string;
  title: string;
  description?: string;
  status: string;
  raised_amount: number;
  goal_amount: number;
  donor_count: number;
  created_at: string;
  donors?: DonorInfo[];
}

export default function StudentCampaignsPage() {
    const { t } = useTranslation();
  const { data: session } = useSession();
  const { formatAmount } = useCurrency();

  const [campaigns, setCampaigns] = useState<CampaignDetail[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedCampaign, setExpandedCampaign] = useState<string | null>(null);
  const [donorLoading, setDonorLoading] = useState<string | null>(null);

  const fetchCampaigns = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/campaigns/my');
      if (res.ok) {
        const data = await res.json();
        setCampaigns(data.data ?? []);
      }
    } catch {
      toast.error('Kampanyalar yüklenemedi');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (session) fetchCampaigns();
  }, [session, fetchCampaigns]);

  const loadDonors = async (campaignId: string) => {
    if (expandedCampaign === campaignId) {
      setExpandedCampaign(null);
      return;
    }
    setExpandedCampaign(campaignId);
    setDonorLoading(campaignId);
    try {
      const res = await fetch(`/api/student/campaigns/${campaignId}/donors`);
      if (res.ok) {
        const data = await res.json();
        setCampaigns((prev) =>
          prev.map((c) =>
            c.campaign_id === campaignId ? { ...c, donors: data.data ?? [] } : c,
          ),
        );
      }
    } catch {
      toast.error('Bağışçılar yüklenemedi');
    } finally {
      setDonorLoading(null);
    }
  };

  const statusColor: Record<string, string> = {
    published: 'bg-green-100 text-green-800',
    draft: 'bg-gray-100 text-gray-800',
    completed: 'bg-blue-100 text-blue-800',
    suspended: 'bg-red-100 text-red-800',
  };

  const statusLabel: Record<string, string> = {
    published: 'Aktif',
    draft: 'Taslak',
    completed: 'Tamamlandı',
    suspended: 'Askıda',
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <Link href="/student/panel">
          <Button variant="ghost" size="sm">
            <ArrowLeft className="h-4 w-4 mr-1" /> {t('app.page.geri')}</Button>
        </Link>
        <div className="flex-1">
          <h1 className="text-2xl font-bold text-gray-900">{t('app.page.kampanyalar_m')}</h1>
          <p className="text-gray-500 text-sm">
            {t('app.page.t_m_kampanyalar_n_z_g_r_n_ba_l')}</p>
        </div>
        <Link href="/campaigns/new">
          <Button size="sm">
            <Plus className="h-4 w-4 mr-1" /> {t('app.page.yeni_kampanya')}</Button>
        </Link>
      </div>

      {/* Campaign List */}
      {loading ? (
        <div className="space-y-4">
          {[1, 2, 3].map((i) => (
            <div key={i} className="bg-white rounded-lg shadow p-6">
              <Skeleton className="h-6 w-2/3 mb-3" />
              <Skeleton className="h-4 w-1/3 mb-2" />
              <Skeleton className="h-3 w-full" />
            </div>
          ))}
        </div>
      ) : campaigns.length === 0 ? (
        <div className="bg-white rounded-lg shadow p-16 text-center">
          <TrendingUp className="h-16 w-16 text-gray-300 mx-auto mb-4" />
          <p className="text-gray-500 text-lg mb-4">{t('app.page.hen_z_kampanyan_z_yok')}</p>
          <Link href="/campaigns/new">
            <Button>
              <Plus className="h-4 w-4 mr-1" /> {t('app.page.lk_kampanyan_z_olu_turun')}</Button>
          </Link>
        </div>
      ) : (
        <div className="space-y-4">
          {campaigns.map((c) => {
              const { t } = useTranslation();
            const pct =
              c.goal_amount > 0
                ? Math.min(100, Math.round((c.raised_amount / c.goal_amount) * 100))
                : 0;
            const isExpanded = expandedCampaign === c.campaign_id;

            return (
              <div key={c.campaign_id} className="bg-white rounded-lg shadow overflow-hidden">
                <div className="p-6">
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="text-lg font-semibold text-gray-900 truncate">
                          {c.title}
                        </h3>
                        <Badge className={statusColor[c.status] ?? 'bg-gray-100 text-gray-800'}>
                          {statusLabel[c.status] ?? c.status}
                        </Badge>
                      </div>
                      <p className="text-sm text-gray-500">
                        {t('app.page.olu_turulma')}{new Date(c.created_at).toLocaleDateString('tr-TR')}
                      </p>
                    </div>
                    <div className="flex gap-2">
                      <Link href={`/campaign/${c.campaign_id}`}>
                        <Button variant="outline" size="sm">
                          <Eye className="h-4 w-4 mr-1" /> {t('app.page.g_r_nt_le')}</Button>
                      </Link>
                      {c.status === 'completed' && (
                        <Link href={`/student/panel/updates?campaign=${c.campaign_id}`}>
                          <Button variant="outline" size="sm">
                            {t('app.page.g_ncelleme_payla')}</Button>
                        </Link>
                      )}
                    </div>
                  </div>

                  {/* Progress */}
                  <div className="mb-4">
                    <div className="flex justify-between text-sm mb-1">
                      <span className="text-gray-600">{t('app.page.lerleme')}</span>
                      <span className="font-medium text-gray-900">{pct}%</span>
                    </div>
                    <div className="w-full bg-gray-200 rounded-full h-3">
                      <div
                        className="bg-blue-600 h-3 rounded-full transition-all"
                        style={{ width: `${pct}%` }}
                      />
                    </div>
                    <div className="flex justify-between text-sm mt-1">
                      <span className="text-green-600 font-medium">
                        {formatAmount(c.raised_amount)}
                      </span>
                      <span className="text-gray-500">/ {formatAmount(c.goal_amount)}</span>
                    </div>
                  </div>

                  {/* Quick Stats */}
                  <div className="flex items-center gap-6 text-sm text-gray-600">
                    <span className="flex items-center gap-1">
                      <Users className="h-4 w-4" /> {c.donor_count} {t('app.page.ba')}</span>
                    <button
                      onClick={() => loadDonors(c.campaign_id)}
                      className="flex items-center gap-1 text-blue-600 hover:text-blue-800 font-medium"
                    >
                      <Users className="h-4 w-4" />
                      {isExpanded ? 'Bağışçıları Gizle' : 'Bağışçıları Göster'}
                    </button>
                    <Link
                      href={`/student/panel/messages?campaign=${c.campaign_id}`}
                      className="flex items-center gap-1 text-blue-600 hover:text-blue-800 font-medium"
                    >
                      <MessageCircle className="h-4 w-4" /> {t('app.page.mesaj_g_nder')}</Link>
                  </div>
                </div>

                {/* Expanded Donors List */}
                {isExpanded && (
                  <div className="border-t bg-gray-50 p-6">
                    <h4 className="font-medium text-gray-900 mb-3">{t('app.page.ba_lar')}</h4>
                    {donorLoading === c.campaign_id ? (
                      <div className="space-y-2">
                        {[1, 2, 3].map((i) => (
                          <div key={i} className="flex items-center gap-3">
                            <Skeleton className="h-8 w-8 rounded-full" />
                            <Skeleton className="h-4 w-32" />
                            <Skeleton className="h-4 w-16 ml-auto" />
                          </div>
                        ))}
                      </div>
                    ) : !c.donors || c.donors.length === 0 ? (
                      <p className="text-gray-500 text-sm">{t('app.page.hen_z_ba_yok')}</p>
                    ) : (
                      <div className="space-y-2">
                        {c.donors.map((d, idx) => (
                          <div
                            key={d.donor_id + '-' + idx}
                            className="flex items-center gap-3 bg-white rounded-lg p-3"
                          >
                            <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-medium text-sm flex-shrink-0">
                              {d.anonymous ? '?' : d.donor_name.charAt(0).toUpperCase()}
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-gray-900">
                                {d.anonymous ? 'Anonim Bağışçı' : d.donor_name}
                              </p>
                              <p className="text-xs text-gray-500">
                                {new Date(d.created_at).toLocaleDateString('tr-TR')}
                              </p>
                            </div>
                            <span className="text-sm font-semibold text-green-600">
                              {formatAmount(d.amount)}
                            </span>
                            {!d.anonymous && (
                              <Link
                                href={`/student/panel/messages?campaign=${c.campaign_id}&donor=${d.donor_id}`}
                              >
                                <Button variant="ghost" size="sm" className="text-blue-600">
                                  <MessageCircle className="h-4 w-4" />
                                </Button>
                              </Link>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useState, useCallback, useRef } from 'react';
import { useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import {
  ArrowLeft,
  MessageCircle,
  Send,
  User,
  ChevronRight,
} from 'lucide-react';
import { useTranslation } from "@/lib/i18n/context";

interface ConversationThread {
  donor_id: string;
  donor_name: string;
  campaign_id: string;
  campaign_title: string;
  last_message: string;
  last_message_at: string;
  unread_count: number;
  anonymous: boolean;
}

interface Message {
  message_id: string;
  sender_id: string;
  sender_name: string;
  recipient_id: string;
  content: string;
  type: string;
  read: boolean;
  created_at: string;
}

export default function StudentMessagesPage() {
    const { t } = useTranslation();
  const { data: session } = useSession();
  const searchParams = useSearchParams();
  const preselectedCampaign = searchParams.get('campaign') || '';
  const preselectedDonor = searchParams.get('donor') || '';

  const [threads, setThreads] = useState<ConversationThread[]>([]);
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(true);
  const [messagesLoading, setMessagesLoading] = useState(false);
  const [sending, setSending] = useState(false);

  const [activeThread, setActiveThread] = useState<ConversationThread | null>(null);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const pollIntervalRef = useRef<NodeJS.Timeout | null>(null);

  const userId = (session?.user as any)?.id;

  const fetchThreads = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/student/messages/threads');
      if (res.ok) {
        const data = await res.json();
        setThreads(data.data ?? []);

        // Auto-open thread if donor/campaign is specified
        if (preselectedDonor && preselectedCampaign) {
          const match = (data.data ?? []).find(
            (t: ConversationThread) =>
              t.donor_id === preselectedDonor && t.campaign_id === preselectedCampaign,
          );
          if (match) {
            openThread(match);
          } else {
            // Create a placeholder thread for new conversation
            setActiveThread({
              donor_id: preselectedDonor,
              donor_name: 'Bağışçı',
              campaign_id: preselectedCampaign,
              campaign_title: '',
              last_message: '',
              last_message_at: '',
              unread_count: 0,
              anonymous: false,
            });
          }
        }
      }
    } catch {
      toast.error('Mesajlar yüklenemedi');
    } finally {
      setLoading(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [preselectedDonor, preselectedCampaign]);

  useEffect(() => {
    if (session) fetchThreads();
    return () => {
      if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
    };
  }, [session, fetchThreads]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const openThread = async (thread: ConversationThread) => {
    setActiveThread(thread);
    setMessagesLoading(true);

    // Clear old polling
    if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);

    try {
      await loadMessages(thread);

      // Mark as read
      await fetch('/api/student/messages/mark-read', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          campaign_id: thread.campaign_id,
          donor_id: thread.donor_id,
        }),
      });

      // Update unread count in thread list
      setThreads((prev) =>
        prev.map((t) =>
          t.donor_id === thread.donor_id && t.campaign_id === thread.campaign_id
            ? { ...t, unread_count: 0 }
            : t,
        ),
      );

      // Start polling for new messages
      pollIntervalRef.current = setInterval(() => {
        loadMessages(thread);
      }, 5000);
    } catch {
      toast.error('Mesajlar yüklenemedi');
    } finally {
      setMessagesLoading(false);
    }
  };

  const loadMessages = async (thread: ConversationThread) => {
    const res = await fetch(
      `/api/student/messages?campaign_id=${thread.campaign_id}&donor_id=${thread.donor_id}`,
    );
    if (res.ok) {
      const data = await res.json();
      setMessages(data.data ?? []);
    }
  };

  const sendMessage = async () => {
    if (!newMessage.trim() || !activeThread) return;

    setSending(true);
    try {
      const res = await fetch('/api/student/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          campaign_id: activeThread.campaign_id,
          recipient_id: activeThread.donor_id,
          content: newMessage.trim(),
        }),
      });

      if (res.ok) {
        setNewMessage('');
        // Immediately reload messages
        await loadMessages(activeThread);
      } else {
        const errData = await res.json();
        toast.error(errData.error?.message || 'Mesaj gönderilemedi');
      }
    } catch {
      toast.error('Mesaj gönderilirken hata oluştu');
    } finally {
      setSending(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <Link href="/student/panel">
          <Button variant="ghost" size="sm">
            <ArrowLeft className="h-4 w-4 mr-1" /> {t('app.page.geri')}</Button>
        </Link>
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{t('app.page.mesajlar')}</h1>
          <p className="text-gray-500 text-sm">
            {t('app.page.sadece_size_ba_yapan_don_rlerl')}</p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow overflow-hidden" style={{ height: 'calc(100vh - 200px)', minHeight: '500px' }}>
        <div className="flex h-full">
          {/* Thread List */}
          <div className={`w-full md:w-80 border-r flex-shrink-0 flex flex-col ${activeThread ? 'hidden md:flex' : 'flex'}`}>
            <div className="p-4 border-b bg-gray-50">
              <h2 className="font-semibold text-gray-900">{t('app.page.konu_malar')}</h2>
            </div>

            <div className="flex-1 overflow-y-auto">
              {loading ? (
                <div className="p-4 space-y-3">
                  {[1, 2, 3, 4].map((i) => (
                    <div key={i} className="flex items-center gap-3">
                      <Skeleton className="h-10 w-10 rounded-full" />
                      <div className="flex-1">
                        <Skeleton className="h-4 w-24 mb-1" />
                        <Skeleton className="h-3 w-32" />
                      </div>
                    </div>
                  ))}
                </div>
              ) : threads.length === 0 ? (
                <div className="p-8 text-center">
                  <MessageCircle className="h-12 w-12 text-gray-300 mx-auto mb-3" />
                  <p className="text-gray-500 text-sm">{t('app.page.hen_z_mesaj_n_z_yok')}</p>
                  <p className="text-gray-400 text-xs mt-1">
                    {t('app.page.ba_lar_n_zdan_mesaj_geldi_inde')}</p>
                </div>
              ) : (
                threads.map((thread) => {
                    const { t } = useTranslation();
                  const isActive =
                    activeThread?.donor_id === thread.donor_id &&
                    activeThread?.campaign_id === thread.campaign_id;
                  return (
                    <button
                      key={`${thread.donor_id}-${thread.campaign_id}`}
                      onClick={() => openThread(thread)}
                      className={`w-full p-4 text-left flex items-center gap-3 border-b hover:bg-gray-50 transition-colors ${isActive ? 'bg-blue-50' : ''
                        }`}
                    >
                      <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-medium flex-shrink-0">
                        {thread.anonymous ? '?' : thread.donor_name.charAt(0).toUpperCase()}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <p className="text-sm font-medium text-gray-900 truncate">
                            {thread.anonymous ? 'Anonim Bağışçı' : thread.donor_name}
                          </p>
                          {thread.unread_count > 0 && (
                            <span className="bg-blue-600 text-white text-xs rounded-full px-2 py-0.5 ml-2">
                              {thread.unread_count}
                            </span>
                          )}
                        </div>
                        <p className="text-xs text-blue-600 truncate">{thread.campaign_title}</p>
                        <p className="text-xs text-gray-500 truncate mt-0.5">
                          {thread.last_message}
                        </p>
                      </div>
                      <ChevronRight className="h-4 w-4 text-gray-400 flex-shrink-0" />
                    </button>
                  );
                })
              )}
            </div>
          </div>

          {/* Chat Area */}
          <div className={`flex-1 flex flex-col ${!activeThread ? 'hidden md:flex' : 'flex'}`}>
            {!activeThread ? (
              <div className="flex-1 flex items-center justify-center text-center p-8">
                <div>
                  <MessageCircle className="h-16 w-16 text-gray-200 mx-auto mb-4" />
                  <p className="text-gray-500">{t('app.page.bir_konu_ma_se_in')}</p>
                  <p className="text-gray-400 text-sm mt-1">
                    {t('app.page.sol_taraftaki_listeden_bir_ba_')}</p>
                </div>
              </div>
            ) : (
              <>
                {/* Chat Header */}
                <div className="p-4 border-b bg-gray-50 flex items-center gap-3">
                  <button
                    onClick={() => {
                      setActiveThread(null);
                      if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
                    }}
                    className="md:hidden p-1 rounded hover:bg-gray-200"
                  >
                    <ArrowLeft className="h-5 w-5" />
                  </button>
                  <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-medium text-sm">
                    {activeThread.anonymous
                      ? '?'
                      : activeThread.donor_name.charAt(0).toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-gray-900 text-sm">
                      {activeThread.anonymous ? 'Anonim Bağışçı' : activeThread.donor_name}
                    </p>
                    {activeThread.campaign_title && (
                      <p className="text-xs text-gray-500 truncate">
                        {activeThread.campaign_title}
                      </p>
                    )}
                  </div>
                </div>

                {/* Messages */}
                <div className="flex-1 overflow-y-auto p-4 space-y-3">
                  {messagesLoading ? (
                    <div className="space-y-3">
                      {[1, 2, 3].map((i) => (
                        <div
                          key={i}
                          className={`flex ${i % 2 === 0 ? 'justify-end' : 'justify-start'}`}
                        >
                          <Skeleton className="h-10 w-48 rounded-lg" />
                        </div>
                      ))}
                    </div>
                  ) : messages.length === 0 ? (
                    <div className="flex items-center justify-center h-full text-center">
                      <div>
                        <p className="text-gray-400 text-sm">{t('app.page.hen_z_mesaj_yok')}</p>
                        <p className="text-gray-400 text-xs mt-1">
                          {t('app.page.lk_mesaj_g_ndererek_konu_may_b')}</p>
                      </div>
                    </div>
                  ) : (
                    messages.map((msg) => {
                      const isOwn = msg.sender_id === userId;
                      return (
                        <div
                          key={msg.message_id}
                          className={`flex ${isOwn ? 'justify-end' : 'justify-start'}`}
                        >
                          <div
                            className={`max-w-[70%] rounded-lg px-4 py-2 ${isOwn
                                ? 'bg-blue-600 text-white'
                                : 'bg-gray-100 text-gray-900'
                              }`}
                          >
                            <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                            <p
                              className={`text-xs mt-1 ${isOwn ? 'text-blue-200' : 'text-gray-400'
                                }`}
                            >
                              {new Date(msg.created_at).toLocaleTimeString('tr-TR', {
                                hour: '2-digit',
                                minute: '2-digit',
                              })}
                            </p>
                          </div>
                        </div>
                      );
                    })
                  )}
                  <div ref={messagesEndRef} />
                </div>

                {/* Message Input */}
                <div className="p-4 border-t bg-white">
                  <div className="flex items-end gap-2">
                    <textarea
                      value={newMessage}
                      onChange={(e) => setNewMessage(e.target.value)}
                      onKeyDown={handleKeyDown}
                      placeholder={t('app.page.mesaj_n_z_yaz_n')}
                      rows={1}
                      className="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 resize-none max-h-24"
                      maxLength={1000}
                    />
                    <Button
                      onClick={sendMessage}
                      disabled={sending || !newMessage.trim()}
                      size="sm"
                      className="h-10"
                    >
                      {sending ? (
                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white" />
                      ) : (
                        <Send className="h-4 w-4" />
                      )}
                    </Button>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useSession } from 'next-auth/react';
import { useEffect, useState, useCallback } from 'react';
import Link from 'next/link';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import {
  Megaphone,
  TrendingUp,
  Users,
  MessageCircle,
  Plus,
  ArrowRight,
  FileEdit,
} from 'lucide-react';
import { useCurrency } from '@/lib/currency-context';
import { useTranslation } from "@/lib/i18n/context";

interface CampaignItem {
  campaign_id: string;
  title: string;
  status: string;
  raised_amount: number;
  goal_amount: number;
  donor_count: number;
  created_at: string;
}

interface DonationItem {
  donation_id: string;
  amount: number;
  donor_name: string;
  donor_id: string;
  anonymous: boolean;
  created_at: string;
  campaign_title?: string;
}

export default function StudentPanelPage() {
    const { t } = useTranslation();
  const { data: session } = useSession();
  const { formatAmount } = useCurrency();

  const [campaigns, setCampaigns] = useState<CampaignItem[]>([]);
  const [recentDonations, setRecentDonations] = useState<DonationItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [unreadMessages, setUnreadMessages] = useState(0);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const [campRes, msgRes] = await Promise.all([
        fetch('/api/campaigns/my'),
        fetch('/api/student/messages/unread-count'),
      ]);

      if (campRes.ok) {
        const campData = await campRes.json();
        setCampaigns(campData.data ?? []);
      }

      if (msgRes.ok) {
        const msgData = await msgRes.json();
        setUnreadMessages(msgData.data?.count ?? 0);
      }

      // Fetch donations for student's campaigns
      try {
        const donRes = await fetch('/api/student/donations');
        if (donRes.ok) {
          const donData = await donRes.json();
          setRecentDonations((donData.data ?? []).slice(0, 5));
        }
      } catch {}
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Veri yüklenemedi';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (session) fetchData();
  }, [session, fetchData]);

  const activeCampaigns = campaigns.filter((c) => c.status === 'published');
  const completedCampaigns = campaigns.filter((c) => c.status === 'completed');
  const totalRaised = campaigns.reduce((sum, c) => sum + (c.raised_amount || 0), 0);
  const totalDonors = campaigns.reduce((sum, c) => sum + (c.donor_count || 0), 0);

  const statusColor: Record<string, string> = {
    published: 'bg-green-100 text-green-800',
    draft: 'bg-gray-100 text-gray-800',
    completed: 'bg-blue-100 text-blue-800',
    suspended: 'bg-red-100 text-red-800',
  };

  const statusLabel: Record<string, string> = {
    published: 'Aktif',
    draft: 'Taslak',
    completed: 'Tamamlandı',
    suspended: 'Askıda',
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">{t('app.page.ho_geldiniz')}</h1>
          <p className="text-gray-500 mt-1">
            {t('app.page.kampanyalar_n_z_y_netin_ba_lar')}</p>
        </div>
        <Link href="/campaigns/new" className="mt-4 sm:mt-0">
          <Button size="sm">
            <Plus className="h-4 w-4 mr-1" /> {t('app.page.yeni_kampanya')}</Button>
        </Link>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <StatsCard
          icon={<Megaphone className="h-5 w-5 text-blue-600" />}
          title={t('app.page.aktif_kampanyalar')}
          value={loading ? '—' : String(activeCampaigns.length)}
          loading={loading}
        />
        <StatsCard
          icon={<TrendingUp className="h-5 w-5 text-green-600" />}
          title={t('app.page.toplam_toplanan')}
          value={loading ? '—' : formatAmount(totalRaised)}
          loading={loading}
        />
        <StatsCard
          icon={<Users className="h-5 w-5 text-purple-600" />}
          title={t('app.page.toplam_ba')}
          value={loading ? '—' : String(totalDonors)}
          loading={loading}
        />
        <StatsCard
          icon={<MessageCircle className="h-5 w-5 text-orange-600" />}
          title={t('app.page.okunmam_mesaj')}
          value={loading ? '—' : String(unreadMessages)}
          loading={loading}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Active Campaigns */}
        <div className="lg:col-span-2 space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-semibold text-gray-900">{t('app.page.aktif_kampanyalar_m')}</h2>
            <Link href="/student/panel/campaigns">
              <Button variant="ghost" size="sm">
                {t('app.page.t_m_n_g_r')}<ArrowRight className="h-4 w-4 ml-1" />
              </Button>
            </Link>
          </div>

          {loading ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <div key={i} className="bg-white rounded-lg shadow p-4">
                  <Skeleton className="h-5 w-2/3 mb-2" />
                  <Skeleton className="h-4 w-1/3 mb-2" />
                  <Skeleton className="h-3 w-full" />
                </div>
              ))}
            </div>
          ) : activeCampaigns.length === 0 ? (
            <div className="bg-white rounded-lg shadow p-12 text-center">
              <Megaphone className="h-12 w-12 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-500 mb-4">{t('app.page.hen_z_aktif_kampanyan_z_yok')}</p>
              <Link href="/campaigns/new">
                <Button>
                  <Plus className="h-4 w-4 mr-1" /> {t('app.page.lk_kampanyan_z_olu_turun')}</Button>
              </Link>
            </div>
          ) : (
            <div className="space-y-3">
              {activeCampaigns.slice(0, 5).map((c) => {
                  const { t } = useTranslation();
                const pct =
                  c.goal_amount > 0
                    ? Math.min(100, Math.round((c.raised_amount / c.goal_amount) * 100))
                    : 0;
                return (
                  <Link
                    key={c.campaign_id}
                    href={`/student/panel/campaigns/${c.campaign_id}`}
                    className="block"
                  >
                    <div className="bg-white rounded-lg shadow p-4 hover:shadow-md transition-shadow">
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0">
                          <h3 className="font-medium text-gray-900 truncate">{c.title}</h3>
                          <p className="text-sm text-gray-500 mt-1">
                            {formatAmount(c.raised_amount)} / {formatAmount(c.goal_amount)} &middot;{' '}
                            {c.donor_count} {t('app.page.ba')}</p>
                        </div>
                        <Badge className={statusColor[c.status] ?? 'bg-gray-100 text-gray-800'}>
                          {statusLabel[c.status] ?? c.status}
                        </Badge>
                      </div>
                      <div className="mt-3 w-full bg-gray-200 rounded-full h-2">
                        <div
                          className="bg-blue-600 h-2 rounded-full transition-all"
                          style={{ width: `${pct}%` }}
                        />
                      </div>
                      <p className="text-xs text-gray-400 mt-1 text-right">{pct}%</p>
                    </div>
                  </Link>
                );
              })}
            </div>
          )}

          {/* Completed campaigns with update prompt */}
          {completedCampaigns.length > 0 && (
            <div>
              <div className="flex items-center justify-between mb-3">
                <h2 className="text-xl font-semibold text-gray-900">{t('app.page.tamamlanan_kampanyalar')}</h2>
                <Link href="/student/panel/updates">
                  <Button variant="ghost" size="sm">
                    {t('app.page.g_ncelleme_payla')}<FileEdit className="h-4 w-4 ml-1" />
                  </Button>
                </Link>
              </div>
              <div className="space-y-3">
                {completedCampaigns.slice(0, 3).map((c) => (
                  <div
                    key={c.campaign_id}
                    className="bg-white rounded-lg shadow p-4 border-l-4 border-blue-500"
                  >
                    <div className="flex items-center justify-between">
                      <div>
                        <h3 className="font-medium text-gray-900">{c.title}</h3>
                        <p className="text-sm text-gray-500">
                          {formatAmount(c.raised_amount)} {t('app.page.topland_middot')}{c.donor_count} {t('app.page.ba')}</p>
                      </div>
                      <Link href={`/student/panel/updates?campaign=${c.campaign_id}`}>
                        <Button variant="outline" size="sm">
                          <FileEdit className="h-4 w-4 mr-1" /> {t('app.page.g_ncelleme')}</Button>
                      </Link>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Right Column - Recent Donations */}
        <div className="space-y-6">
          <h2 className="text-xl font-semibold text-gray-900">{t('app.page.son_ba_lar')}</h2>

          {loading ? (
            <div className="space-y-3">
              {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className="bg-white rounded-lg shadow p-3">
                  <Skeleton className="h-4 w-1/2 mb-1" />
                  <Skeleton className="h-3 w-1/3" />
                </div>
              ))}
            </div>
          ) : recentDonations.length === 0 ? (
            <div className="bg-white rounded-lg shadow p-8 text-center">
              <p className="text-gray-500">{t('app.page.hen_z_ba_yok')}</p>
            </div>
          ) : (
            <div className="space-y-2">
              {recentDonations.map((d) => (
                <div
                  key={d.donation_id}
                  className="bg-white rounded-lg shadow p-3 flex items-center justify-between"
                >
                  <div>
                    <p className="text-sm font-medium text-gray-900">
                      {d.anonymous ? 'Anonim Bağışçı' : d.donor_name}
                    </p>
                    <p className="text-xs text-gray-500">
                      {d.campaign_title && (
                        <span className="text-blue-600">{d.campaign_title} &middot; </span>
                      )}
                      {new Date(d.created_at).toLocaleDateString('tr-TR')}
                    </p>
                  </div>
                  <span className="text-sm font-semibold text-green-600">
                    +{formatAmount(d.amount)}
                  </span>
                </div>
              ))}
            </div>
          )}

          {/* Quick Links */}
          <div className="bg-white rounded-lg shadow p-4 space-y-3">
            <h3 className="font-medium text-gray-900">{t('app.page.h_zl_eri_im')}</h3>
            <Link
              href="/student/panel/messages"
              className="flex items-center gap-2 text-sm text-blue-600 hover:text-blue-800"
            >
              <MessageCircle className="h-4 w-4" />
              {t('app.page.ba_lar_n_za_mesaj_g_nderin')}{unreadMessages > 0 && (
                <span className="bg-red-500 text-white text-xs rounded-full px-2 py-0.5">
                  {unreadMessages}
                </span>
              )}
            </Link>
            <Link
              href="/student/panel/updates"
              className="flex items-center gap-2 text-sm text-blue-600 hover:text-blue-800"
            >
              <FileEdit className="h-4 w-4" />
              {t('app.page.g_ncelleme_ve_foto_raf_payla_n')}</Link>
          </div>
        </div>
      </div>
    </div>
  );
}

function StatsCard({
  icon,
  title,
  value,
  loading,
}: {
  icon: React.ReactNode;
  title: string;
  value: string;
  loading: boolean;
}) {
  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="flex items-center gap-3 mb-2">
        {icon}
        <span className="text-sm text-gray-500">{title}</span>
      </div>
      {loading ? (
        <Skeleton className="h-8 w-20" />
      ) : (
        <p className="text-2xl font-bold text-gray-900">{value}</p>
      )}
    </div>
  );
}

﻿'use client';

import { useState, useEffect, Suspense, useRef, useCallback } from 'react';
import { useTranslation } from "@/lib/i18n/context";
import { useRouter, useSearchParams } from 'next/navigation';
import { useSession } from 'next-auth/react';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { toast } from 'sonner';
import {
    TIER_CONFIG,
    isEducationalEmail,
    getTierBadgeInfo
} from '@/lib/verification/tiers';
import type { VerificationTier } from '@/types/verification';
import {
    X, Upload, FileText, CheckCircle2, AlertCircle,
    ShieldCheck, Shield, Mail, GraduationCap, User,
    FileUp, ClipboardCheck, ChevronRight, ChevronLeft,
    Building2, MapPin, Calendar, Phone, BookOpen, Star
} from 'lucide-react';

// Multi-step form stages
type FormStep = 'tier-select' | 'personal-info' | 'education-info' | 'documents' | 'review';

interface FormData {
    tierRequested: VerificationTier;
    institutionEmail: string;
    firstName: string;
    lastName: string;
    dateOfBirth: string;
    phone: string;
    country: string;
    city: string;
    institutionName: string;
    institutionCountry: string;
    institutionType: 'university' | 'college' | 'vocational' | 'high_school';
    studentId: string;
    enrollmentYear: number;
    expectedGraduation: number;
    degreeProgram: string;
    degreeLevel: 'bachelor' | 'master' | 'phd' | 'associate' | 'certificate';
    isFullTime: boolean;
    financialNeedStatement: string;
}

const initialFormData: FormData = {
    tierRequested: 1,
    institutionEmail: '',
    firstName: '',
    lastName: '',
    dateOfBirth: '',
    phone: '',
    country: '',
    city: '',
    institutionName: '',
    institutionCountry: '',
    institutionType: 'university',
    studentId: '',
    enrollmentYear: new Date().getFullYear(),
    expectedGraduation: new Date().getFullYear() + 4,
    degreeProgram: '',
    degreeLevel: 'bachelor',
    isFullTime: true,
    financialNeedStatement: '',
};

// File upload
const ALLOWED_FILE_TYPES = ['application/pdf', 'image/jpeg', 'image/jpg', 'image/png'];
const ALLOWED_EXTENSIONS = ['.pdf', '.jpg', '.jpeg', '.png'];
const MAX_FILE_SIZE = 10 * 1024 * 1024;

interface UploadedFile {
    file: File;
    status: 'queued' | 'uploading' | 'uploaded' | 'error';
    error?: string;
}

// Step Icons
const STEP_ICONS: Record<FormStep, React.ElementType> = {
    'tier-select': Shield,
    'personal-info': User,
    'education-info': GraduationCap,
    'documents': FileUp,
    'review': ClipboardCheck,
};

// Documents Upload Component
function DocumentsUploadStep({ tierRequested, t }: { tierRequested: number; t: (key: string) => string }) {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [files, setFiles] = useState<UploadedFile[]>([]);
    const [dragActive, setDragActive] = useState(false);

    const validateFile = (file: File): string | null => {
        if (!ALLOWED_FILE_TYPES.includes(file.type)) {
            return `Geçersiz dosya türü. İzin verilen: ${ALLOWED_EXTENSIONS.join(', ')}`;
        }
        if (file.size > MAX_FILE_SIZE) {
            return 'Dosya cok buyuk. Maksimum: 10MB';
        }
        return null;
    };

    const handleFiles = useCallback((fileList: FileList | null) => {
        if (!fileList) return;
        const newFiles: UploadedFile[] = [];
        for (let i = 0; i < fileList.length; i++) {
            const file = fileList[i];
            const error = validateFile(file);
            newFiles.push({ file, status: error ? 'error' : 'queued', error: error || undefined });
        }
        setFiles(prev => [...prev, ...newFiles]);
    }, []);

    const handleButtonClick = () => fileInputRef.current?.click();

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        handleFiles(e.target.files);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleDrag = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setDragActive(e.type === 'dragenter' || e.type === 'dragover');
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setDragActive(false);
        handleFiles(e.dataTransfer.files);
    };

    const removeFile = (index: number) => setFiles(prev => prev.filter((_, i) => i !== index));

    const formatFileSize = (bytes: number) => {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
    };

    return (
        <div className="space-y-6">
            <div className="p-5 bg-gradient-to-r from-amber-50 to-orange-50 rounded-xl border border-amber-200">
                <div className="flex items-start gap-3">
                    <div className="p-2 bg-amber-100 rounded-lg">
                        <AlertCircle className="w-5 h-5 text-amber-600" />
                    </div>
                    <div>
                        <h4 className="font-semibold text-amber-900 mb-2">
                            {t('verification.documentGuidance') || 'Belgeler okunaklı, tam kadraj ve güncel olmalı.'}
                        </h4>
                        <p className="text-sm text-amber-700 mb-3">
                            {t('verification.documentMaskingHint') || 'Gerekli olmayan hassas bilgileri kapatabilirsin.'}
                        </p>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                            <div className="flex items-center gap-2 text-sm text-amber-800">
                                <CheckCircle2 className="w-4 h-4 text-emerald-600 flex-shrink-0" />
                                {t('verification.acceptedDocs.enrollment') || 'Öğrenci belgesi / Kayıt belgesi'}
                            </div>
                            <div className="flex items-center gap-2 text-sm text-amber-800">
                                <CheckCircle2 className="w-4 h-4 text-emerald-600 flex-shrink-0" />
                                {t('verification.acceptedDocs.studentId') || 'Öğrenci kimliği'}
                            </div>
                            <div className="flex items-center gap-2 text-sm text-amber-800">
                                <CheckCircle2 className="w-4 h-4 text-emerald-600 flex-shrink-0" />
                                {t('verification.acceptedDocs.transcript') || 'Transkript'}
                            </div>
                            {tierRequested >= 2 && (
                                <div className="flex items-center gap-2 text-sm text-amber-800">
                                    <CheckCircle2 className="w-4 h-4 text-emerald-600 flex-shrink-0" />
                                    {t('verification.acceptedDocs.portalScreenshot') || 'Okul portalı ekran görüntüsü'}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            <input
                ref={fileInputRef}
                type="file"
                multiple
                accept={ALLOWED_EXTENSIONS.join(',')}
                onChange={handleFileChange}
                className="hidden"
            />

            <div
                className={`relative border-2 border-dashed rounded-xl p-10 text-center transition-all cursor-pointer group ${dragActive
                    ? 'border-emerald-500 bg-emerald-50 scale-[1.01]'
                    : 'border-gray-300 hover:border-emerald-400 hover:bg-emerald-50/30'
                    }`}
                onDragEnter={handleDrag}
                onDragLeave={handleDrag}
                onDragOver={handleDrag}
                onDrop={handleDrop}
                onClick={handleButtonClick}
            >
                <div className={`w-16 h-16 rounded-full mx-auto mb-4 flex items-center justify-center transition-colors ${dragActive ? 'bg-emerald-100' : 'bg-gray-100 group-hover:bg-emerald-100'}`}>
                    <Upload className={`w-8 h-8 transition-colors ${dragActive ? 'text-emerald-600' : 'text-gray-400 group-hover:text-emerald-500'}`} />
                </div>
                <p className="text-gray-700 font-medium mb-1">
                    {t('verification.dragDrop') || 'Sürükle bırak veya dosya seç'}
                </p>
                <p className="text-sm text-gray-500 mb-4">
                    {t('verification.fileTypes') || 'PDF, JPG, PNG (max 10MB)'}
                </p>
                <Button type="button" variant="outline" size="sm" className="pointer-events-none">
                    <Upload className="w-4 h-4 mr-2" />
                    {t('verification.form.uploadDocuments') || 'Belgeleri Yükle'}
                </Button>
            </div>

            {files.length > 0 && (
                <div className="space-y-3">
                    <h4 className="font-medium text-gray-900 flex items-center gap-2">
                        <FileText className="w-4 h-4 text-gray-500" />
                        {t('verification.selectedFiles') || 'Seçilen Dosyalar'} ({files.length})
                    </h4>
                    <div className="space-y-2">
                        {files.map((uploadedFile, index) => (
                            <div
                                key={index}
                                className={`flex items-center gap-3 p-3 rounded-xl border transition-colors ${uploadedFile.status === 'error'
                                    ? 'bg-red-50 border-red-200'
                                    : uploadedFile.status === 'uploaded'
                                        ? 'bg-emerald-50 border-emerald-200'
                                        : 'bg-white border-gray-200 hover:border-gray-300'
                                    }`}
                            >
                                <div className={`p-2 rounded-lg ${uploadedFile.status === 'error' ? 'bg-red-100' : 'bg-gray-100'}`}>
                                    <FileText className={`w-4 h-4 ${uploadedFile.status === 'error' ? 'text-red-500' : 'text-gray-500'}`} />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-medium text-gray-900 truncate">{uploadedFile.file.name}</p>
                                    <p className="text-xs text-gray-500">
                                        {formatFileSize(uploadedFile.file.size)}
                                        {uploadedFile.error && (
                                            <span className="text-red-600 ml-2">- {uploadedFile.error}</span>
                                        )}
                                    </p>
                                </div>
                                {uploadedFile.status === 'queued' && (
                                    <span className="text-xs text-emerald-700 bg-emerald-100 px-2.5 py-1 rounded-full font-medium">{t('app.page.hazir')}</span>
                                )}
                                {uploadedFile.status === 'uploaded' && (
                                    <CheckCircle2 className="w-5 h-5 text-emerald-600" />
                                )}
                                {uploadedFile.status === 'error' && (
                                    <AlertCircle className="w-5 h-5 text-red-500" />
                                )}
                                <button
                                    type="button"
                                    onClick={(e) => { e.stopPropagation(); removeFile(index); }}
                                    className="p-1.5 hover:bg-red-100 rounded-lg transition-colors"
                                >
                                    <X className="w-4 h-4 text-gray-400 hover:text-red-500" />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <p className="text-sm text-gray-500 text-center flex items-center justify-center gap-2">
                <Shield className="w-4 h-4" />
                {t('verification.documentsNote') || 'Belgeler sadece doğrulama için kullanılır ve güvenli şekilde saklanır.'}
            </p>
        </div>
    );
}

// Main Component
function VerifyPageContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const { data: session, status } = useSession();
    const { t } = useTranslation();

    const isPreviewMode = searchParams.get('preview') === 'true';

    const [currentStep, setCurrentStep] = useState<FormStep>('tier-select');
    const [formData, setFormData] = useState<FormData>(initialFormData);
    const [loading, setLoading] = useState(false);
    const [existingVerification, setExistingVerification] = useState<any>(null);
    const [errors, setErrors] = useState<Record<string, string>>({});

    useEffect(() => {
        if (!isPreviewMode && status === 'unauthenticated') {
            router.replace('/login?callbackUrl=/verify');
        }
    }, [status, router, isPreviewMode]);

    useEffect(() => {
        if (session?.user) {
            fetch('/api/verification')
                .then(res => res.json())
                .then(data => {
                    if (data.verification) setExistingVerification(data.verification);
                })
                .catch(console.error);
        }
    }, [session]);

    const steps: { id: FormStep; title: string; shortTitle: string }[] = [
        { id: 'tier-select', title: t('verification.steps.tierSelect') || 'Doğrulama Seviyesi Seçin', shortTitle: 'Seviye' },
        { id: 'personal-info', title: t('verification.steps.personalInfo') || 'Kişisel Bilgiler', shortTitle: 'Kisisel' },
        { id: 'education-info', title: t('verification.steps.educationInfo') || 'Eğitim Bilgileri', shortTitle: 'Eğitim' },
        { id: 'documents', title: t('verification.steps.documents') || 'Belge Yükle', shortTitle: 'Belgeler' },
        { id: 'review', title: t('verification.steps.review') || 'İncele ve Gönder', shortTitle: 'Gönder' },
    ];

    const currentStepIndex = steps.findIndex(s => s.id === currentStep);

    const validateCurrentStep = (): boolean => {
        const newErrors: Record<string, string> = {};

        if (currentStep === 'personal-info') {
            if (!formData.firstName.trim()) newErrors.firstName = 'Ad zorunludur';
            if (!formData.lastName.trim()) newErrors.lastName = 'Soyad zorunludur';
            if (!formData.dateOfBirth) newErrors.dateOfBirth = 'Doğum tarihi zorunludur';
            if (!formData.phone.trim()) newErrors.phone = 'Telefon zorunludur';
            if (!formData.country.trim()) newErrors.country = 'Ülke zorunludur';
        }

        if (currentStep === 'education-info') {
            if (!formData.institutionName.trim()) newErrors.institutionName = 'Kurum adı zorunludur';
            if (!formData.institutionCountry.trim()) newErrors.institutionCountry = 'Kurum ülkesi zorunludur';
            if (!formData.degreeProgram.trim()) newErrors.degreeProgram = 'Bölüm zorunludur';
        }

        setErrors(newErrors);
        if (Object.keys(newErrors).length > 0) {
            toast.error('Lütfen zorunlu alanları doldurun');
            return false;
        }
        return true;
    };

    const nextStep = () => {
        if (!validateCurrentStep()) return;
        const nextIndex = currentStepIndex + 1;
        if (nextIndex < steps.length) {
            setCurrentStep(steps[nextIndex].id);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const prevStep = () => {
        const prevIndex = currentStepIndex - 1;
        if (prevIndex >= 0) {
            setErrors({});
            setCurrentStep(steps[prevIndex].id);
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const goToStep = (stepIndex: number) => {
        if (stepIndex <= currentStepIndex) {
            setErrors({});
            setCurrentStep(steps[stepIndex].id);
        }
    };

    const handleSubmit = async () => {
        setLoading(true);
        try {
            const response = await fetch('/api/verification', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    tier_requested: formData.tierRequested,
                    institution_email: formData.institutionEmail,
                    first_name: formData.firstName,
                    last_name: formData.lastName,
                    date_of_birth: formData.dateOfBirth,
                    phone: formData.phone,
                    country: formData.country,
                    city: formData.city,
                    institution_name: formData.institutionName,
                    institution_country: formData.institutionCountry,
                    institution_type: formData.institutionType,
                    student_id: formData.studentId,
                    enrollment_year: formData.enrollmentYear,
                    expected_graduation: formData.expectedGraduation,
                    degree_program: formData.degreeProgram,
                    degree_level: formData.degreeLevel,
                    is_full_time: formData.isFullTime,
                    financial_need_statement: formData.financialNeedStatement,
                }),
            });

            if (!response.ok) throw new Error('Failed to submit verification');

            const data = await response.json();
            toast.success(t('verification.submitSuccess') || 'Doğrulama başvurusu başarıyla gönderildi!');
            router.push(`/verify/status?id=${data.verification.verification_id}`);
        } catch (error) {
            console.error('Verification error:', error);
            toast.error(t('verification.submitError') || 'Başvuru gönderilemedi. Lütfen tekrar deneyin.');
        } finally {
            setLoading(false);
        }
    };

    // Already verified
    if (existingVerification && existingVerification.status !== 'REJECTED') {
        return (
            <div className="min-h-screen flex flex-col bg-gradient-to-br from-gray-50 via-white to-emerald-50/30">
                <Navbar />
                <main className="flex-grow flex items-center justify-center px-4">
                    <div className="max-w-md mx-auto p-8 bg-white rounded-2xl shadow-xl border border-gray-100 text-center">
                        <div className="w-20 h-20 bg-gradient-to-br from-emerald-400 to-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-lg shadow-emerald-200">
                            <ShieldCheck className="w-10 h-10 text-white" />
                        </div>
                        <h2 className="text-2xl font-bold text-gray-900 mb-2">
                            {t('verification.alreadySubmitted') || 'Başvuru Zaten Gönderildi'}
                        </h2>
                        <p className="text-gray-600 mb-6">
                            {t('verification.checkStatus') || 'Doğrulama durumunuzu kontrol edin.'}
                        </p>
                        <Button
                            onClick={() => router.push(`/verify/status?id=${existingVerification.verification_id}`)}
                            className="bg-emerald-600 hover:bg-emerald-700 w-full"
                            size="lg"
                        >
                            {t('verification.viewStatus') || 'Durumu Görüntüle'}
                            <ChevronRight className="w-4 h-4 ml-2" />
                        </Button>
                    </div>
                </main>
                <Footer />
            </div>
        );
    }

    if (status === 'loading') {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-50 via-white to-emerald-50/30">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-4 border-emerald-200 border-t-emerald-600 mx-auto mb-4"></div>
                    <p className="text-gray-500">{t('app.page.yukleniyor')}</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col bg-gradient-to-br from-gray-50 via-white to-emerald-50/30">
            <Navbar />
            <main className="flex-grow">
                {/* Hero Header */}
                <div className="bg-gradient-to-r from-emerald-600 via-emerald-700 to-teal-700 text-white py-10 px-4">
                    <div className="max-w-3xl mx-auto text-center">
                        <div className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-2xl flex items-center justify-center mx-auto mb-4">
                            <ShieldCheck className="w-8 h-8 text-white" />
                        </div>
                        <h1 className="text-3xl md:text-4xl font-bold mb-3">
                            {t('verification.title') || 'Öğrenci Doğrulaması'}
                        </h1>
                        <p className="text-emerald-100 text-lg max-w-xl mx-auto">
                            {t('verification.subtitle') || 'Bağışçıların güvenini artırmak için doğrulama seviyeni seç ve gerekli belgeleri yükle.'}
                        </p>
                    </div>
                </div>

                {/* Step Indicator */}
                <div className="max-w-3xl mx-auto px-4 -mt-6">
                    <div className="bg-white rounded-2xl shadow-lg border border-gray-100 p-4">
                        <div className="flex items-center justify-between">
                            {steps.map((step, index) => {
                                const Icon = STEP_ICONS[step.id];
                                const isActive = index === currentStepIndex;
                                const isCompleted = index < currentStepIndex;
                                const isClickable = index <= currentStepIndex;

                                return (
                                    <div key={step.id} className="flex items-center flex-1 last:flex-initial">
                                        <button
                                            onClick={() => isClickable && goToStep(index)}
                                            className={`flex flex-col items-center gap-1.5 transition-all ${isClickable ? 'cursor-pointer' : 'cursor-default'}`}
                                        >
                                            <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl flex items-center justify-center transition-all duration-300 ${isActive
                                                ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200 scale-110'
                                                : isCompleted
                                                    ? 'bg-emerald-100 text-emerald-700'
                                                    : 'bg-gray-100 text-gray-400'
                                                }`}>
                                                {isCompleted ? (
                                                    <CheckCircle2 className="w-5 h-5 md:w-6 md:h-6" />
                                                ) : (
                                                    <Icon className="w-5 h-5 md:w-6 md:h-6" />
                                                )}
                                            </div>
                                            <span className={`text-xs font-medium hidden sm:block ${isActive ? 'text-emerald-700' : isCompleted ? 'text-emerald-600' : 'text-gray-400'}`}>
                                                {step.shortTitle}
                                            </span>
                                        </button>

                                        {index < steps.length - 1 && (
                                            <div className="flex-1 mx-2 md:mx-3">
                                                <div className={`h-1 rounded-full transition-all duration-500 ${index < currentStepIndex ? 'bg-emerald-400' : 'bg-gray-200'}`} />
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>

                {/* Form Body */}
                <div className="max-w-3xl mx-auto px-4 py-8">
                    <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
                        {/* Step Header */}
                        <div className="px-6 md:px-8 pt-6 md:pt-8 pb-4 border-b border-gray-100">
                            <div className="flex items-center gap-3">
                                {(() => {
                                    const Icon = STEP_ICONS[currentStep];
                                    return (
                                        <div className="p-2.5 bg-emerald-100 rounded-xl">
                                            <Icon className="w-5 h-5 text-emerald-700" />
                                        </div>
                                    );
                                })()}
                                <div>
                                    <p className="text-sm text-emerald-600 font-medium">{t('app.page.adim')}{currentStepIndex + 1} / {steps.length}</p>
                                    <h2 className="text-xl font-bold text-gray-900">
                                        {steps[currentStepIndex].title}
                                    </h2>
                                </div>
                            </div>
                        </div>

                        {/* Step Content */}
                        <div className="px-6 md:px-8 py-6 md:py-8">

                            {/* Step 1: Tier Selection */}
                            {currentStep === 'tier-select' && (
                                <div className="space-y-5">
                                    <p className="text-gray-600">
                                        {t('verification.tierSelectDescription') || 'Daha yüksek seviye = daha yüksek güven. Seviye arttıkça ek kanıt istenebilir.'}
                                    </p>

                                    <div className="space-y-4">
                                        {TIER_CONFIG.filter(tier => tier.tier >= 1 && tier.tier <= 2).map((tier) => {
                                            const { t } = useTranslation();
                                            const isSelected = formData.tierRequested === tier.tier;
                                            const tierNames: Record<number, string> = {
                                                1: t('verification.tiers.tier1.name') || 'Belge ile Doğrulama',
                                                2: t('verification.tiers.tier2.name') || 'Yüksek Güven',
                                            };
                                            const tierDescs: Record<number, string> = {
                                                1: t('verification.tiers.tier1.description') || 'Öğrenci belgesi veya kayıt belgesi yükleyerek doğrula.',
                                                2: t('verification.tiers.tier2.description') || 'Belge + okul portalı ekran görüntüsü ile doğrula.',
                                            };
                                            const tierReqs: Record<number, string> = {
                                                1: t('verification.tiers.tier1.subtext') || 'Gerekli: Öğrenci belgesi',
                                                2: t('verification.tiers.tier2.subtext') || 'Gerekli: Öğrenci belgesi, Portal ekran görüntüsü',
                                            };

                                            return (
                                                <div
                                                    key={tier.tier}
                                                    onClick={() => setFormData({ ...formData, tierRequested: tier.tier as VerificationTier })}
                                                    className={`relative p-5 border-2 rounded-xl cursor-pointer transition-all duration-200 group ${isSelected
                                                        ? 'border-emerald-500 bg-emerald-50/50 shadow-md shadow-emerald-100'
                                                        : 'border-gray-200 hover:border-emerald-300 hover:bg-gray-50'
                                                        }`}
                                                >
                                                    <div className="flex items-start gap-4">
                                                        <div className={`p-3 rounded-xl transition-colors ${isSelected ? 'bg-emerald-100' : 'bg-gray-100 group-hover:bg-emerald-50'}`}>
                                                            {tier.tier === 1 ? (
                                                                <Shield className={`w-6 h-6 ${isSelected ? 'text-emerald-700' : 'text-gray-500'}`} />
                                                            ) : (
                                                                <ShieldCheck className={`w-6 h-6 ${isSelected ? 'text-emerald-700' : 'text-gray-500'}`} />
                                                            )}
                                                        </div>
                                                        <div className="flex-1">
                                                            <div className="flex items-center gap-2 mb-1">
                                                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${isSelected
                                                                    ? 'bg-emerald-600 text-white'
                                                                    : 'bg-gray-200 text-gray-700'}`}>
                                                                    {t('app.page.tier')}{tier.tier}
                                                                </span>
                                                                <h3 className="font-semibold text-gray-900">{tierNames[tier.tier]}</h3>
                                                            </div>
                                                            <p className="text-sm text-gray-600 mb-2">{tierDescs[tier.tier]}</p>
                                                            <p className="text-xs text-gray-500 flex items-center gap-1.5">
                                                                <FileText className="w-3.5 h-3.5" />
                                                                {tierReqs[tier.tier]}
                                                            </p>
                                                        </div>
                                                        {isSelected && (
                                                            <div className="absolute top-4 right-4">
                                                                <div className="w-7 h-7 bg-emerald-600 rounded-full flex items-center justify-center">
                                                                    <CheckCircle2 className="w-5 h-5 text-white" />
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* Tier 0 Email verification */}
                                    <div className="relative mt-6">
                                        <div className="absolute inset-0 flex items-center" aria-hidden="true">
                                            <div className="w-full border-t border-gray-200" />
                                        </div>
                                        <div className="relative flex justify-center">
                                            <span className="bg-white px-3 text-sm text-gray-500">veya</span>
                                        </div>
                                    </div>

                                    <div className="p-5 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl border border-blue-200">
                                        <div className="flex items-start gap-3 mb-3">
                                            <div className="p-2 bg-blue-100 rounded-lg">
                                                <Mail className="w-5 h-5 text-blue-600" />
                                            </div>
                                            <div>
                                                <h4 className="font-semibold text-blue-900">
                                                    {t('verification.tier0Option') || 'Okul E-postası ile Hızlı Doğrulama'}
                                                </h4>
                                                <p className="text-sm text-blue-700 mt-1">
                                                    {t('verification.tier0Description') || 'Okul e-postanıza bir doğrulama bağlantısı göndeririz.'}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="flex gap-2 items-center">
                                            <Input
                                                type="email"
                                                placeholder={t('app.page.renci_universite_edu_tr')}
                                                value={formData.institutionEmail}
                                                onChange={(e) => setFormData({ ...formData, institutionEmail: e.target.value })}
                                                className="flex-1 bg-white"
                                            />
                                            {formData.institutionEmail && isEducationalEmail(formData.institutionEmail) && (
                                                <span className="text-emerald-600 flex items-center gap-1 text-sm font-medium whitespace-nowrap">
                                                    <CheckCircle2 className="w-4 h-4" /> {t('app.page.ge_erli')}</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Step 2: Personal Information */}
                            {currentStep === 'personal-info' && (
                                <div className="space-y-5">
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="firstName" className="flex items-center gap-1.5">
                                                <User className="w-3.5 h-3.5 text-gray-400" />
                                                {t('verification.form.firstName') || 'Ad'} <span className="text-red-500">*</span>
                                            </Label>
                                            <Input
                                                id="firstName"
                                                value={formData.firstName}
                                                onChange={(e) => { setFormData({ ...formData, firstName: e.target.value }); setErrors({ ...errors, firstName: '' }); }}
                                                className={errors.firstName ? 'border-red-300 focus:border-red-400' : ''}
                                                placeholder={t('app.page.ahmet')}
                                            />
                                            {errors.firstName && <p className="text-xs text-red-500">{errors.firstName}</p>}
                                        </div>
                                        <div className="space-y-2">
                                            <Label htmlFor="lastName" className="flex items-center gap-1.5">
                                                <User className="w-3.5 h-3.5 text-gray-400" />
                                                {t('verification.form.lastName') || 'Soyad'} <span className="text-red-500">*</span>
                                            </Label>
                                            <Input
                                                id="lastName"
                                                value={formData.lastName}
                                                onChange={(e) => { setFormData({ ...formData, lastName: e.target.value }); setErrors({ ...errors, lastName: '' }); }}
                                                className={errors.lastName ? 'border-red-300 focus:border-red-400' : ''}
                                                placeholder={t('app.page.yilmaz')}
                                            />
                                            {errors.lastName && <p className="text-xs text-red-500">{errors.lastName}</p>}
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="dateOfBirth" className="flex items-center gap-1.5">
                                            <Calendar className="w-3.5 h-3.5 text-gray-400" />
                                            {t('verification.form.dateOfBirth') || 'Doğum Tarihi'} <span className="text-red-500">*</span>
                                        </Label>
                                        <Input
                                            id="dateOfBirth"
                                            type="date"
                                            value={formData.dateOfBirth}
                                            onChange={(e) => { setFormData({ ...formData, dateOfBirth: e.target.value }); setErrors({ ...errors, dateOfBirth: '' }); }}
                                            className={errors.dateOfBirth ? 'border-red-300 focus:border-red-400' : ''}
                                        />
                                        {errors.dateOfBirth && <p className="text-xs text-red-500">{errors.dateOfBirth}</p>}
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="phone" className="flex items-center gap-1.5">
                                            <Phone className="w-3.5 h-3.5 text-gray-400" />
                                            {t('verification.form.phone') || 'Telefon Numarası'} <span className="text-red-500">*</span>
                                        </Label>
                                        <Input
                                            id="phone"
                                            type="tel"
                                            value={formData.phone}
                                            onChange={(e) => { setFormData({ ...formData, phone: e.target.value }); setErrors({ ...errors, phone: '' }); }}
                                            className={errors.phone ? 'border-red-300 focus:border-red-400' : ''}
                                            placeholder={t('app.page.90_5xx_xxx_xx_xx')}
                                        />
                                        {errors.phone && <p className="text-xs text-red-500">{errors.phone}</p>}
                                    </div>

                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="country" className="flex items-center gap-1.5">
                                                <MapPin className="w-3.5 h-3.5 text-gray-400" />
                                                {t('verification.form.country') || 'Ülke'} <span className="text-red-500">*</span>
                                            </Label>
                                            <Input
                                                id="country"
                                                value={formData.country}
